-- Poems batch 329
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2a2848f4-68f1-4add-b6d3-287402c1d481','漁者  其三','黄裳','宋','宋诗','song-poetry','','[]','一葉輕舠住處清，荻灣鷗渚幾曾榮。',32,'全唐诗/poet.song.54000.json','["一葉輕舠住處清，荻灣鷗渚幾曾榮。", "旁人莫笑魚吞餌，此爲生如爾爲生。"]'),
('9422031c-c838-45dd-9ba9-5ca5df78372d','漁者  其四','黄裳','宋','宋诗','song-poetry','','[]','水雲生計有誰拘，烟雨蟾光已自娛。',32,'全唐诗/poet.song.54000.json','["水雲生計有誰拘，烟雨蟾光已自娛。", "得喪與魚同所遇，垂綸何似且施罛。"]'),
('15df38f2-425c-4df6-809b-8659a715d446','藏春峽','黄裳','宋','宋诗','song-poetry','','[]','一元長抱百花根，峽裏看春野思存。',32,'全唐诗/poet.song.54000.json','["一元長抱百花根，峽裏看春野思存。", "只恐藏春藏不得，却隨風雨過南園。"]'),
('974315aa-d911-412a-9d14-12f695d405a3','容照巖','黄裳','宋','宋诗','song-poetry','','[]','慎獨幽人坐處深，陽精陰魄許相尋。',32,'全唐诗/poet.song.54000.json','["慎獨幽人坐處深，陽精陰魄許相尋。", "也知自有天光在，謾借餘輝照我吟。"]'),
('20d0f28d-75c8-4b0d-a038-7d959cbe7af5','茶苑  其一','黄裳','宋','宋诗','song-poetry','','[]','莫道雨芽非北苑，須知山脈是東溪。',32,'全唐诗/poet.song.54000.json','["莫道雨芽非北苑，須知山脈是東溪。", "旋燒石鼎供吟笑，容照巖中日未西。"]'),
('e5a63da5-c8da-4996-b8ad-d95dcde9b745','茶苑  其二','黄裳','宋','宋诗','song-poetry','','[]','想見春來噉動山，雨前收得幾籃還。',32,'全唐诗/poet.song.54000.json','["想見春來噉動山，雨前收得幾籃還。", "斧斤不落幽人手，且喜家園禁已閒。"]'),
('84a1f020-b3f9-465e-8a60-446b3f366ced','冬後  其一','黄裳','宋','宋诗','song-poetry','','[]','萬物歸來有却無，不知誰與計榮枯。',32,'全唐诗/poet.song.54000.json','["萬物歸來有却無，不知誰與計榮枯。", "雪天梅信何時得，寂寞中開一畫圖。"]'),
('a8efaa89-f217-4ab2-9e4d-99245f1fd287','冬後  其二','黄裳','宋','宋诗','song-poetry','','[]','令向冬行造歲功，曉來天篆已排空。',32,'全唐诗/poet.song.54000.json','["令向冬行造歲功，曉來天篆已排空。", "急催雪意藏蕭索，只望瓊林一夜風。"]'),
('e595d262-3fac-4d30-bf9c-4b49f951fd3b','冬後  其三','黄裳','宋','宋诗','song-poetry','','[]','曉霜初甃瑶池薄，脫稻新炊玉粒香。',32,'全唐诗/poet.song.54000.json','["曉霜初甃瑶池薄，脫稻新炊玉粒香。", "向我歲寒惟有菊，葛巾時爲醱醅忙。"]'),
('b02fbd12-4f0c-43b0-8efa-c096cdb4da83','冬後  其四','黄裳','宋','宋诗','song-poetry','','[]','方醖新寒晦又明，歲華無幾壯心驚。',32,'全唐诗/poet.song.54000.json','["方醖新寒晦又明，歲華無幾壯心驚。", "吹斜雁字霜風勁，忽送行人一兩聲。"]'),
('eaa92931-6764-43dd-8249-513175793ace','建溪舟行','黄裳','宋','宋诗','song-poetry','','[]','兩岸青山倒影濃，一江秋色兩山中。',32,'全唐诗/poet.song.54000.json','["兩岸青山倒影濃，一江秋色兩山中。", "扁舟不怯泝流水，天意借人帆上風。"]'),
('d26aca65-5e59-47c9-9dfe-d223555fb1df','清陰堂  其一','黄裳','宋','宋诗','song-poetry','','[]','仙洞氣寒龍送雨，瑞蓮香冷水生風。',32,'全唐诗/poet.song.54000.json','["仙洞氣寒龍送雨，瑞蓮香冷水生風。", "煩襟銷盡梯雲去，見遠樓前色入空。"]'),
('9b61a215-93a8-4056-9d38-60a0cc6338a9','清陰堂  其二','黄裳','宋','宋诗','song-poetry','','[]','方沼涵天雲淡淡，長林篩日地深深。',32,'全唐诗/poet.song.54000.json','["方沼涵天雲淡淡，長林篩日地深深。", "九仙山照青烟洞，先向堂中洗此心。"]'),
('05733d37-c80f-4fa7-8ff3-8ae0b2c378a3','清陰堂  其三','黄裳','宋','宋诗','song-poetry','','[]','龍含雨意簷前過，日轉花光席上來。',32,'全唐诗/poet.song.54000.json','["龍含雨意簷前過，日轉花光席上來。", "小徑深深塵不到，一樽多爲逸人開。"]'),
('5aa9ffe8-7090-4432-9016-91c753cb20f8','江上對月','黄裳','宋','宋诗','song-poetry','','[]','無處月清如水國，有誰心滿似孤輪。',32,'全唐诗/poet.song.54000.json','["無處月清如水國，有誰心滿似孤輪。", "幽期終在綠巖畔，長願寒光隨我身。"]'),
('986cefb1-6296-42f2-8a7d-dfac0c7f0f98','雙梧堂','黄裳','宋','宋诗','song-poetry','','[]','好音長引鳳來棲，對立薰風可愛時。',32,'全唐诗/poet.song.54000.json','["好音長引鳳來棲，對立薰風可愛時。", "葉上雨聲枝上月，何須焦尾始相知。"]'),
('7a112d80-8651-4dd1-bbe8-a7aeb8e6b1ff','次致政李大夫郊步之韵  其一','黄裳','宋','宋诗','song-poetry','','[]','垂髫孫子侍閒行，只此閒中度此生。',32,'全唐诗/poet.song.54000.json','["垂髫孫子侍閒行，只此閒中度此生。", "偏是杜鵑能愜意，不如歸去兩三聲。"]'),
('25e9e3e0-9865-423f-ae98-477ae64f5d55','次致政李大夫郊步之韵  其二','黄裳','宋','宋诗','song-poetry','','[]','偶欲閒行儘日斜，虎頭幽徑二龍沙。',32,'全唐诗/poet.song.54000.json','["偶欲閒行儘日斜，虎頭幽徑二龍沙。", "花無欄檻人無累，自在人看自在花。"]'),
('cd4ba7c3-1ca9-4480-954a-a793d0586b4b','江上','黄裳','宋','宋诗','song-poetry','','[]','鷺從何處起來遲，點破青山一字飛。',32,'全唐诗/poet.song.54000.json','["鷺從何處起來遲，點破青山一字飛。", "更好小舟蓬下聽，過雲斜日未須歸。"]'),
('a1631f19-fc25-484e-a507-b32656421ee1','貽傳神  其一','黄裳','宋','宋诗','song-poetry','','[]','默默紫玄像，蕭蕭青竹軒。',24,'全唐诗/poet.song.54000.json','["默默紫玄像，蕭蕭青竹軒。", "相看誰有道，無問亦無言。"]'),
('0aac6b61-ce68-4642-a8cf-877bd2a41657','貽傳神  其二','黄裳','宋','宋诗','song-poetry','','[]','筆頭何處得天真，幻化身中氣與神。',32,'全唐诗/poet.song.54000.json','["筆頭何處得天真，幻化身中氣與神。", "傳取本來空是色，莫將心印向他人。"]'),
('014ecda9-fd9b-448d-a0a9-89a7137c0376','題仁壽閣','黄裳','宋','宋诗','song-poetry','','[]','百年塵外境，萬慮靜中身。',24,'全唐诗/poet.song.54000.json','["百年塵外境，萬慮靜中身。", "終日無他事，寒泉照隠人。"]'),
('630295e8-08ef-4329-8253-c6e40aa8f35d','夏日窗下','黄裳','宋','宋诗','song-poetry','','[]','蝎虎窺蠅恨未烹，看書人悄紙窗鳴。',32,'全唐诗/poet.song.54000.json','["蝎虎窺蠅恨未烹，看書人悄紙窗鳴。", "一絲喜子天機靜，任便薰風寄此生。"]'),
('d0c4b8ac-3e7d-4ffa-8287-5332f16da120','過嚴州同太守遊烏龍寺  其一','黄裳','宋','宋诗','song-poetry','','[]','參天松徑夾籃輿，僧在烏龍腹內居。',32,'全唐诗/poet.song.54000.json','["參天松徑夾籃輿，僧在烏龍腹內居。", "莫道此山無妙用，但看雲雨見真如。"]'),
('3665fdf5-d02b-45ea-ae5b-d82c0b72e38b','過嚴州同太守遊烏龍寺  其二','黄裳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','家近西湖去欲飛，到山心却爲山遲。',32,'全唐诗/poet.song.54000.json','["家近西湖去欲飛，到山心却爲山遲。", "看禪弟子人休問，正是龕中作夢時。"]'),
('3416a975-fa51-4d0d-8233-d0c412f37bd4','過嚴州同太守遊烏龍寺  其三','黄裳','宋','宋诗','song-poetry','','[]','脚力猶能上翠微，青娥扶我謾勞伊。',32,'全唐诗/poet.song.54000.json','["脚力猶能上翠微，青娥扶我謾勞伊。", "也知山共文章好，競破朱顔乞小詩。"]'),
('a03d3131-b3bd-4847-bc24-9a9510e15b95','過嚴州同太守遊烏龍寺  其四','黄裳','宋','宋诗','song-poetry','','[]','北山還掃笑歌地，南浦尚懷離別時。',32,'全唐诗/poet.song.54000.json','["北山還掃笑歌地，南浦尚懷離別時。", "到處此緣尤未斷，洞天休怪我來遲。"]'),
('33452480-28b3-4593-b40c-336a4241b92a','寄懶散子  其一','黄裳','宋','宋诗','song-poetry','','[]','此生知了夢初殘，行客遊塵入道觀。',32,'全唐诗/poet.song.54000.json','["此生知了夢初殘，行客遊塵入道觀。", "興去謾窮山一徑，睡來纔起日三竿。"]'),
('b7f0b09e-1fc7-42c9-9d20-0cd88dbf7a8c','寄懶散子  其二','黄裳','宋','宋诗','song-poetry','','[]','非真非妄愜誰看，萬物輪中歲自寒。',32,'全唐诗/poet.song.54000.json','["非真非妄愜誰看，萬物輪中歲自寒。", "玉液浄生仙況味，天香清惹道衣冠。"]'),
('86cf2a90-d812-4dfe-8dfb-a660f33a849e','寄懶散子  其三','黄裳','宋','宋诗','song-poetry','','[]','綠髮紛紛滿道冠，高風吹我一襟寒。',32,'全唐诗/poet.song.54000.json','["綠髮紛紛滿道冠，高風吹我一襟寒。", "看山想有雲臺集，得句應勝得好官。"]'),
('01309e3c-13cc-4f07-a81e-7717d5adc61b','自萬松嶺之龍山  其一','黄裳','宋','宋诗','song-poetry','','[]','萬松雖落斧斤手，一徑尚邀行路人。',32,'全唐诗/poet.song.54000.json','["萬松雖落斧斤手，一徑尚邀行路人。", "嶺是松非休更問，逍遙巾下已離塵。"]'),
('0d38d784-dc05-4510-8f4d-25c37246d72b','自萬松嶺之龍山  其二','黄裳','宋','宋诗','song-poetry','','[]','駸駸車蓋與雲參，控景金漿尚未酣。',32,'全唐诗/poet.song.54000.json','["駸駸車蓋與雲參，控景金漿尚未酣。", "穿過竹林何處樂，龍山前有集虛庵。"]'),
('93408da3-96b7-46be-b514-888118dbb241','還鄉有感','黄裳','宋','宋诗','song-poetry','','[]','竹馬兒童已失真，且尋春色莫尋人。',32,'全唐诗/poet.song.54000.json','["竹馬兒童已失真，且尋春色莫尋人。", "溪山不似當時見，只爲交遊半是塵。"]'),
('35960fba-1eb4-4634-bca9-859bb3dcd61f','戲寄南華翁  其一','黄裳','宋','宋诗','song-poetry','','[]','南華翁也爲官忙，能用牛刀亦是莊。',32,'全唐诗/poet.song.54000.json','["南華翁也爲官忙，能用牛刀亦是莊。", "歸去來兮歸未得，一山風月委寒堂。"]'),
('7f1df595-4b82-4218-887d-5ad5d5811ae0','戲寄南華翁  其二','黄裳','宋','宋诗','song-poetry','','[]','山陰劉子無清策，彭澤陶公有逸才。',32,'全唐诗/poet.song.54000.json','["山陰劉子無清策，彭澤陶公有逸才。", "種秫劍溪休更問，俸錢須買菊花栽。"]'),
('b01b3961-50b7-4705-b4d4-d6a639fe31e1','戲寄南華翁  其三','黄裳','宋','宋诗','song-poetry','','[]','始聞佳耦得韓娘，百里恩新綬與章。',32,'全唐诗/poet.song.54000.json','["始聞佳耦得韓娘，百里恩新綬與章。", "月欲籠人籠未得，先生猶治魯山忙。"]'),
('7e113ac0-7d54-4737-a1e0-90006d845900','題止止堂','黄裳','宋','宋诗','song-poetry','','[]','萬緣忘外息，百福靜中收。',24,'全唐诗/poet.song.54000.json','["萬緣忘外息，百福靜中收。", "莫作南柯夢，浮榮一覺休。"]'),
('eee78f71-c52e-4127-a840-4a866cec6063','妙光堂  其一','黄裳','宋','宋诗','song-poetry','','[]','泰定中含一黍靈，千江明月萬枝燈。',32,'全唐诗/poet.song.54000.json','["泰定中含一黍靈，千江明月萬枝燈。", "自談禪處無人會，安用山僧纏葛藤。"]'),
('f4fb2e1f-df96-418b-910c-ca11a5fbd9ff','妙光堂  其二','黄裳','宋','宋诗','song-poetry','','[]','一體全時萬象生，只緣虛靜到圓明。',32,'全唐诗/poet.song.54000.json','["一體全時萬象生，只緣虛靜到圓明。", "陰陽了取歸根旨，但看蟾光與日精。"]'),
('8ac78bd5-f75c-4668-be4a-e042a144d0f0','謝惠香餠  其一','黄裳','宋','宋诗','song-poetry','','[]','清分馥馥南州餠，靜對綿綿北海雲。',32,'全唐诗/poet.song.54000.json','["清分馥馥南州餠，靜對綿綿北海雲。", "欲曉博山來入被，祥烟尤愜夢回聞。"]'),
('ae40d1c4-ada1-4c37-bf45-454786ca4fa9','謝惠香餠  其二','黄裳','宋','宋诗','song-poetry','','[]','朱餠青烟篆古文，聊資清致聚還分。',32,'全唐诗/poet.song.54000.json','["朱餠青烟篆古文，聊資清致聚還分。", "縱饒五出花殘後，尤有餘香聳未聞。"]'),
('1b517577-03f2-4fe9-8840-f153e8d1a386','和靖山居','黄裳','宋','宋诗','song-poetry','','[]','高吟人去幾年餘，今日孤山始是孤。',32,'全唐诗/poet.song.54000.json','["高吟人去幾年餘，今日孤山始是孤。", "疏影暗香雖更在，應隨閒物落平蕪。"]'),
('e9b4eaf2-5dbc-4ad4-aa3a-02a3961f85d3','將遊苕溪先寄同志','黄裳','宋','宋诗','song-poetry','','[]','長愛苕溪乍入秋，有時東去與君遊。',32,'全唐诗/poet.song.54000.json','["長愛苕溪乍入秋，有時東去與君遊。", "詩牋酒盞遊何處，十里荷花一葉舟。"]'),
('4f553045-f8d4-4fa7-871a-34f1e8740b3f','遊吳有作  其一','黄裳','宋','宋诗','song-poetry','','[]','想見湖山只欲飛，急逃緣累拯衰遲。',32,'全唐诗/poet.song.54000.json','["想見湖山只欲飛，急逃緣累拯衰遲。", "無心雲伴無心客，杖屨相從更許誰。"]'),
('7dfea976-1e9a-4808-8d1c-39760a3b6672','遊吳有作  其二','黄裳','宋','宋诗','song-poetry','','[]','舟人曾記得吳儂，煮粒烹鮮別有功。',32,'全唐诗/poet.song.54000.json','["舟人曾記得吳儂，煮粒烹鮮別有功。", "好是閒爲江上客，隨船還見賣魚翁。"]'),
('90897f47-f6ff-4dad-acc7-981415fd0e7d','遊吳有作  其三','黄裳','宋','宋诗','song-poetry','','[]','拏舟曾過芰荷鄉，十里薰風一水長。',32,'全唐诗/poet.song.54000.json','["拏舟曾過芰荷鄉，十里薰風一水長。", "趁取秋時尋舊賞，且留三日臥清香。"]'),
('9d5b705f-c852-4a04-987b-343f3609dcb3','遊吳有作  其四','黄裳','宋','宋诗','song-poetry','','[]','俸入未辭聊助道，客來多避爲忘機。',32,'全唐诗/poet.song.54000.json','["俸入未辭聊助道，客來多避爲忘機。", "一帆風起鱸魚興，到是秋時恰正肥。"]'),
('f2fc64ab-1be5-4f51-9dfb-f5216d82686c','遊吳有作  其五','黄裳','宋','宋诗','song-poetry','','[]','且刺扁舟入芰荷，香風中聽採蓮歌。',32,'全唐诗/poet.song.54000.json','["且刺扁舟入芰荷，香風中聽採蓮歌。", "秋來最好樽前物，霜滿江天蟹二螯。"]'),
