('5d29a945-384b-4b22-9a27-f12f3c3cfae3','神宗皇帝挽辭  其四','黄裳','宋','宋诗','song-poetry','','[]','圖治心方壯，追班世忽非。',48,'全唐诗/poet.song.54000.json','["圖治心方壯，追班世忽非。", "鼎中龍蜿蜿，陵上栢依依。", "物外音何悄，人間夢亦稀。", "少陽來侍宴，天意已知微。"]'),
('68f78086-5553-462b-9bdd-8a6da46aee64','神宗皇帝挽辭  其五','黄裳','宋','宋诗','song-poetry','','[]','忽自明庭去，風高帝所寒。',48,'全唐诗/poet.song.54000.json','["忽自明庭去，風高帝所寒。", "有期修玉檢，無處覓仙丹。", "與子基圖遠，開天數度寬。", "錦標何以報，空展賜詩看。"]'),
('652fb12a-a53c-4aa7-9b00-3e2fac88e62c','哲宗皇帝挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','忽追班入未央宮，急問宸遊早御風。',64,'全唐诗/poet.song.54000.json','["忽追班入未央宮，急問宸遊早御風。", "流俗豈知塵念斷，故嬪休嘆愛緣空。", "還元精爽留天下，復土聲靈在虜中。", "來自武夷歸去否，幔亭聞說好如嵩。"]'),
('624aaa43-414a-4618-8e53-c6bafbf32c3d','哲宗皇帝挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','數行空下侍臣班，十六回春一夢闌。',64,'全唐诗/poet.song.54000.json','["數行空下侍臣班，十六回春一夢闌。", "天意預形傳國璽，人生難望返魂丹。", "銀河寂寂星垣暗，金闕冥冥羽衛寒。", "月色滿宮誰悵望，春來無處接回鸞。"]'),
('0d5a8601-873f-448e-970a-1265c7232ccf','哲宗皇帝挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','何事騎龍不可攀，衣冠空自在人寰。',64,'全唐诗/poet.song.54000.json','["何事騎龍不可攀，衣冠空自在人寰。", "詔遺夷夏秋容動，言付公卿玉几閒。", "能使抱弓號百姓，豈勞求藥問三山。", "元符事業誰相似，兩漢須看鳳露間。"]'),
('4cea5f33-ec1e-47c7-8750-81d9c887f2c6','欽慈憲肅皇太后挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','懿範存遺詔，香塵守浣衣。',48,'全唐诗/poet.song.54000.json','["懿範存遺詔，香塵守浣衣。", "中天扶日上，西邸引龍歸。", "方慰人寰望，那知輦路非。", "仁恩和夜月，千古在慈闈。"]'),
('acc659bf-ab42-49b4-822b-bc9907f7b9c9','欽慈憲肅皇太后挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','相門陰德遠，天妹儷周文。',48,'全唐诗/poet.song.54000.json','["相門陰德遠，天妹儷周文。", "還政前期速，求賢內助勤。", "仙丹猶訪道，金闕已乘雲。", "紫極空回首，虞號慘日曛。"]'),
('a5244860-35c6-431d-81f9-86c356850731','欽慈憲肅皇太后挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','聽斷簾方捲，遺留事已傳。',48,'全唐诗/poet.song.54000.json','["聽斷簾方捲，遺留事已傳。", "繼承知有後，建立許誰先。", "救弊趨中道，論功列上仙。", "九重空怨慕，霜露鳳臺前。"]'),
('d048325a-8894-42e0-9dd4-9860e5f9095a','欽慈皇后挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','夢中懷日有誰知，莫恨真人下降遲。',64,'全唐诗/poet.song.54000.json','["夢中懷日有誰知，莫恨真人下降遲。", "會合裕陵同祔處，因緣潜邸獨飛時。", "九霄重引真仙仗，四海初傳大母儀。", "悵望鳳臺山下去，東郊無計上金巵。"]'),
('8d1c695f-cfc2-4dd8-a960-098e7ee6c50c','欽慈皇后挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','平日未霑天下養，芳春先棄域中遊。',64,'全唐诗/poet.song.54000.json','["平日未霑天下養，芳春先棄域中遊。", "昔從內令任思順，今起東𣪁舜解憂。", "衣在果聞成赭色，書存尤喜見銀鈎。", "懿圍故事誰攀得，再幸仁皇御九州。"]'),
('a4667cce-e03c-4fd6-8d9b-e0d36303d458','欽慈皇后挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','已傳龍德與承休，果在丹臺不可留。',64,'全唐诗/poet.song.54000.json','["已傳龍德與承休，果在丹臺不可留。", "新冊却埋千古玉，舊恩重起六宮秋。", "尊開圍步松雲遠，榮到支陵雨露憂。", "三十六宮休說恨，誰知先作裕陵遊。"]'),
('a52918e7-5782-48f0-b679-9cc178dc0326','曾魯公挽辭','黄裳','宋','宋诗','song-poetry','','[]','曾侍前星在玉霄，兢爲元老立清朝。',64,'全唐诗/poet.song.54000.json','["曾侍前星在玉霄，兢爲元老立清朝。", "重遊西府羈羣虜，危坐東臺鑒庶僚。", "擾擾萬緣留事業，悠悠千載想風標。", "傳家已有蓬萊客，何患于門到寂寥。"]'),
('20eb67ca-c9b7-4c66-81c4-a9c56ace87eb','王岐公挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','世事今朝了，天閽昨夜開。',48,'全唐诗/poet.song.54000.json','["世事今朝了，天閽昨夜開。", "自當騎鶴去，誰更作霖來。", "寶座扶初日，靈光落上台。", "管弦空悵望，重蓋幾時回。"]'),
('0ae97bdc-9156-4560-9742-7786b4f1c2d2','王岐公挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','貳車登第日，秉軸蓋棺時。',48,'全唐诗/poet.song.54000.json','["貳車登第日，秉軸蓋棺時。", "未掩西陵土，先埋上相碑。", "白麻人已化，黄壤客空悲。", "歲晚林間趣，歸侯想恨遲。"]'),
('296681d7-7f73-47d9-b33b-86526ed53b51','王岐公挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','鼎味難求和，龍髯忽許攀。',48,'全唐诗/poet.song.54000.json','["鼎味難求和，龍髯忽許攀。", "應隨先帝仗，已立太師班。", "人散沙堤悄，恩收客館閒。", "風神巖兢秀，千古畫圖間。"]'),
('7f8d8a6d-314a-44a7-b178-42b09aa94017','王岐公挽辭  其四','黄裳','宋','宋诗','song-poetry','','[]','富貴風波靜，文章態度清。',48,'全唐诗/poet.song.54000.json','["富貴風波靜，文章態度清。", "有緣登相府，無日出都城。", "彝鼎垂行止，金珠照死生。", "百年留不住，廣阜暮烟橫。"]'),
('b6c26f8b-ed26-42e3-ad31-2316d4c503b2','秦國夫人挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','三封皆大國，一子已重金。',48,'全唐诗/poet.song.54000.json','["三封皆大國，一子已重金。", "位到西樞重，春歸寸草深。", "榮華緣忽斷，寂寞路難尋。", "愁入韋溝境，回頭月滿林。"]'),
('20f715ff-5640-4dd8-915e-3d0b4cd0c883','秦國夫人挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','偕老人惆悵，秋深雁獨哀。',48,'全唐诗/poet.song.54000.json','["偕老人惆悵，秋深雁獨哀。", "西風何處問，北首幾時回。", "白日晞朝露，黄埃掩夜臺。", "已辭班第一，內殿不須催。"]'),
('86edc9ce-1be4-4c92-b9be-56c6b58cf588','秦國夫人挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','慰使來三殿，澆觴走百官。',48,'全唐诗/poet.song.54000.json','["慰使來三殿，澆觴走百官。", "送行千乘富，歸宿萬家寬。", "自今騰空往，誰能入定觀。", "曉堂終不見，誰展佛書看。"]'),
('da8a3c3f-bcd5-4ccd-a02e-4ae2687da3c1','安康郡夫人挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','未滿中身壽，尤虛大國封。',48,'全唐诗/poet.song.54000.json','["未滿中身壽，尤虛大國封。", "德明埋玉篆，魂冷臥銀龍。", "漳水恨涵月，秋風悲入松。", "塵寰應不住，無處訪遺蹤。"]'),
('d01ae71c-a3db-4363-8dba-85a5b77dac39','安康郡夫人挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','俄拋中饋世緣空，君子休悲老未同。',32,'全唐诗/poet.song.54000.json','["俄拋中饋世緣空，君子休悲老未同。", "不負大寧身後計，道山人出凱風中。"]'),
('be6bb45a-dbe8-4b37-a7a2-d0e0b1f8c533','安康郡夫人挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','堂堂歸處魏公家，纔飾笄珈日未斜。',32,'全唐诗/poet.song.54000.json','["堂堂歸處魏公家，纔飾笄珈日未斜。", "蒿里數聲留不得，豐安松下早聞鴉。"]'),
('5f1a1424-2990-4cbc-ab98-8e8d2e90720d','郭將軍挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','新里秋聲不忍聞，黄埃千古宋將軍。',32,'全唐诗/poet.song.54000.json','["新里秋聲不忍聞，黄埃千古宋將軍。", "東兵二百今何在，猶有西人想似雲。"]'),
('4b00b10c-a5dd-457f-a6cd-99b737a81ed2','郭將軍挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','赳赳汾陽十世孫，胸中奇業與誰論。',32,'全唐诗/poet.song.54000.json','["赳赳汾陽十世孫，胸中奇業與誰論。", "蓋棺雖愧淩烟閣，猶有蕃豪說舊恩。"]'),
('19e07c9e-a29b-4bdf-91d1-2210eee33766','郭將軍挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','佛書看盡更何憂，不怨生前未是侯。',32,'全唐诗/poet.song.54000.json','["佛書看盡更何憂，不怨生前未是侯。", "日到中天春夢斷，御風歸去玉華秋。"]'),
('ce6c05d3-9358-4e5a-9768-e1214d63ae81','顧學正挽辭','黄裳','宋','宋诗','song-poetry','','[]','行人緣斷絕，弔客淚縱橫。',48,'全唐诗/poet.song.54000.json','["行人緣斷絕，弔客淚縱橫。", "白髮雙親重，青衫一命輕。", "仙丹誰際會，禪頌自分明。", "去住無尋處，今生與後生。"]'),
('bac17d15-aba9-4b5c-af3b-e18d2243557d','夫人陳氏挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','曉來悲接夜來歡，安不人驚夢不還。',32,'全唐诗/poet.song.54000.json','["曉來悲接夜來歡，安不人驚夢不還。", "已御翔鸞天上去，委形空寄古樓山。"]'),
('df292dab-3401-438a-b1d4-7a50da1d4f17','夫人陳氏挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','寶奩人去月空寒，百歲榮華忽蓋棺。',32,'全唐诗/poet.song.54000.json','["寶奩人去月空寒，百歲榮華忽蓋棺。", "萬葉遺經香一篆，日華簾下與誰看。"]'),
('30544c45-896f-4e3f-b8e0-597c72ab9a0d','夫人陳氏挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','北堂旁立兩青衫，六十春風愜笑談。',32,'全唐诗/poet.song.54000.json','["北堂旁立兩青衫，六十春風愜笑談。", "追遠亭前思不見，怨隨霜露滿山南。"]'),
('4abc9928-4f8f-4ec4-b7ac-28ec26c93ff8','陳朝議挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','簫鼓聲中遠遠歸，只因千里有庭闈。',32,'全唐诗/poet.song.54000.json','["簫鼓聲中遠遠歸，只因千里有庭闈。", "彭城君在今休望，黄髮樽前看綵衣。"]'),
('402a19b2-c8a7-40ec-a75d-2fe4690f172b','陳朝議挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','六擁旌麾一夢闌，陳公橋上小棠間。',32,'全唐诗/poet.song.54000.json','["六擁旌麾一夢闌，陳公橋上小棠間。", "掛冠桑梓情尤厚，誰愧遺形葬客山。"]'),
('26b0cba0-b7aa-485f-b402-7cb865e451b6','陳朝議挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','從來風義不憂貧，累行纔踰七十春。',32,'全唐诗/poet.song.54000.json','["從來風義不憂貧，累行纔踰七十春。", "世上榮枯漚影散，進階空有帝綸新。"]'),
('f92e19fa-04e5-4d63-8538-96fc5400d4b3','陳朝議挽辭  其四','黄裳','宋','宋诗','song-poetry','','[]','信到溫陵不忍聞，使君何往盡沾巾。',32,'全唐诗/poet.song.54000.json','["信到溫陵不忍聞，使君何往盡沾巾。", "最高仙桂君家物，更起黌堂遺里人。"]'),
('c7110914-9648-4123-b41b-2c30cd6c1585','陳朝議挽辭  其五','黄裳','宋','宋诗','song-poetry','','[]','未及歸來且勝遊，忽聞庭木已經秋。',32,'全唐诗/poet.song.54000.json','["未及歸來且勝遊，忽聞庭木已經秋。", "羅源三十年遺愛，今作還山一日愁。"]'),
('6ad95109-6efd-47bd-8cf9-dadba17cb48b','俞法曹挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','一息秋來誤壯圖，揚名身後喜諸孤。',32,'全唐诗/poet.song.54000.json','["一息秋來誤壯圖，揚名身後喜諸孤。", "平生樂易歸何處，恐逐清風落有無。"]'),
('dd645212-2636-42e7-8003-3e7e303bb6c4','俞法曹挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','罇前故舊歡尤少，世上光陰惜未終。',32,'全唐诗/poet.song.54000.json','["罇前故舊歡尤少，世上光陰惜未終。", "去歲書來曾說夢，攀龍應御九天風。"]'),
('21924955-a3d5-4b90-a3c3-69af501999c5','陳達野母氏恭人挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','百度韶華少一年，有誰堂上可爭先。',32,'全唐诗/poet.song.54000.json','["百度韶華少一年，有誰堂上可爭先。", "錦衣養志歸來早，報了春暉已獨賢。"]'),
('52d5e5c3-f26a-4c66-85f2-9183816cde82','陳達野母氏恭人挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','眼明身健莫扶持，遽向華堂看綵衣。',32,'全唐诗/poet.song.54000.json','["眼明身健莫扶持，遽向華堂看綵衣。", "已共月明無認處，孝思休踴蓋棺時。"]'),
('a9a8e195-bd8c-40f5-82ea-6fe03e6ff987','方彥稽母安仁縣太君黄氏挽辭  其一','黄裳','宋','宋诗','song-poetry','','[]','文科名峻歸寧日，卿部官高致養時。',32,'全唐诗/poet.song.54000.json','["文科名峻歸寧日，卿部官高致養時。", "罔極是恩誰報得，更緣霜露有餘悲。"]'),
('25b039fe-a422-4751-9203-fc5615f7a8ba','方彥稽母安仁縣太君黄氏挽辭  其二','黄裳','宋','宋诗','song-poetry','','[]','八十三年婦德成，綵衣歡笑過浮生。',32,'全唐诗/poet.song.54000.json','["八十三年婦德成，綵衣歡笑過浮生。", "含虛臺上尋仙侶，瀨口愁人月自明。"]'),
('ac0b4242-e6a6-4a47-9694-4a5919eaf531','方彥稽母安仁縣太君黄氏挽辭  其三','黄裳','宋','宋诗','song-poetry','','[]','來處緣應異，歸時壽已稀。',24,'全唐诗/poet.song.54000.json','["來處緣應異，歸時壽已稀。", "校讎孫繼子，無限是春暉。"]'),
('26babeef-4bdf-4245-8141-4da8af40cf52','方彥稽母安仁縣太君黄氏挽辭  其四','黄裳','宋','宋诗','song-poetry','','[]','數終還是福，道盡更何言。',24,'全唐诗/poet.song.54000.json','["數終還是福，道盡更何言。", "子到康民處，方知鞠育恩。"]'),
('9782662b-a024-42ff-a7c8-ed6dc35284fe','壽安太君挽辭','黄裳','宋','宋诗','song-poetry','','[]','榮知隨養去，恨向蓋棺歸。',48,'全唐诗/poet.song.54000.json','["榮知隨養去，恨向蓋棺歸。", "故里三千遠，浮生七十稀。", "曉臺空匣鑑，秋露謾沾衣。", "相伴勤田上，殘蟾與夕暉。"]'),
('1a46f25a-d559-4fe8-8886-19d320db8d9a','章銀青挽辭','黄裳','宋','宋诗','song-poetry','','[]','八十六年盡，竈中丹未成。',48,'全唐诗/poet.song.54000.json','["八十六年盡，竈中丹未成。", "貳車歸去勇，辟穀老來清。", "寂寂水天境，悠悠春露情。", "揚名尤有子，身後許誰爭。"]'),
('1769e75b-a3df-4384-926b-f8ea1a5932f9','悼張公實','黄裳','宋','宋诗','song-poetry','','[]','六十三年素自知，人生如此更何疑。',64,'全唐诗/poet.song.54000.json','["六十三年素自知，人生如此更何疑。", "調詼常爲供狂笑，騷雅偏能斲小詩。", "悼子杳冥歸往路，悔予輕易別離時。", "水雲村記相期事，雖到家山已恨遲。"]'),
('1c3444c7-b612-4577-b64e-4da0c19496fe','悼陳伯修殿院  其一','黄裳','宋','宋诗','song-poetry','','[]','塵勞常共笑，怱遽忽相違。',48,'全唐诗/poet.song.54000.json','["塵勞常共笑，怱遽忽相違。", "已失重歸約，應無再見時。", "短長前事定，來去幾人知。", "陰籍更何累，惟餘身後悲。"]'),
('b06639a0-3483-4676-8127-cc1b2a7f6463','悼陳伯修殿院  其二','黄裳','宋','宋诗','song-poetry','','[]','喜從楊子過江湄，惹起浮生一段悲。',32,'全唐诗/poet.song.54000.json','["喜從楊子過江湄，惹起浮生一段悲。", "不見武林吟笑侶，却來京口看銘詩。"]'),
('b1930f6e-09c9-4afc-9205-c1cc75f0d299','悼陳伯修殿院  其三','黄裳','宋','宋诗','song-poetry','','[]','少年科第少能攀，未及登庸夢已闌。',32,'全唐诗/poet.song.54000.json','["少年科第少能攀，未及登庸夢已闌。", "豈意蓋棺尤有地，于飛同在戲魚山。"]'),
('57723a45-b00b-4eb5-9f4e-5ddc66477371','悼陳先之博士','黄裳','宋','宋诗','song-poetry','','[]','五行纔悟已忘筌，妙旨知誰更得傳。',64,'全唐诗/poet.song.54000.json','["五行纔悟已忘筌，妙旨知誰更得傳。", "夢幻去時無別苦，旌幢歸處有前緣。", "寂寥月伴松楸室，悽愴人逢雨露天。", "尚記辱書來見報，春回寒谷未踰年。"]'),
('dae3e5eb-bacc-4a67-bef8-b137e679262f','悼李承議','黄裳','宋','宋诗','song-poetry','','[]','去後家山宴未闌，已聞忙蓋旅中棺。',64,'全唐诗/poet.song.54000.json','["去後家山宴未闌，已聞忙蓋旅中棺。", "幾多言笑情先斷，些小窮通夢已殘。", "友愛方嗟離別易，子賢休恤繼承難。", "曾相從處應留恨，未結松庵棄外觀。"]'),
('c57ded03-55a6-465d-8906-430441c8fda0','哭陳商老','黄裳','宋','宋诗','song-poetry','','[]','浮雲前事定，壯志此生休。',48,'全唐诗/poet.song.54000.json','["浮雲前事定，壯志此生休。", "夢冷水中月，文高天上樓。", "冥冥誰造物，衮衮自封侯。", "南國一緘破，西風雙淚流。"]'),
('35edd82f-5bc9-407e-a6d9-11fafa42a631','六祖傳付偈頌 初祖 其一','黄裳','宋','宋诗','song-poetry','','[]','一花迦葉離塵果，四卷楞伽助道書。',32,'全唐诗/poet.song.54000.json','["一花迦葉離塵果，四卷楞伽助道書。", "莫謂竺乾天樣遠，片雲歸去祇須臾。"]'),
('51359625-cd78-46f5-a991-85c6833a9fe3','六祖傳付偈頌 初祖 其二','黄裳','宋','宋诗','song-poetry','','[]','誰知花葉一中生，二氣相催果自成。',32,'全唐诗/poet.song.54000.json','["誰知花葉一中生，二氣相催果自成。", "體了色空無覓處，有時人說見還嬰。"]'),
('172f985e-2b4d-49e7-8b99-7e105930cb36','六祖傳付偈頌 初祖 其三','黄裳','宋','宋诗','song-poetry','','[]','大乘氣象已相扶，吾意方終道不孤。',32,'全唐诗/poet.song.54000.json','["大乘氣象已相扶，吾意方終道不孤。", "秀出五峰塵下少，中華先許到真如。"]'),
('808ce6e3-1044-4221-b31f-3ef8400c119d','六祖傳付偈頌 初祖 其四','黄裳','宋','宋诗','song-poetry','','[]','日用中來體已親，平常是道豈須陳。',32,'全唐诗/poet.song.54000.json','["日用中來體已親，平常是道豈須陳。", "得吾髓處無他事，擬議三人且覓真。"]'),
('81aa5a76-ce87-448e-8d41-f20cfaa6bf37','六祖傳付偈頌 初祖 其五','黄裳','宋','宋诗','song-poetry','','[]','安心惟在覓心時，後世支塵兩自欺。',32,'全唐诗/poet.song.54000.json','["安心惟在覓心時，後世支塵兩自欺。", "寄語禪林休歇去，古來仙聖本無爲。"]'),
('6575792f-311f-4bab-a1dd-470304ccec60','六祖傳付偈頌 初祖 其六','黄裳','宋','宋诗','song-poetry','','[]','本來無一亦無華，都向真空是一家。',32,'全唐诗/poet.song.54000.json','["本來無一亦無華，都向真空是一家。", "聞說一花還共笑，寧甘鬼窟作生涯。"]'),
('dd587074-afc4-4e44-8602-fea7c5de4ce7','六祖傳付偈頌 初祖 其七','黄裳','宋','宋诗','song-poetry','','[]','如意珠，舍利子，建立法身無二理。',128,'全唐诗/poet.song.54000.json','["如意珠，舍利子，建立法身無二理。", "發明道果獨爲師，長養聖胎誰得旨。", "六物名同實非異，微妙如來出塵計。", "一念中含一點來，太無根種豈須猜。", "誰尸五運催神化，忽見天花五葉開。", "含萬類，貫三界，無無無有非私解。", "法輪如我神氣精，塵世通他來去在。", "九年轉了大還丹，世間無價人難買。"]'),
('2d1cca20-7d33-4184-9846-aeaf605cd14e','六祖傳付偈頌 初祖 其八','黄裳','宋','宋诗','song-poetry','','[]','參禪須向坐禪人，本末相通可了真。',32,'全唐诗/poet.song.54000.json','["參禪須向坐禪人，本末相通可了真。", "二念回機都掃盡，乾坤猶在一微塵。"]'),
('24684e76-4962-482c-ad02-a99b0985e045','六祖傳付偈頌 初祖 其九','黄裳','宋','宋诗','song-poetry','','[]','精傳神氣一傳精，性命於中附會成。',32,'全唐诗/poet.song.54000.json','["精傳神氣一傳精，性命於中附會成。", "道世渾淪窺不破，更從何處覓無生。"]'),
('3d49b9d2-7634-4929-8707-00e0847389bf','六祖傳付偈頌 初祖 其一○','黄裳','宋','宋诗','song-poetry','','[]','精傳神氣一傳精，含作真空萬化行。',32,'全唐诗/poet.song.54000.json','["精傳神氣一傳精，含作真空萬化行。", "是物此中來與去，莫持偏性作圓成。"]'),
('78631e6c-04f0-4499-80a4-02c08e6d4623','六祖傳付偈頌 初祖 其一一','黄裳','宋','宋诗','song-poetry','','[]','天游杳杳海漫漫，無有無無是道觀。',32,'全唐诗/poet.song.54000.json','["天游杳杳海漫漫，無有無無是道觀。", "大法藥兼心地要，兩門都作混成看。"]'),
('02713952-8838-496f-8ea4-f86b593d7bec','六祖傳付偈頌 初祖 其一二','黄裳','宋','宋诗','song-poetry','','[]','神光中見一還嬰，非外非中已混成。',32,'全唐诗/poet.song.54000.json','["神光中見一還嬰，非外非中已混成。", "忽向玉爐飛上去，數聲靈鵲夜來驚。"]'),
('097f9d49-231a-4372-96d8-430cf1d2bab4','六祖傳付偈頌 初祖 其一三','黄裳','宋','宋诗','song-poetry','','[]','萬枝燈，千江月，一燈傳，一月攝。',64,'全唐诗/poet.song.54000.json','["萬枝燈，千江月，一燈傳，一月攝。", "莫知根種有虛空，祇見祥光無斷絕。", "三千世界掌中知，百億化身天下說。", "秘密豈當容易談，一臂尤輕冷欺雪。"]'),
('2d474a11-3a22-4685-ae06-707ab6f25592','六祖傳付偈頌 二祖 其一','黄裳','宋','宋诗','song-poetry','','[]','有地有花空具色，無花無種色含空。',32,'全唐诗/poet.song.54000.json','["有地有花空具色，無花無種色含空。", "混成一物誰圓就，但向無言一化工。"]'),
('d7b7868a-5565-4e11-afbf-0bebb4473980','六祖傳付偈頌 二祖 其二','黄裳','宋','宋诗','song-poetry','','[]','受果時來合見仙，香山禪定想多年。',32,'全唐诗/poet.song.54000.json','["受果時來合見仙，香山禪定想多年。", "少林得旨圓融了，不在中間與兩邊。"]'),
('61f55549-2d3a-468b-b571-5be58d91970b','六祖傳付偈頌 二祖 其三','黄裳','宋','宋诗','song-poetry','','[]','華豈曾生種亦無，邇來何事得神珠。',32,'全唐诗/poet.song.54000.json','["華豈曾生種亦無，邇來何事得神珠。", "塵凡不悟無爲旨，但笑高人一似愚。"]'),
('e8d43dad-a133-4ab2-a89f-e81d592c2545','六祖傳付偈頌 二祖 其四','黄裳','宋','宋诗','song-poetry','','[]','曾窮莊易到源淵，三教從來共本根。',32,'全唐诗/poet.song.54000.json','["曾窮莊易到源淵，三教從來共本根。", "自到少林應已悟，後來誰爲曉宗門。"]'),
('1964c77b-f4bf-4a7c-9d8f-ac384f583e71','六祖傳付偈頌 二祖 其五','黄裳','宋','宋诗','song-poetry','','[]','宿來緣累尚相拘，何事圓成未自如。',32,'全唐诗/poet.song.54000.json','["宿來緣累尚相拘，何事圓成未自如。", "十地三乘誰便了，了時猶待到無無。"]'),
('6649ae06-9468-4a75-b784-eefc276a1c35','六祖傳付偈頌 三祖 其一','黄裳','宋','宋诗','song-poetry','','[]','入道從來自有緣，許誰心地是金仙。',32,'全唐诗/poet.song.54000.json','["入道從來自有緣，許誰心地是金仙。", "如來止止教休說，妙法難思莫妄傳。"]'),
('9c2b5c53-decc-4b5a-b668-37e5d7293646','六祖傳付偈頌 三祖 其二','黄裳','宋','宋诗','song-poetry','','[]','衣法曾傳莫己知，兩山禪定了何疑。',32,'全唐诗/poet.song.54000.json','["衣法曾傳莫己知，兩山禪定了何疑。", "本無一物非何有，大道寧嫌得小兒。"]'),
('98e723e0-7119-4ce4-b0c8-23450659e6ff','六祖傳付偈頌 三祖 其三','黄裳','宋','宋诗','song-poetry','','[]','地種精華總是無，無中和會一神珠。',32,'全唐诗/poet.song.54000.json','["地種精華總是無，無中和會一神珠。", "前緣誰是傳衣子，水月如心可上圖。"]'),
('f6232f5b-231c-4339-8609-50c1d525bc1a','六祖傳付偈頌 四祖 其一','黄裳','宋','宋诗','song-poetry','','[]','萬寶收還萬合中，更尋心地亦還空。',32,'全唐诗/poet.song.54000.json','["萬寶收還萬合中，更尋心地亦還空。", "紫雲蓋下已呈瑞，佛法一枝誰與同。"]'),
('287d4a6d-186a-4ba8-9a0e-22e23bad6a8b','六祖傳付偈頌 四祖 其二','黄裳','宋','宋诗','song-poetry','','[]','路上相逢即是緣，心知衣法有人傳。',32,'全唐诗/poet.song.54000.json','["路上相逢即是緣，心知衣法有人傳。", "真成浄土含諸種，直到生生始得仙。"]'),
('6ab4c362-0934-4784-96a0-90271ba39231','六祖傳付偈頌 四祖 其三','黄裳','宋','宋诗','song-poetry','','[]','解脫門中宿已知，種花生性豈須期。',32,'全唐诗/poet.song.54000.json','["解脫門中宿已知，種花生性豈須期。", "詔書四反終難起，不要浮名不待時。"]'),
('712b1f79-6940-42c5-b705-3201d1da7459','六祖傳付偈頌 五祖 其一','黄裳','宋','宋诗','song-poetry','','[]','情種俱收入混成，還并四事得無生。',32,'全唐诗/poet.song.54000.json','["情種俱收入混成，還并四事得無生。", "字雖不識人休笑，壁上留題已可驚。"]'),
('af2b3dff-ffa6-4350-a73f-67de0a1a5143','六祖傳付偈頌 五祖 其二','黄裳','宋','宋诗','song-poetry','','[]','無生無種菩提就，非佛非心混沌成。',32,'全唐诗/poet.song.54000.json','["無生無種菩提就，非佛非心混沌成。", "欲說性空何處覓，可憐禪律謾相爭。"]'),
('c0d6de47-27f0-4bcb-8719-094d5c16db9e','六祖傳付偈頌 五祖 其三','黄裳','宋','宋诗','song-poetry','','[]','形生收攝出塵籠，一顆圓光色與空。',32,'全唐诗/poet.song.54000.json','["形生收攝出塵籠，一顆圓光色與空。", "槽廠有人來作祖，自然吟入太無中。"]'),
('cfe1d1ee-ebf3-4f57-809b-e793555313b3','六祖傳付偈頌 五祖 其四','黄裳','宋','宋诗','song-poetry','','[]','塵埃可佛是修時，無物無修秀也知。',32,'全唐诗/poet.song.54000.json','["塵埃可佛是修時，無物無修秀也知。", "欲說菩提符祖意，圓明來處想曾窺。"]'),
('22651935-938c-48d7-81f7-2b76a6e9611e','六祖傳付偈頌 六祖 其一','黄裳','宋','宋诗','song-poetry','','[]','頓悟花情有幾人，源流相遠却非真。',32,'全唐诗/poet.song.54000.json','["頓悟花情有幾人，源流相遠却非真。", "須知佛性無南北，芥子中藏萬法輪。"]'),
('f49a9a6c-6e2b-4ca7-bdf3-bf118897cf2f','六祖傳付偈頌 六祖 其二','黄裳','宋','宋诗','song-poetry','','[]','泰定猶忘相行深，種華當向此中生。',32,'全唐诗/poet.song.54000.json','["泰定猶忘相行深，種華當向此中生。", "坐禪只恐人無證，得旨須教礦作金。"]'),
('f987d190-0e46-4c1f-ae2b-334c1a3f08db','六祖傳付偈頌 六祖 其三','黄裳','宋','宋诗','song-poetry','','[]','下種人來地有因，若非因地若輕陳。',32,'全唐诗/poet.song.54000.json','["下種人來地有因，若非因地若輕陳。", "曾將此子教誰種，安解參同向呂真。"]'),
('5b6304c9-410f-4210-a80c-4000de453eb4','六祖傳付偈頌 六祖 其四','黄裳','宋','宋诗','song-poetry','','[]','從來生滅本因心，旁出紛紛沒處尋。',32,'全唐诗/poet.song.54000.json','["從來生滅本因心，旁出紛紛沒處尋。", "無性無心方是道，執空誰可脫浮沉。"]'),
('9e0f288b-c95f-4762-b175-1c0af5fcc7c0','六祖傳付偈頌 六祖 其五','黄裳','宋','宋诗','song-poetry','','[]','法身行止本來無，葉落歸根是幻軀。',32,'全唐诗/poet.song.54000.json','["法身行止本來無，葉落歸根是幻軀。", "生滅已除還寂滅，有情相感莫踟躕。"]'),
('5b9beaba-984d-4d62-829d-210595e497de','六祖傳付偈頌 六祖 其六','黄裳','宋','宋诗','song-poetry','','[]','曾戒觀空與坐禪，惟因唐使說真筌。',32,'全唐诗/poet.song.54000.json','["曾戒觀空與坐禪，惟因唐使說真筌。", "九年面壁誰能少，秘密先當得祖傳。"]'),
('04f14bc5-d183-4652-b492-3ede4d96645d','六祖傳付偈頌 六祖 其七','黄裳','宋','宋诗','song-poetry','','[]','妙了形神更有人，不須捐下夢中身。',32,'全唐诗/poet.song.54000.json','["妙了形神更有人，不須捐下夢中身。", "逍遙便作丹臺客，誰悟三丹有二真。"]'),
('66f1d5a7-1100-4fc5-b788-3bf73b0afcd7','六祖傳付偈頌 六祖 其八','黄裳','宋','宋诗','song-poetry','','[]','大事從來夙有因，太空全是氣精神。',32,'全唐诗/poet.song.54000.json','["大事從來夙有因，太空全是氣精神。", "牟尼莫怪無人問，作用皆云已得真。"]'),
('6fae23cf-9c93-4472-891f-588dbda5c1f3','六祖傳付偈頌 六祖 其九','黄裳','宋','宋诗','song-poetry','','[]','圓妙高人覺已通，便辭歸去謾參同。',32,'全唐诗/poet.song.54000.json','["圓妙高人覺已通，便辭歸去謾參同。", "一篇證道誰能賽，不謂唐僧有此風。"]'),
('10c79ca8-8b08-4da7-9ed0-88bb453d7ad0','六祖傳付偈頌 六祖 其一○','黄裳','宋','宋诗','song-poetry','','[]','道果天成豈可猜，圓光何處更尋臺。',32,'全唐诗/poet.song.54000.json','["道果天成豈可猜，圓光何處更尋臺。", "性爲妙種心爲地，况有慈雲作雨來。"]'),
('7f9a878c-0080-4f6a-9a04-2dec47ee5b6c','泗洲頌','黄裳','宋','宋诗','song-poetry','','[]','十數運行天與地，五氣生成入無始。',72,'全唐诗/poet.song.54000.json','["十數運行天與地，五氣生成入無始。", "混成惟一數相尋，十一觀音生一體。", "耳如目，聽如視，通身是眼誰能計，觀盡十方無巨細。", "有時塔上聳人看，妙用無方乃餘事。"]'),
('86699bed-93d8-4313-89a2-dcd57348e0ed','上天竺思尚真讚','黄裳','宋','宋诗','song-poetry','','[]','貌像雖相似，水中空捉月。',24,'全唐诗/poet.song.54000.json','["貌像雖相似，水中空捉月。", "非教亦非禪，使我如何說。"]'),
('af0cfb17-2cd6-4045-9329-03fd9d94d72e','讀頭陀安文頌','黄裳','宋','宋诗','song-poetry','','[]','九九八十一，圓明體如日。',48,'全唐诗/poet.song.54000.json','["九九八十一，圓明體如日。", "豈是空說禪，精魂中掃迹。", "立道須當修，九九八十一。", "性見與意會，如何體空色。"]'),
('1050f571-2754-4e06-883c-7ef143e2a206','朱氏天和堂','黄裳','宋','宋诗','song-poetry','','[]','谷水悠悠水天闊，綠竹漪漪玉龍活。',144,'全唐诗/poet.song.54000.json','["谷水悠悠水天闊，綠竹漪漪玉龍活。", "天和堂在翠微中，堂上誰誇青瑣闥。", "二俊昔爲才所驅，未識危邦何太愚。", "輕抱雄文走西洛，漫勞黄耳尋中吳。", "豈謂七百有餘載，乃獲夫子營我廬。", "能向平時脫羈絡，爲悟浮雲此生錯。", "通道益深醉隠亭，載鵬風厚逍遙閣。", "萬累紛紛無處尋，須信天和有斯樂。", "彼哉二俊胡不歸，空歎華亭數聲鶴。"]'),
('c78314bb-ac69-4c25-b9ea-d16b4406985f','雷擊南劍州譙門柱','黄裳','宋','宋诗','song-poetry','','[]','風雷昨夜破枯株，借問天公有意無。',32,'全唐诗/poet.song.54000.json','["風雷昨夜破枯株，借問天公有意無。", "莫是臥龍蹤迹困，放開頭角入亨衢。"]'),
('92b2cd53-d2fb-4dff-91a2-0ba8cad19511','朝元閣','黄裳','宋','宋诗','song-poetry','','[]','東別家山十六程，曉來和月到華清。',32,'全唐诗/poet.song.54000.json','["東別家山十六程，曉來和月到華清。", "朝元閣下西風急，都入長楊作雨聲。"]'),
('08d27596-5287-4de7-960f-5e66da6405c5','贈探花郎','黄裳','宋','宋诗','song-poetry','','[]','探花車騎似游龍，未入桃源先閬風。',64,'全唐诗/poet.song.54000.json','["探花車騎似游龍，未入桃源先閬風。", "衫上十分新染翠，衣間一點半開紅。", "身如驥子無雙俊，人報鼇山第幾宮。", "便是醉仙何處去，上林園在五雲中。"]'),
('683b5395-a49b-46ac-af08-5b1445dd8aa4','樓鑰水月圖','黄裳','宋','宋诗','song-poetry','','[]','具美盃殘意未休，相將重上望湖樓。',64,'全唐诗/poet.song.54000.json','["具美盃殘意未休，相將重上望湖樓。", "樓臺忽已居平地，風月何曾識舊游。", "更挈酒樽過水月，坐增詩興滿滄洲。", "春風共約新橋畔，遙拜雙龍萬斛舟。"]'),
('8fdb3246-3487-498f-9b00-5140c025d6f1','句  其一','黄裳','宋','宋诗','song-poetry','','[]','任爾巍峨千萬丈，也須還我上頭行。',16,'全唐诗/poet.song.54000.json','["任爾巍峨千萬丈，也須還我上頭行。"]'),
('227ccf76-6f2c-4165-85ab-8c85de418bd1','句  其二','黄裳','宋','宋诗','song-poetry','','[]','凌波應作水中仙。',8,'全唐诗/poet.song.54000.json','["凌波應作水中仙。"]'),
('934324c8-a4df-46e4-9c25-deb070dfcd2f','句  其三','黄裳','宋','宋诗','song-poetry','','[]','朝元閣成老君現。',8,'全唐诗/poet.song.54000.json','["朝元閣成老君現。"]'),
('56990f68-d78b-407d-8c69-25cf2a669cc0','偕冕仲雪中聯句','王道觀','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.54000.json','["無正文。"]'),
('2342b09c-f798-49e4-b15d-ec8862e3a353','梳洗臺','王震','宋','宋诗','song-poetry','','[]','俗緣磨未盡，空山傍妝臺。',24,'全唐诗/poet.song.54000.json','["俗緣磨未盡，空山傍妝臺。", "溪雲惹粉黛，巖花寶靨開。"]'),
('3a12210c-d09a-4e90-b42f-3738fe4b4799','雪','王震','宋','宋诗','song-poetry','','[]','未送餘寒歸嶰谷，先傳春信到花叢。',32,'全唐诗/poet.song.54000.json','["未送餘寒歸嶰谷，先傳春信到花叢。", "侵凌竹色回新綠，點注梅梢破小紅。"]'),
('37192139-ecb3-4ad3-a24e-51ac085b435a','句  其一','張仲時','宋','宋诗','song-poetry','','[]','太平功業屬男兒，虹蜺萬丈雲中氣。',16,'全唐诗/poet.song.54000.json','["太平功業屬男兒，虹蜺萬丈雲中氣。"]'),
('1cfd6f60-a68b-49c5-82bb-89a91d0ef42d','句  其二','張仲時','宋','宋诗','song-poetry','','[]','一源湛湛攀清疏，今日樽前逢一笑。',16,'全唐诗/poet.song.54000.json','["一源湛湛攀清疏，今日樽前逢一笑。"]'),
('a1fccc99-80fc-405e-b440-cdf74922e4cf','留題大雲寺石洞','鄧□誥','宋','宋诗','song-poetry','','[]','大雲陰洞石嶄然，跳攫□□萬狀全。',64,'全唐诗/poet.song.54000.json','["大雲陰洞石嶄然，跳攫□□萬狀全。", "□海醜神殭且死，吳江恚浪凍來堅。", "元功□物窺天藴，巨手題詩玩化權。", "勿訝荒唐非格調，勾□傲吏醉成篇。"]'),
('deebc4a5-2b9e-4e92-8b22-ff8ce5938d01','和慎思詩呈同院諸公  其一','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，羣賢道足依。',48,'全唐诗/poet.song.54000.json','["秋日同文館，羣賢道足依。", "心遊黄卷靜，目送白雲歸。", "寶玉荆山盡，文星禁掖稀。", "清談欣屢接，紛若落瓊璣。"]'),
('04bc0214-1161-47ef-8f8a-8cf03ccc4426','和慎思詩呈同院諸公  其二','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，雲沉夕照光。',48,'全唐诗/poet.song.54000.json','["秋日同文館，雲沉夕照光。", "蛩吟階下草，螢照屋間梁。", "臥月搜詩句，挑燈認藥囊。", "夜闌獨衾枕，歸夢楚山長。"]'),
('a36e5296-c5d6-4cc8-a837-20812ccf732f','和慎思詩呈同院諸公  其三','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，愁腸夜九回。',48,'全唐诗/poet.song.54000.json','["秋日同文館，愁腸夜九回。", "圖書堆枕畔，歌吹隔牆隈。", "宿鳥翻枝去，凉風带雨來。", "新詩勞見寄，難繼謫仙才。"]'),
('8ed9ef77-8905-44c1-9ab8-a3ab9140bb07','和慎思詩呈同院諸公  其四','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，羣書晝可依。',48,'全唐诗/poet.song.54000.json','["秋日同文館，羣書晝可依。", "衰遲多病在，留滯故園歸。", "但怕酒杯滿，莫教詩卷稀。", "惟羞狂斐句，瓦礫報珍璣。"]'),
('326dd565-8857-4dd8-9d70-fdb805ee8904','和慎思詩呈同院諸公  其五','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，晨暉带冷光。',48,'全唐诗/poet.song.54000.json','["秋日同文館，晨暉带冷光。", "綵雲瞻鳳闕，細雨憶魚梁。", "久事班超筆，空嗟趙壹囊。", "簾閒坐無語，千丈旅愁長。"]'),
('1c6a02f3-690b-4f7f-a998-535d7fb03089','和慎思詩呈同院諸公  其六','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，西風昨夜回。',48,'全唐诗/poet.song.54000.json','["秋日同文館，西風昨夜回。", "燕巢留屋角，蛛網掛牆隈。", "書任邊韶懶，詩慚匡鼎來。", "人人皆抱璞，誰是濟川才。"]'),
('117e11ee-cbed-4c6a-a264-8d51a068c8ca','和慎思秋日同文館  其一','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，高堂燕集齊。',48,'全唐诗/poet.song.54000.json','["秋日同文館，高堂燕集齊。", "杯盤供魯酒，殽核欠張梨。", "楊孟持新論，韓莊鄙舊題。", "須知宗匠手，文采冠朝閨。"]'),
('4240cece-2815-426e-860f-0a4e561e0eee','和慎思秋日同文館  其二','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，何人獨擅場。',48,'全唐诗/poet.song.54000.json','["秋日同文館，何人獨擅場。", "養莪方在沚，琢玉已成章。", "筆列千鋒陣，庭焚一炷香。", "得賢從此始，豈特致民康。"]'),
('266118fe-8dcc-4314-abde-7c7b33c4921d','和慎思秋日同文館  其三','商倚','宋','宋诗','song-poetry','','[]','秋日同文館，棲林看晚雞。',48,'全唐诗/poet.song.54000.json','["秋日同文館，棲林看晚雞。", "斗垂宮殿北，月轉戶庭西。", "酒勸杯中淥，詩分燭下題。", "何時還九陌，細雨莫成泥。"]'),
('4b368f56-5a88-4dcd-94e4-9d9b0736ea1f','和慎思未試即事雜書率用秋日同文館爲首句  其一','商倚','宋','宋诗','song-poetry','','[]','氣候逢秋晏，蛩鳴入戶闈。',48,'全唐诗/poet.song.54000.json','["氣候逢秋晏，蛩鳴入戶闈。", "簷空看雀鬭，天闊暮鴉歸。", "風急飄庭葉，寒光著客衣。", "重陽故人境，應念賞心違。"]'),
('56255638-2a71-4a47-a4f9-acbbc7ebacb5','和慎思未試即事雜書率用秋日同文館爲首句  其二','商倚','宋','宋诗','song-poetry','','[]','門深廛市遠，幽寂興何長。',48,'全唐诗/poet.song.54000.json','["門深廛市遠，幽寂興何長。", "徑菊晴披艷，窗風晚逗凉。", "聖經閒裏醉，塵鎖夢中忘。", "更苦年來病，時看肘後方。"]'),
('ed6d451e-1237-4396-a7c1-016bf4a2bf69','和慎思未試即事雜書率用秋日同文館爲首句  其三','商倚','宋','宋诗','song-poetry','','[]','旁舍回廊接，重簾晝日開。',48,'全唐诗/poet.song.54000.json','["旁舍回廊接，重簾晝日開。", "鳴蟬隨雨退，疏雁拂雲來。", "吟興降難韵，羈懷寄淺杯。", "驚飆漸凄緊，又欲作寒媒。"]'),
('d3d162ac-3feb-49b5-a571-ec361e3c4b04','和慎思初入試院','商倚','宋','宋诗','song-poetry','','[]','承詔掄材敢倦行，廣庭深鎖待羣英。',64,'全唐诗/poet.song.54000.json','["承詔掄材敢倦行，廣庭深鎖待羣英。", "分場自敵三千客，决勝誰降七十城。", "夜案尚閒塗卷筆，曉堂方聽讀書聲。", "歸時還有黄花否，已覺秋風滿袖生。"]'),
('882823a9-18dd-4950-be55-a36e0d047861','次韵余幹試院即事呈諸公','商倚','宋','宋诗','song-poetry','','[]','風生簾幕撼層波，况值清秋一半過。',64,'全唐诗/poet.song.54000.json','["風生簾幕撼層波，况值清秋一半過。", "堂上簪裾方鷺集，案間圖史已星羅。", "東籬採菊朝嘗酒，北里吹竽夜聽歌。", "早晚奏名聞黼坐，望中無奈白雲何。"]'),
('4ad70ba5-c12e-4f27-98f2-471033fc6804','再呈慎思諸公兼以言懷','商倚','宋','宋诗','song-poetry','','[]','南窗寂若隠山河，時枉金門步見過。',64,'全唐诗/poet.song.54000.json','["南窗寂若隠山河，時枉金門步見過。", "談笑且看揮麈玉，篇章寧惜洒牋羅。", "已羞軒冕嬰身住，更問功名撫劍歌。", "賒得凉秋好風月，不成吟醉奈愁何。"]'),
('be7b8c9f-8319-4247-a687-3ed4c100697c','次韵重九之什  其一','商倚','宋','宋诗','song-poetry','','[]','英豪獻策廣庭中，問辨紛紛似叩鐘。',64,'全唐诗/poet.song.54000.json','["英豪獻策廣庭中，問辨紛紛似叩鐘。", "名奏九重書密上，士欣千載運親逢。", "鶑鳴定獲喬林樂，鳳舉應容衆羽從。", "盛世文章由此變，坐看風俗反醇濃。"]'),
('03232f99-1441-432f-88f0-f317b76e7fea','次韵重九之什  其二','商倚','宋','宋诗','song-poetry','','[]','昔年此日故園東，爛醉牛山到暮鐘。',64,'全唐诗/poet.song.54000.json','["昔年此日故園東，爛醉牛山到暮鐘。", "已往光陰那再得，如今羈旅又重逢。", "淵明把菊情雖厚，子美登臺願莫從。", "且看羣書欹枕臥，病多仍負酒杯濃。"]'),
('743f2ba2-ccfb-4bd3-bd9d-0b984d9306dc','和慎思同舍問及故山景物用鍾字韵詩以答','商倚','宋','宋诗','song-poetry','','[]','先生家住翠微峰，萬卷詩書酒一鍾。',64,'全唐诗/poet.song.54000.json','["先生家住翠微峰，萬卷詩書酒一鍾。", "壁掛葛巾無客到，雲藏古洞有仙逢。", "溪邊晚釣呼鷗伴，花底春吟引鶴從。", "只恐舊山歸未得，帝恩朝夕露濃濃。"]'),
('3a68e6eb-6eeb-49fd-9c73-bcf080d17ad9','題萬年妙蓮閣','呂仲甫','宋','宋诗','song-poetry','','[]','千尺杉前帝釋宮，種蓮不用百花叢。',64,'全唐诗/poet.song.54000.json','["千尺杉前帝釋宮，種蓮不用百花叢。", "石橋路近橫天外，池水光寒坐檻中。", "紅日几窗新活計，白雲香火舊家風。", "虎溪社客今憔悴，此意憑誰謝遠公。"]'),
('c6ae4232-eba3-45e5-8560-6c111ccd9580','送羅正之年兄出使二浙','呂仲甫','宋','宋诗','song-poetry','','[]','錫馬恩隨汴楫浮，過家身近石橋遊。',64,'全唐诗/poet.song.54000.json','["錫馬恩隨汴楫浮，過家身近石橋遊。", "勤勞王事甘胼手，磨琢風騷苦白頭。", "浙水魚龍移窟宅，浚郊陂澤變田疇。", "使君亮直人知少，好笑封侯曲似鈎。"]'),
('405d7a64-6ec9-4be6-befb-274d235e57e5','送程給事知越州','余中','宋','宋诗','song-poetry','','[]','會稽太守垂金魚，玉杯宴客離京都。',208,'全唐诗/poet.song.54000.json','["會稽太守垂金魚，玉杯宴客離京都。", "曾騎天馬出沙漠，萬里行冰渡河朔。", "歸來却厭承明廬，欲學鴟夷蹈寥廓。", "三吳風物故鄉關，人望旌旗何日還。", "壺漿勞問有耆老，杖策登臨知舊山。", "清江一水分吳越，越山岧嶢更孤絕。", "禹穴烟霞翠不收，往往雲中見仙闕。", "秋風剡溪生早凉，鑑湖一夜飛清霜。", "綵舟繫纜浣紗石，綺筵應得調笙篁。", "此時詩興誰能禦，照耀驪珠月宮吐。", "祇恐彤庭急詔催，桃源不許長爲主。", "都門疏雨柳輕明，送客蕭蕭千馬鳴。", "須臾畫鷁東飛去，欻見淮山天外青。"]'),
('ff55d407-852a-441b-9d54-8b36155a6281','歸田','徐勣','宋','宋诗','song-poetry','','[]','懸車疏上動龍顔，幾度陳辭始放還。',64,'全唐诗/poet.song.54000.json','["懸車疏上動龍顔，幾度陳辭始放還。", "敢憶溪山孤聖眷，只緣衰病乞身閑。", "都門祖餞心情劇，里舍招邀禮數刪。", "最喜兒孫解農事，稻花香滿舊田間。"]'),
('044b842c-cf15-4d99-94f4-89694550c784','望舊廬有感','葉濤','宋','宋诗','song-poetry','','[]','重來舊屋誰爲主，江令蕭條歎獨存。',64,'全唐诗/poet.song.54000.json','["重來舊屋誰爲主，江令蕭條歎獨存。", "已愧問人纔知路，更悲無柳可知門。", "舟車到處成家宅，歲月惟驚長子孫。", "孤客濫巾非得已，故交零落與誰論。"]'),
('49c7cb3b-a8ba-4597-90d5-36105b59805e','句','葉濤','宋','宋诗','song-poetry','','[]','碾成天上龍兼鳳，煮出人間蟹與蝦。',16,'全唐诗/poet.song.54000.json','["碾成天上龍兼鳳，煮出人間蟹與蝦。"]'),
('62e82966-71dd-4708-b070-f1565c59327f','題壁絕句','龔程','宋','宋诗','song-poetry','','[]','月度疏櫺起更慵，坐聽澄照五更鐘。',32,'全唐诗/poet.song.54000.json','["月度疏櫺起更慵，坐聽澄照五更鐘。", "却思潮上西興急，風遶山前萬箇松。"]'),
('55352485-dbd0-43f3-a0f5-d7bbe8cbb1b0','題永慶院一覽亭','丁注','宋','宋诗','song-poetry','','[]','插迥飛簷聳，淩虛疊砌危。',48,'全唐诗/poet.song.54000.json','["插迥飛簷聳，淩虛疊砌危。", "四天欄下揖，萬象掌中窺。", "目力不到處，雲容無盡時。", "塵塵皆勝事，凭檻幾人知。"]'),
('1640cb13-864e-42c9-b61d-1e4a95e24481','真覺院','夏臻','宋','宋诗','song-poetry','','[]','半天聞梵唱，一徑踏松陰。',24,'全唐诗/poet.song.54000.json','["半天聞梵唱，一徑踏松陰。", "起石雲千仞，懸空瀑萬尋。"]'),
('960802f0-446b-458a-9bd9-cb7ca9d2210c','題竹軒','吳亶','宋','宋诗','song-poetry','','[]','虛室澄心近竹開，雪中無事共徘徊。',64,'全唐诗/poet.song.54000.json','["虛室澄心近竹開，雪中無事共徘徊。", "不須翠柏亭前見，自有清風座上來。", "林小未宜輕瘦節，歲寒方可看高材。", "支公適好誠何在，豈謂香嚴擊俊雷。"]'),
('6f028639-c30f-4e4f-aa0c-dbe06297fafb','題張公翊清溪圖','張勵','宋','宋诗','song-poetry','','[]','九華鬰兮江南山，清溪下兮貫山間。',320,'全唐诗/poet.song.54000.json','["九華鬰兮江南山，清溪下兮貫山間。", "江北騖兮溪東旋，濁湯湯兮清漫漫。", "山幾轉兮水幾盤，近交臂兮遠連環。", "决天末兮浮雲端，齊之山兮秋之浦。", "景晦明兮氣吞吐，草木蓊兮媚林莽。", "繡屏張兮翠綃舞，深窈窕兮掩幽塢。", "雨吟猿兮風嘯虎，下鳬雁兮泳魴鱮。", "商之檣兮漁之罟，互出沒兮更散聚。", "樵有舍兮梵有宇，雲巖阿兮棘樊圃。", "翬連甍兮岸之滸，弄潺湲兮棹容與。", "中橫絕兮梁爲渡，隠孤城兮其西去。", "春之朝兮秋之夕，風既清兮月又白。", "遐矯首兮俯陳迹，携佳人兮不可得。", "空遠望兮中感百，思悠悠兮情惻惻。", "悵興亡兮懷今昔，獨茲溪兮無終極。", "嗟夫人兮擺塵滓，遙徜徉兮玩山水。", "移山川兮置窗几，手舒卷兮千萬里。", "輈余車兮秣余馬，往其從兮山之下。", "枻吾舟兮泛清瀉，樂魚鳥兮放林野。", "願未適兮胡爲者，聊寓言兮公墨畫。"]'),
('3ec6c48b-fa13-4d83-be8d-f6ca022e7c13','句  其一','張勵','宋','宋诗','song-poetry','','[]','莫言伯道無兒嗣，看取千秋祀事存。',16,'全唐诗/poet.song.54000.json','["莫言伯道無兒嗣，看取千秋祀事存。"]'),
('2ae662c8-45f2-4b27-9ac7-08064f28c613','句  其二','張勵','宋','宋诗','song-poetry','','[]','青林蔽日明爲晦，紺宇生風暑亦秋。',16,'全唐诗/poet.song.54000.json','["青林蔽日明爲晦，紺宇生風暑亦秋。"]'),
('1ef1b331-5ebb-47e8-ad24-7727fbbe83a6','武山','張汝賢','宋','宋诗','song-poetry','','[]','雨過僧房景更奇，邀朋閒訪此遊嬉。',32,'全唐诗/poet.song.54000.json','["雨過僧房景更奇，邀朋閒訪此遊嬉。", "一登占得嵯峨處，始覺羣峰迤邐低。"]'),
('182a7155-fb54-49a1-932c-a7b5e237ebc2','仙居寺','毛沂','宋','宋诗','song-poetry','','[]','肉山六月火雲蒸，渴想滹沱一片冰。',32,'全唐诗/poet.song.54000.json','["肉山六月火雲蒸，渴想滹沱一片冰。", "回首家山林下寺，水簾深處定中僧。"]'),
('0db2a490-bb8c-4cf8-8ef8-f83bce5f632b','呈東坡','何恭','宋','宋诗','song-poetry','','[]','昔日歐陽心獨苦，搜羅天下文中虎。',384,'全唐诗/poet.song.54000.json','["昔日歐陽心獨苦，搜羅天下文中虎。", "未逢賈馬嗟誰有，崑體文章正旁午。", "一得眉山老翁語，始愜平生好奇古。", "騫騰鸞鳳螭虬侶，錦繡腎腸終日吐。", "眉山跨馬挾雙龍，迤邐斜欹劍閣東。", "一息萬里先羣雄，是日魯酒歸醇醲。", "仁廟當朝起數公，四時閶闔來清風。", "眉山秉筆摩蒼穹，稽首獻議何雍容。", "是時慶曆垂嘉祐，東省西垣半耆舊。", "一代偉人爭入彀，大開黄閣咸虛受。", "公時脫穎眉山後，歆向機雲同一奏。", "建安數子空鳴脰，集賢學士皆籠袖。", "玉人發馬下天階，華蓋星邊捧詔來。", "天子延英不浪開，爲公此日深徘徊。", "金吾侍側天顔低，上列四輔前三台。", "相與疇咨將相材，飄然八駿先龍媒。", "西京應制十八九，晁董褎然爲舉首。", "此輩昂藏希世有，劉蕡又作蛟龍吼。", "觀公舉勸新人手，玉壺破碎珠囊剖。", "許國誠心仍貫斗，識者談之不容口。", "天公一見列詩曹，指揮姮娥供兔毫。", "公歌數闕風刁刁，若耶溪上皆停橈。", "郢客擲筆不敢操，楚人往往收離騷。", "李杜藩牆不甚牢，李白脫却錦繡袍。"]'),
('999fc493-8a60-4ace-aabc-0dba4362c9bb','猿嶠','傅翼','宋','宋诗','song-poetry','','[]','參差茅屋带村烟，驛路崎嶇石岸邊。',64,'全唐诗/poet.song.54000.json','["參差茅屋带村烟，驛路崎嶇石岸邊。", "風物盡成三谷景，溪山分斷七閩天。", "夜猿乘月悲霜樹，秋石和雲瀉澗泉。", "謝守來遊幾千載，何人能爲續佳篇。"]'),
('c925c95f-87dd-4373-b156-be8f092d9c6a','福山寺','傅翼','宋','宋诗','song-poetry','','[]','隠隠晴空露翠微，也知深處有禪扉。',32,'全唐诗/poet.song.54000.json','["隠隠晴空露翠微，也知深處有禪扉。", "幾回待入烟霞去，只恐烟霞不放歸。"]'),
('98cd55b5-4db7-4fed-a5e8-cb42923372fe','句','傅翼','宋','宋诗','song-poetry','','[]','寂寞不勝情。',6,'全唐诗/poet.song.54000.json','["寂寞不勝情。"]'),
('441590a6-56e4-4f68-984d-2a7492c17ee4','且止堂','吳干','宋','宋诗','song-poetry','','[]','無心終日看雲飛，空幻猶如鳥跡遺。',32,'全唐诗/poet.song.54000.json','["無心終日看雲飛，空幻猶如鳥跡遺。", "欲問堂中常住相，黄花翠竹已多知。"]'),
('3e01bddc-686f-4f2e-a5d8-c8ae9bce27f9','靈巖寺  其一','吳栻','宋','宋诗','song-poetry','','[]','丹崖翠壑一重重，香火因緣古寺鐘。',32,'全唐诗/poet.song.54000.json','["丹崖翠壑一重重，香火因緣古寺鐘。", "若有金龍隨玉簡，武夷溪上幔亭峰。"]'),
('959a9e06-2360-4b4f-ad63-def70e0d18f9','靈巖寺  其二','吳栻','宋','宋诗','song-poetry','','[]','一麾邂逅得東秦，憶別家山六度春。',32,'全唐诗/poet.song.54000.json','["一麾邂逅得東秦，憶別家山六度春。", "何意眼看毛竹洞，主人仍是故鄉人。"]'),
('17bfcec3-fb99-45a8-b688-7b3070aad441','靈巖寺  其三','吳栻','宋','宋诗','song-poetry','','[]','大士分身石罅開，輕烟微雨證明臺。',32,'全唐诗/poet.song.54000.json','["大士分身石罅開，輕烟微雨證明臺。", "灑然一覺鄉關夢，換骨巖高好在哉。"]'),
('4b2eaa5d-f64a-497c-8ab9-25ab485ac309','登重光寺','吳栻','宋','宋诗','song-poetry','','[]','上窮蒼石躡丹梯，祖意誰參隻履西。',64,'全唐诗/poet.song.54000.json','["上窮蒼石躡丹梯，祖意誰參隻履西。", "曉閣濃陰雲散嶺，亥堂清影月雙溪。", "池開今日青銅鑑，碑立何年碧玉圭。", "靜覺官名微可笑，南華經裏一醢雞。"]'),
('1b86b452-799d-44a0-bdf5-675f65b9f2b7','蘇老亭','吳栻','宋','宋诗','song-poetry','','[]','蘇老行諸郡，多爲洒落遊。',48,'全唐诗/poet.song.54000.json','["蘇老行諸郡，多爲洒落遊。", "靜心山共止，動意水俱流。", "赴社呼陶令，翻經約謝侯。", "高風誰復記，明月上西樓。"]'),
('8e677510-5b2a-431a-988d-b602ba928a0d','越峰院','吳栻','宋','宋诗','song-poetry','','[]','野僧迎客笑開關，更拂殘碑蘚字班。',64,'全唐诗/poet.song.54000.json','["野僧迎客笑開關，更拂殘碑蘚字班。", "徐姓仙歸空碧洞，越封王去漫青山。", "影來秋月林千缺，聲落春風水一灣。", "焙茗滿甌須强啜，過橋車馬便人間。"]'),
('b65759ae-161a-4636-b270-2fb032a2b2df','暑雪軒','吳栻','宋','宋诗','song-poetry','','[]','呪土臺頭寺，披襟笑語閒。',48,'全唐诗/poet.song.54000.json','["呪土臺頭寺，披襟笑語閒。", "千年雲抱石，六月雪彌山。", "酒熟篘嘗外，茶新輾試間。", "要須時點筆，來此賦躋攀。"]'),
('1577d9d5-ed69-4806-895e-2ee58e1a88c7','和田望再賦暑雪軒','吳栻','宋','宋诗','song-poetry','','[]','石照臺高暑不侵，雪橫天際蜀西岑。',64,'全唐诗/poet.song.54000.json','["石照臺高暑不侵，雪橫天際蜀西岑。", "但知賦客如梁苑，那得參徒似少林。", "月上便成銀色界，風生兼作海潮音。", "可憐火宅人空老，誰解跏趺一解襟。"]'),
('5214c03c-466b-40a8-b7d4-6b5722382143','和周燾合江亭  其一','吳栻','宋','宋诗','song-poetry','','[]','使者風流照錦城，東郊攬轡更澄清。',64,'全唐诗/poet.song.54000.json','["使者風流照錦城，東郊攬轡更澄清。", "春江合處烟凝曉，秀嶺橫邊日弄晴。", "石鼎煮茶濃有味，金鐘注酒釃無聲。", "何時却信橋南步，細讀詩人古柏行。"]'),
('c00d5a92-d178-4f87-a250-f2d3be30f15c','和周燾合江亭  其二','吳栻','宋','宋诗','song-poetry','','[]','聞公載酒合江亭，要使邦人識使星。',64,'全唐诗/poet.song.54000.json','["聞公載酒合江亭，要使邦人識使星。", "宿雨乍晴聊信馬，曉風初熟更揚舲。", "賦成不是緣鸚鵡，詩就當和爲脊令。", "只欠湘靈來鼓瑟，漁歌聲斷數峰青。"]'),
('5830502c-e0b5-47db-bd6c-c2a259a173e4','遊南山','吳栻','宋','宋诗','song-poetry','','[]','但看都梁山拱北，莫尋浮磬水朝東。',48,'全唐诗/poet.song.54000.json','["但看都梁山拱北，莫尋浮磬水朝東。", "此間半築瞿曇室，底處曾營煬帝宮。", "七眼泉邊百無念，一襟披盡晚來風。"]'),
('36b6e4c6-d1ce-484e-bada-97ac309b7128','五峰巖  其一','吳栻','宋','宋诗','song-poetry','','[]','雲烟杳靄環諸峰，石徑詰曲穿疏松。',32,'全唐诗/poet.song.54000.json','["雲烟杳靄環諸峰，石徑詰曲穿疏松。", "更無飛埃趁短屐，祇有鳴溜迎修筇。"]'),
('bc77a7e1-bdea-4932-be72-78737006ef3f','五峰巖  其二','吳栻','宋','宋诗','song-poetry','','[]','玲瓏數竇明相通，造化恍惚真難窮。',32,'全唐诗/poet.song.54000.json','["玲瓏數竇明相通，造化恍惚真難窮。", "陽回三冬照暖日，陰納九夏吹寒風。"]'),
('d7e1cd9c-dac3-4b6e-8ff7-5bc0dcc708a6','寄智翁宣州知府鄉兄','吳栻','宋','宋诗','song-poetry','','[]','使君真是十年兄，投老相看眼更明。',64,'全唐诗/poet.song.54000.json','["使君真是十年兄，投老相看眼更明。", "入省早推何水部，作州今見謝宣城。", "應憐遠岫雲俱曉，定夢澄江月共晴。", "安得陪公觴詠後，春風桃李滿交情。"]'),
('7743b37e-82cd-461b-b21a-58a6ad57e1df','釣臺','吳栻','宋','宋诗','song-poetry','','[]','一水自東流，蕭蕭霜木秋。',48,'全唐诗/poet.song.54000.json','["一水自東流，蕭蕭霜木秋。", "笑談輕萬乘，身世老扁舟。", "薄俗迷方餌，高人悟直鈎。", "至今馴不散，沙上晚來鷗。"]'),
('ae6bdaa4-4581-4ae9-98d7-d6bd8791af00','嚴陵懷古','吳栻','宋','宋诗','song-poetry','','[]','龍衮新天子，羊裘古野人。',48,'全唐诗/poet.song.54000.json','["龍衮新天子，羊裘古野人。", "清名在林藪，高行動星辰。", "風月空齊國，烟霞自富春。", "滄浪秋更碧，不敢濯纓塵。"]'),
('136cdeac-8cae-4527-9f85-d78361b4eee0','佛巖塔','吳栻','宋','宋诗','song-poetry','','[]','灑落巖題宴寂高，旋添香火掛青袍。',64,'全唐诗/poet.song.54000.json','["灑落巖題宴寂高，旋添香火掛青袍。", "霜頭不懼九侯劍，雪臂應□二祖刀。", "月照瓦棺服虎兕，風吹石室嘯狷猿。", "簷前舊雨天花處，循想眉間兩白毫。"]'),
('d66113f9-99c3-4147-8f3e-ff791a1e2c46','登姜相臺  其一','吳栻','宋','宋诗','song-poetry','','[]','滿林紅葉墜紛紛，耆老猶言別駕墳。',64,'全唐诗/poet.song.54000.json','["滿林紅葉墜紛紛，耆老猶言別駕墳。", "舊府光華關右月，故鄉蕭索海南雲。", "酒杯湖上同方伯，茶竈巖邊共隠君。", "二百餘年真一夢，遶牆荒隴半耕耘。"]'),
('d2162647-541c-4f2d-ba10-ac66b0fd40c7','登姜相臺  其二','吳栻','宋','宋诗','song-poetry','','[]','苑門北出禍匆匆，叩馬何人獨記公。',64,'全唐诗/poet.song.54000.json','["苑門北出禍匆匆，叩馬何人獨記公。", "葬厚欲裁寧詐直，謀南能利倍其忠。", "剛各臘後喬林雪，廢迹秋來敗葉風。", "華表千年相對鶴，長看碑鎖舊亭中。"]'),
('e30a78f5-98ac-49cf-9953-9ac0d403ba8b','題秦君亭  其一','吳栻','宋','宋诗','song-poetry','','[]','芸閣讎書謝建封，生涯瀟灑一枝筇。',64,'全唐诗/poet.song.54000.json','["芸閣讎書謝建封，生涯瀟灑一枝筇。", "曾爲剡隠雲橫水，更作閩遊月滿峰。", "子美藩籬清可造，長卿城郭巧能攻。", "拂琴無復塵埃想，落落霜風一晉松。"]'),
('0eca95fe-f9e0-4745-afb6-734411831e6d','題秦君亭  其二','吳栻','宋','宋诗','song-poetry','','[]','秋日春風麗句亭，先生天上少微星。',64,'全唐诗/poet.song.54000.json','["秋日春風麗句亭，先生天上少微星。", "滿爐松影隨香碧，一硯苔痕带雨青。", "姜相笑中應斗酒，等公談外祇函經。", "何人爲我携氈蠟，來洗蒼碑墨數廳。"]'),
('39e6cb55-ba85-424e-aa73-7e5ba97345bb','題清洋院','吳栻','宋','宋诗','song-poetry','','[]','瀟灑堂中披晚襟，紅蕉花裏葉成陰。',64,'全唐诗/poet.song.54000.json','["瀟灑堂中披晚襟，紅蕉花裏葉成陰。", "飄來無雨水長急，飛去有雲山更深。", "苔蘚細痕緣巨石，藤蘿密影挂疏林。", "上人莫作人間想，此地人間不可尋。"]'),
('9277c9a4-b132-4092-ac3b-27ce6b2bdac5','題報劬院','吳栻','宋','宋诗','song-poetry','','[]','山列三峰來不斷，水交雙港送無窮。',32,'全唐诗/poet.song.54000.json','["山列三峰來不斷，水交雙港送無窮。", "帆邊洲渚瀟瀟雨，牆外園林淅淅風。"]'),
('ad8959bf-a13e-4d8d-a508-4bb5e89f3030','靈巖  其一','吳栻','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','三齊何處古叢林，石作門闌岱嶽陰。',64,'全唐诗/poet.song.54000.json','["三齊何處古叢林，石作門闌岱嶽陰。", "雲暗鷄鳴川谷淺，月明龜吐水泉深。", "未須讚歎袈裟鐵，且可歸依世界金。", "彈指上方還一夢，夢中聊續去年吟。"]'),
('00af6b36-4ba0-4bf5-8c0c-756bfca086af','靈巖  其二','吳栻','宋','宋诗','song-poetry','','[]','濟南驚蟄隠新雷，底事陽關疊疊催。',64,'全唐诗/poet.song.54000.json','["濟南驚蟄隠新雷，底事陽關疊疊催。", "不稱濼源湧觱沸，只堪崧阜上崔巍。", "他年髮已千莖雪，今日心仍一寸灰。", "文雅臺邊蝸有舍，甕頭歸去潑春醅。"]'),
('eaf91a01-0366-4a56-abc4-cf99dc1aeaa7','靈巖  其三','吳栻','宋','宋诗','song-poetry','','[]','飛錫道人知幾年，青蛇白兔亦茫然。',64,'全唐诗/poet.song.54000.json','["飛錫道人知幾年，青蛇白兔亦茫然。", "焚香且上五花殿，煮茗更臨雙鶴泉。", "今日別栽庭下柏，當時曾種社中蓮。", "證明佛事真何事，聊策藤枝結勝緣。"]'),
('3d5d3987-882c-45de-bcc5-f222cbb20f3e','句','吳栻','宋','宋诗','song-poetry','','[]','晴開千障霧，翠落萬家樓。',12,'全唐诗/poet.song.54000.json','["晴開千障霧，翠落萬家樓。"]'),
('0454921c-95d2-4417-b18d-f9be1ee06c22','桃花巖','李通儒','宋','宋诗','song-poetry','','[]','地勢下臨鄖子國，山光遙射楚王城。',32,'全唐诗/poet.song.54000.json','["地勢下臨鄖子國，山光遙射楚王城。", "惟有桃花巖上月，曾聞李白醉吟聲。"]'),
('40b9d02f-a051-423c-be03-f56a87363ab7','送程給事知越州','范鏜','宋','宋诗','song-poetry','','[]','青門聊起濯纓歌，晝繡經從鬢已皤。',64,'全唐诗/poet.song.54000.json','["青門聊起濯纓歌，晝繡經從鬢已皤。", "越俗易諳緣地近，吳人奚獨羨金多。", "要知新集餘民事，亦有東來使者過。", "今日輕帆到江滸，藩宣宜得似西河。"]'),
('08497e09-4796-4339-b53e-1b0f901029a9','游湞陽峽','范鏜','宋','宋诗','song-poetry','','[]','峽流觸石石欲裂，峽舟泝水心寸拆。',64,'全唐诗/poet.song.54000.json','["峽流觸石石欲裂，峽舟泝水心寸拆。", "繫纜心頭夜向闌，驚浪沄沄寫寒月。", "風餐水宿知幾年，餘生可復瘴江邊。", "愁絕不眠起披戶，顧視海宇天茫然。"]'),
('b7c68aa0-c227-4811-bbf0-49fe64da6805','書碧落洞','范鏜','宋','宋诗','song-poetry','','[]','君不見英江碧落之洞之奇異，覽遍堪輿無一二。',293,'全唐诗/poet.song.54000.json','["君不見英江碧落之洞之奇異，覽遍堪輿無一二。", "亂石叢中孕粹精，萬里荒崖啟靈秘。", "飛來峰喜石玲瓏，後人雕琢徂真風。", "通天巖穴亦幽敞，有山無水非吾從。", "錦石半空杳元逕，泉石猶憐未相應。", "星巖山澤本自佳，却被漁人苦深病。", "何如此洞妙神工，架空絕壑如長虹。", "一水中流抱青碧，羣峰掩映迷僊迹。", "巨靈擘開神禹鑿，怪石崆峒翳寥廓。", "雲華縹緲聞簫笙，寶室光騰下鸞鶴。", "初疑河漢通天閽，欲泛星槎一問津。", "又如悞入桃源滸，□□恐有先秦民。", "我生僻性耽奇特，每遇勝遊興增逸。", "□來得此慰初心，積慮沈痾恍如失。", "吳羅二子亦豪英，溪頭飲我雙玉瓶。", "醉來晞髮雲霜外，一笑林壑生秋聲。", "洞天福地遍天下，蓬島三山終幻化。", "會當八極恣神游，小作行窩駐吾駕。"]'),
('64c51e77-1e61-424a-a194-4d45bb267bdc','碧落洞','范鏜','宋','宋诗','song-poetry','','[]','玉削蒼巒千碧虛，洞中杳杳真人居。',64,'全唐诗/poet.song.54000.json','["玉削蒼巒千碧虛，洞中杳杳真人居。", "綽約冰采顔如珠，一念不起終無如。", "我緣樸陋厭紛挐，心與幽致煩簪裾。", "九陽丹就括靈樞，飄然再訪聊踟躕。"]'),
('217cca95-fe8d-4544-9a3b-34af9ab6030c','游惠山  其一','蔣之美','宋','宋诗','song-poetry','','[]','絕頂疑天設，重門一徑深。',48,'全唐诗/poet.song.54000.json','["絕頂疑天設，重門一徑深。", "泉清千古意，松老百年心。", "高閣窺平陸，危亭倚翠岑。", "勝遊方自適，猶恐日西沈。"]'),
('9581a108-94ef-42f9-a40e-a09e904fe2de','游惠山  其二','蔣之美','宋','宋诗','song-poetry','','[]','九隴分形怪，蒼龍據厚坤。',48,'全唐诗/poet.song.54000.json','["九隴分形怪，蒼龍據厚坤。", "洞寒清水脈，石潤養雲根。", "探遠塵應斷，窮高斗可捫。", "江湖倦行者，對此欲忘言。"]'),
('aeb7a305-f1f5-4b1a-bce9-498c31799ff9','游惠山  其三','蔣之美','宋','宋诗','song-poetry','','[]','維舟上重巘，景物近斜暉。',72,'全唐诗/poet.song.54000.json','["維舟上重巘，景物近斜暉。", "流水連珠落，殘花碎錦飛。", "白雲隨步武，香鳥傍軒扉。", "拂井松傾蓋，緣崖蘚上衣。", "池光清可鑑，竹色翠成圍。", "更接高僧話，林梢带月歸。"]'),
('b06ce55c-7aa0-4f65-9655-89235dad966b','飛來山','葉棣','宋','宋诗','song-poetry','','[]','亂山深處款禪扃，十里松陰步障行。',64,'全唐诗/poet.song.54000.json','["亂山深處款禪扃，十里松陰步障行。", "翠竹黄花幾開發，南星北斗自高明。", "樓臺日轉天邊影，鐘磬風回地底聲。", "爲問閩江船釣客，謝家誰更未知名。"]'),
('54540859-a25b-4340-92ee-3388f173dd1b','句','葉棣','宋','宋诗','song-poetry','','[]','聞說治平元太守，慇懃晚到鳳皇池。',16,'全唐诗/poet.song.54000.json','["聞說治平元太守，慇懃晚到鳳皇池。"]'),
('36a96903-d1dd-40a3-a980-1ecbfe84e04f','當陽寺','林誥','宋','宋诗','song-poetry','','[]','何處遇幽景，當陽絕頂尋。',48,'全唐诗/poet.song.54000.json','["何處遇幽景，當陽絕頂尋。", "雲霞千古態，松竹四時陰。", "岫列天邊嶂，泉鳴澗底琴。", "高人不遊此，應負愛山心。"]'),
('05454169-2f6a-48fa-b3ee-818ffb438470','句  其一','林安道','宋','宋诗','song-poetry','','[]','古甃千齡在，寒泉味最醇。',12,'全唐诗/poet.song.54000.json','["古甃千齡在，寒泉味最醇。"]'),
('ad031f5b-4609-4d36-b98f-14a267dbe8ac','句  其二','林安道','宋','宋诗','song-poetry','','[]','海外蟠桃同永久，月中丹桂共參差。',16,'全唐诗/poet.song.54000.json','["海外蟠桃同永久，月中丹桂共參差。"]'),
('8ca80c56-5158-4e5b-a0e4-97f7b3cdc713','老人巖','林嗣宗','宋','宋诗','song-poetry','','[]','九月黄花次第開，带星約客上崔嵬。',64,'全唐诗/poet.song.54000.json','["九月黄花次第開，带星約客上崔嵬。", "擬從老子巖前去，却入真仙洞裏來。", "幸勉西風吹落帽，且陪東道引深杯。", "箇中便見蓬萊境，何必龍山戲馬臺。"]'),
('1e0f4e54-6a24-44d2-9c62-57788eb5b9f4','句','柳庭俊','宋','宋诗','song-poetry','','[]','滁陽山水佳，幽谷尤勝絕。',12,'全唐诗/poet.song.54000.json','["滁陽山水佳，幽谷尤勝絕。"]'),
('2093ecfb-443d-4842-a6cd-0e20f4042dcf','吳江太湖笠澤虹橋','梅灝','宋','宋诗','song-poetry','','["\u592a\u6e56"]','水無濁浪地無塵，渺渺江湖天與鄰。',64,'全唐诗/poet.song.54000.json','["水無濁浪地無塵，渺渺江湖天與鄰。", "占得滄波輸釣叟，吟窮清景屬詩人。", "陰晴隠見山千疊，上下澄明月一輪。", "欲畫爲圖隨處看，風光變態狀難真。"]'),
('951da294-e8b1-4416-8e04-27b67fec2493','題梅壇','呂防','宋','宋诗','song-poetry','','[]','封事悠悠即掛冠，蒼烟古木鎖空壇。',32,'全唐诗/poet.song.54000.json','["封事悠悠即掛冠，蒼烟古木鎖空壇。", "當時不識蓬萊客，祇作南昌一尉看。"]'),
('7750b5d5-a28b-4601-9f80-4ac006fba9c4','題梅仙觀','呂防','宋','宋诗','song-poetry','','[]','嘗讀子真傳，掩卷屢長嘆。',216,'全唐诗/poet.song.54000.json','["嘗讀子真傳，掩卷屢長嘆。", "如何忠正資，適在元成間。", "危言論時政，條暢窮根源。", "直節破姦膽，憤氣衝儒冠。", "上書輒報罷，九九慚齊桓。", "是時公卿輩，曾不爲厚顔。", "雄文燦方冊，至今日星攢。", "深機識禍福，拂衣九江干。", "一朝棄妻子，變姓抱吳關。", "位卑而言高，自古爲尤難。", "斯人能保身，出處何其艱。", "繄子偶得邑，駕言謁仙壇。", "壇側千丈松，凜凜清風還。", "壽春下新詔，高蹈翠琰刊。", "壁間羅隠記，中理極可觀。", "當年康樂公，遊覽遍名山。", "云何此佳蹟，未被金石言。", "真人久悵望，佇看西飛鸞。"]'),
('a2332828-c54f-4fa2-b6a3-c24b0d6846d6','瀫波亭','呂防','宋','宋诗','song-poetry','','[]','王孫餘巧力，銀漢亦經營。',24,'全唐诗/poet.song.54000.json','["王孫餘巧力，銀漢亦經營。", "地軸卷不盡，風梭織又成。"]'),
('af116821-af70-43ad-8bd5-4ceafaad06bf','元章好古過人書畫驚世起余作歌','劉涇','宋','宋诗','song-poetry','','[]','天下愛奇人沒量，奇不諛人奇解相。',336,'全唐诗/poet.song.54000.json','["天下愛奇人沒量，奇不諛人奇解相。", "奇人奇物方合璧，乞與世間人物樣。", "六朝唐盛始兼得，訪古知名已蕭爽。", "人亡物喪付衰夢，注想後來逢好尚。", "元章心自鑒秋月，一路仍行九霄上。", "家時菜色無斗粟，書畫奇奇世人望。", "譬如大海沈百寶，爾輩乘風得之浪。", "二王褚陸已天作，老顧如來更天匠。", "其餘緹襲凡幾重，但見光明爛垂象。", "珍犀瑞錦扶蘭茝，龍躍鸞驚訶魍魎。", "金仙詎敢觸以手，雪子玉人聊置掌。", "余家僻素最沈著，退舍還師覺難傍。", "世人往往力能幹，未免目蝦終惚恍。", "緘機僞謬各臣妾，未睹堂堂筆中王。", "袖間澀縮氣如線，浄几明窗謾瞻仰。", "從來所有萬錢價，不即臭帤當火葬。", "傾心妙絕豈求勝，妄意臨摹須殺謗。", "端居自號書一品，好事如封繪三藏。", "諸郎青出即護持，未肯充饑謬爲駔。", "余衰二物擬高閣，子可專之世無兩。", "書來詩往但悠悠，塵土欺人正惆悵。"]'),
('7152252f-0fb4-4105-b6be-71bb6d989fa8','題韓溪','劉涇','宋','宋诗','song-poetry','','[]','豪傑相從意氣中，憐才傾倒獨蕭公。',32,'全唐诗/poet.song.54000.json','["豪傑相從意氣中，憐才傾倒獨蕭公。", "後來可是無奇客，東閣投名尚不通。"]'),
('8eacfd72-b88c-41a9-8281-0ffe23330bb6','留題釣臺','劉涇','宋','宋诗','song-poetry','','[]','水綠山青人可知，不知生氣得之誰。',32,'全唐诗/poet.song.54000.json','["水綠山青人可知，不知生氣得之誰。", "釣竿已屬嚴公手，直到元英解道詩。"]'),
('127a7eed-1828-4cd9-b3cf-281a532b708c','青城山','劉涇','宋','宋诗','song-poetry','','[]','拔地山爭秀，藏天谷受虛。',24,'全唐诗/poet.song.54000.json','["拔地山爭秀，藏天谷受虛。", "雲開西蜀後，木老避秦初。"]'),
('f1f6ce93-6b35-4ec1-8d2d-de996bdb27e6','仙都山','劉涇','宋','宋诗','song-poetry','','[]','石城雲屋抱浮丘，正是真人舊括州。',32,'全唐诗/poet.song.54000.json','["石城雲屋抱浮丘，正是真人舊括州。", "會擲仙圖爭少勝，不知身到洞天遊。"]'),
('6f0fa809-f162-42fd-81fc-9b6464d440df','石洞門  其一','劉涇','宋','宋诗','song-poetry','','[]','密竹流泉不居熱，洞門深沉風雨歇。',32,'全唐诗/poet.song.54000.json','["密竹流泉不居熱，洞門深沉風雨歇。", "洗出清明快活天，醉弄江南謝家月。"]'),
('baa7a1f5-2e37-407b-9ca6-f5a476e1bbda','石洞門  其二','劉涇','宋','宋诗','song-poetry','','[]','未逢仙手破天荒，我得披雲第一章。',32,'全唐诗/poet.song.54000.json','["未逢仙手破天荒，我得披雲第一章。", "它日愛奇思謝客，却須因事憶劉郎。"]'),
('f77a9cb8-e5da-472a-8463-d1058fe3f12d','和米元章龍真行','劉涇','宋','宋诗','song-poetry','','[]','秦火蕩焚天地赤，孔堂壞後無餘壁。',160,'全唐诗/poet.song.54000.json','["秦火蕩焚天地赤，孔堂壞後無餘壁。", "不知科斗六書文，化作龍蛇二王跡。", "集賢他日作仙久，官姓篆章存歷歷。", "自憐黄眼未親逢，一段因依徒奪魄。", "元章揮灑早驚動，祕篋墨皇曾敬識。", "孤標未要後生知，劣許下官論莫逆。", "好奇舉世不多得，神物尤來終變易。", "神鋒雙合會有時，真璽一飛無處覓。", "頗聞祕篋作訛語，別有擾龍招異客。", "不如乾沒歸去來，勝在箇家遭水厄。"]'),
('602bd98f-589f-4058-96e1-90d6002f8393','天王寺','劉涇','宋','宋诗','song-poetry','','[]','金碧爲家定化城，書床南偃略相迎。',64,'全唐诗/poet.song.54000.json','["金碧爲家定化城，書床南偃略相迎。", "人間蝶夢正深黑，天上木魚初發明。", "半里好風招隠士，一枝枯竹助閑行。", "已慚懷紱無高致，可更標門著姓名。"]'),
('55cc59ee-11bb-4d40-a8af-1ae5f8d68aee','登麻姑山  其一','劉涇','宋','宋诗','song-poetry','','[]','溪行愛宛轉，石坐憐皴蒼。',48,'全唐诗/poet.song.54000.json','["溪行愛宛轉，石坐憐皴蒼。", "白雲起目前，如鶴兩翼張。", "蛻我衣上塵，駕之以翱翔。", "欲攬恍不接，身在意飄揚。"]'),
('bf417b35-fdc0-4393-acb9-4e37f3397550','登麻姑山  其二','劉涇','宋','宋诗','song-poetry','','[]','石鼓埋入地，荆璧飛上天。',48,'全唐诗/poet.song.54000.json','["石鼓埋入地，荆璧飛上天。", "嗚呼魯公碑，風雨三百年。", "愛字不愛石，磨滅安得傳。", "不敢手觸之，謂是甘棠篇。"]'),
('1ffe93de-b16a-4839-92e2-bc215d15cd10','葛仙壇  其一','劉涇','宋','宋诗','song-poetry','','[]','天風吹餘晦，萬木晴扶疏。',48,'全唐诗/poet.song.54000.json','["天風吹餘晦，萬木晴扶疏。", "寒雲淡山色，水墨漲秋圖。", "駕言寥廓中，一徑渺盤紆。", "却首謝塵世，培塿而潢汙。"]'),
('431c5ad9-8de0-43ec-81d6-c6ee878b397b','葛仙壇  其二','劉涇','宋','宋诗','song-poetry','','[]','謝公好登山，折屐第三谷。',48,'全唐诗/poet.song.54000.json','["謝公好登山，折屐第三谷。", "麻姑乃不到，頗負登山足。", "寒杉鳴古璫，澗道瀉淙玉。", "筇竹白接䍦，吾將追往躅。"]'),
('4e4f8615-9c96-494b-a166-456236ed2f71','葛仙壇  其三','劉涇','宋','宋诗','song-poetry','','[]','空山萬幽木，彈以終日風。',48,'全唐诗/poet.song.54000.json','["空山萬幽木，彈以終日風。", "無弦自秋曲，奏滿天地中。", "愛之以心靈，聽之以耳聰。", "道人抱琴來，此意不可通。"]'),
('7a13cd62-fc1b-433e-a793-686d06a2165c','瀑布泉','劉涇','宋','宋诗','song-poetry','','[]','瀑布宜終宵，幽鳥時一吟。',48,'全唐诗/poet.song.54000.json','["瀑布宜終宵，幽鳥時一吟。", "浩然太虛際，始識本來心。", "情閑日自長，步遠意亦深。", "更携九節杖，插遍蕭蕭林。"]'),
('c3eb0ccc-f0a7-4876-9b6c-8a145c6d0673','三巖遊','劉涇','宋','宋诗','song-poetry','','[]','混成初造物，幽絕故離群。',48,'全唐诗/poet.song.54000.json','["混成初造物，幽絕故離群。", "入戶清容月，分棲淡借雲。", "木陰闌暑氣，泉滴厭秋聞。", "欲索秦人記，消磨篆不文。"]'),
('e37eb21e-1dc2-4f15-8b98-52650aafae38','混元峰','劉涇','宋','宋诗','song-poetry','','[]','青泥切石劍無迹，丹水含英鼎飛出。',32,'全唐诗/poet.song.54000.json','["青泥切石劍無迹，丹水含英鼎飛出。", "仙風絕塵鷄犬喧，杉松老大如人立。"]'),
('d560769e-d3ee-4be5-97f9-739f560ad2cd','題籠空巖','劉涇','宋','宋诗','song-poetry','','[]','蒼崖如堂水如布，橋危如繩石如鋸。',32,'全唐诗/poet.song.54000.json','["蒼崖如堂水如布，橋危如繩石如鋸。", "不有樵夫踏破雲，世間可復知深處。"]'),
('f1df4501-da8c-45cc-9eca-1ab268d0ddc9','溪雨亭','劉涇','宋','宋诗','song-poetry','','[]','塵土孤城空自忙，不知精舍早秋凉。',64,'全唐诗/poet.song.54000.json','["塵土孤城空自忙，不知精舍早秋凉。", "林間曲折磬三里，天上金光月滿堂。", "浄飯打魚刳老木，寒灰添火爇明香。", "鵓鳩山脚溪聲好，流入人間雨意長。"]'),
('af50b135-2eb1-4ab1-88ff-ffed09130772','句  其一','劉涇','宋','宋诗','song-poetry','','[]','初起褪紅唇啟絳，半沾斜綠眼橫波。',16,'全唐诗/poet.song.54000.json','["初起褪紅唇啟絳，半沾斜綠眼橫波。"]'),
('fb69c9fd-edfc-49a7-a257-ffe587478d96','句  其二','劉涇','宋','宋诗','song-poetry','','[]','曉來風入萬花動，零落滿頭飛下時。',16,'全唐诗/poet.song.54000.json','["曉來風入萬花動，零落滿頭飛下時。"]'),
('7da55e7b-0886-48b6-a340-df2f99744ed0','詩一首','俞括','宋','宋诗','song-poetry','','[]','二十四峰尖，參差列郡南。',24,'全唐诗/poet.song.54000.json','["二十四峰尖，參差列郡南。", "半空擎梵宇，絕頂寄僧龕。"]'),
('63fc59b9-0dda-4eb5-b353-55feb71483cf','句','俞括','宋','宋诗','song-poetry','','[]','巖排星斗七，石湧佛身三。',12,'全唐诗/poet.song.54000.json','["巖排星斗七，石湧佛身三。"]'),
('c22c6f06-9105-410a-8416-ed8acee3a711','贈王介甫','段縫','宋','宋诗','song-poetry','','[]','溪橋久廢湮，竹樹半欹側。',288,'全唐诗/poet.song.54000.json','["溪橋久廢湮，竹樹半欹側。", "夢尋六代塵，老構一椽宅。", "誰知江令門，猶倒山公舄。", "霸氣消舊朝，歌聲慨陳迹。", "鼎族昔繁華，荒徑今岑寂。", "願言闢榛蕪，重與開景色。", "石疊雲自生，渠鑿流不息。", "我幸卜公鄰，望衡步咫尺。", "晨夕愜素心，把臂共悅懌。", "西崦带烟樵，南埭釣水食。", "底事憂怦怦，相將愛惕惕。", "或築吟詩壇，或設談經席。", "焉知才不才，聊各適其適。", "岸幘豁眼界，揮麈吐胸臆。", "隴晴許扶鳩，水漲可𣏾鷁。", "嗒然得喪忘，往事莫凄惻。", "佳會不可常，歲月豈拋擲。", "蒙莊頼妻賢，淵明空子責。", "弱木手自栽，勿徒嗟立壁。", "滋培待其成，斧削工師職。", "更爲廣軒亭，左右支圖籍。", "鍾山挹爽來，烟鳥紛若織。", "綠菘籬下采，金尊池上滌。", "此盟更歲寒，一笑星髮白。"]'),
('081e35bf-9a0f-4037-9e1d-e7fa662894e7','過惠山皞老試茶二首  其一','孫迪','宋','宋诗','song-poetry','','[]','蕭蕭阿蘭若，桑苧有故家。',96,'全唐诗/poet.song.54000.json','["蕭蕭阿蘭若，桑苧有故家。", "佛屋倚高寒，僧蹊抱欹斜。", "殷勤泉下客，流落瘴海涯。", "蜑酒壓梨楂，蠻烹啗蠅蛇。", "光潔鏡一奩，影照空自嗟。", "老僧薦茗粥，芳鮮凝露華。", "驅除鼻中雷，掃盡眼界花。", "飄飄思凌雲，攝身上蒼霞。"]'),
('55f96679-c2c9-4a7e-a927-06b14df52064','過惠山皞老試茶二首  其二','孫迪','宋','宋诗','song-poetry','','[]','戰塵霾漢天，獵火焮塵地。',96,'全唐诗/poet.song.54000.json','["戰塵霾漢天，獵火焮塵地。", "一筇遺垢氛，步入青蓮寺。", "耽耽九龍盤，一壑埋老翠。", "倚天松骨大，粘碧苔𩬊細。", "道人本臞儒，得法妙出世。", "胸中萬斛泉，洗盡蔬笋氣。", "天風吹泠泠，助我鳴鼓吹。", "名爲不二門，聲音作佛事。"]'),
('558acaf5-0ba7-4957-ba3c-c60e93950146','見舊題  其一','孫迪','宋','宋诗','song-poetry','','[]','一別名山十五年，宦情羈思兩茫然。',32,'全唐诗/poet.song.54000.json','["一別名山十五年，宦情羈思兩茫然。", "故人半作纍纍塚，只有蒼官立道邊。"]'),
('397cc6d1-b5fd-445f-82f4-30d0467036b1','見舊題  其二','孫迪','宋','宋诗','song-poetry','','[]','髀肉消磨馬上鞍，塵砂滿眼路漫漫。',32,'全唐诗/poet.song.54000.json','["髀肉消磨馬上鞍，塵砂滿眼路漫漫。", "不須更障西風扇，爲酌崖泉一洗看。"]'),
('28ce8271-759b-464d-9a93-ead54ff22950','謁李太白祠','李之儀','宋','宋诗','song-poetry','','[]','愛君獨酌板橋句，想君不向稽山時。',150,'全唐诗/poet.song.54000.json','["愛君獨酌板橋句，想君不向稽山時。", "千載風流同一轍，孤墳數尺埋蒿藜。", "文章誤人豈當日，聲名雖好終何爲。", "譬之花卉自開落，又如時鳥啼高低。", "行吟漫葬江魚腹，鵩來空賦予何之。", "君不見吾腰恥爲小兒折，或車或棹聊爲期。", "又不見嬴顛劉蹶不到耳，採花摘實相維持。", "春寒漠漠青山路，厚顔已覺歸來遲。", "一廛尚冀容此老，與君朽骨分東西。"]'),
('c2a017cf-b6f3-4f58-ab3f-be83ac634c8d','累日氣候差暖梅花輒已弄色聊課童僕芟削培灌以助其發戲成小詩三首  其一','李之儀','宋','宋诗','song-poetry','','[]','京洛三十年作客，每見梅花欲忘食。',144,'全唐诗/poet.song.54000.json','["京洛三十年作客，每見梅花欲忘食。", "時時魂夢到江南，足跡塵埃來不得。", "嗅香嚼蘂不忍捨，爲憐絕韵真顔色。", "誰知晚得江南身，特此一株當舍北。", "寒根老枿初不辨，幾與桑榆同棄擲。", "慇懃地主故指示，頓覺翛然超眼域。", "幾山氣候也深春，戢戢枝頭危欲坼。", "呼奴鄰家借刀斧，穿斷因之聊拂拭。", "便宜邀月作嘉賓，不惜淋漓慰疇昔。"]'),
('0c260125-8f86-4743-b56c-e2346d1dd2f7','累日氣候差暖梅花輒已弄色聊課童僕芟削培灌以助其發戲成小詩三首  其二','李之儀','宋','宋诗','song-poetry','','[]','邂逅梅花同作客，此理雖龜亦難食。',144,'全唐诗/poet.song.54000.json','["邂逅梅花同作客，此理雖龜亦難食。", "道人無眼自超羣，定裏觀之想應得。", "爲惜花開將及時，枕上朝朝問天色。", "自是春工力尚堅，一向風頭來自北。", "昨夜雪深幾一尺，不覺起來欲跳躑。", "雪過春回固可期，聊與此花爲畛域。", "今朝舉頭消息別，物理人情原未坼。", "綠萼柔條宛相契，正色真香浄如拭。", "更煩妙語爲詮評，莫遣塵根迷夙昔。"]'),
('4830be5c-f5b6-4980-8402-e50ca8b2142d','累日氣候差暖梅花輒已弄色聊課童僕芟削培灌以助其發戲成小詩三首  其三','李之儀','宋','宋诗','song-poetry','','[]','花是主人身是客，更欲花前羅酒食。',144,'全唐诗/poet.song.54000.json','["花是主人身是客，更欲花前羅酒食。", "花應笑我强相親，畢竟人花誰是得。", "金樽到手我自醉，道人何妨且觀色。", "三界觀來即是空，醉裏寧知漸遊北。", "等爲圓鏡隨身現，認着分明却虛擲。", "持此問花花不答，嗟我與君徒入域。", "不如收却閒眼坐，萬境紛紛在披坼。", "一番風雨便紛飛，念垢情塵漫磨拭。", "今年春盡有明年，花落花開幾今昔。"]'),
('32db2430-123f-4be8-8f1c-779c8386642d','彥行和梅詩甚工輒次元韵','李之儀','宋','宋诗','song-poetry','','[]','春風不揀尊前客，未必藜羹輸肉食。',144,'全唐诗/poet.song.54000.json','["春風不揀尊前客，未必藜羹輸肉食。", "玲瓏點綴移月窟，誰謂吾家最先得。", "直從去臘約爲伴，旦旦相看無倦色。", "朝披日彩爛迎東，夜插斗杓寒挂北。", "擬將西子作孤注，對與春工分一擲。", "又疑妖冶凟清真，子細籌量信難域。", "發狂不意落紙上，勝句爭來共推坼。", "諸郎獨殿語尤老，似欲塵埃劇湔拭。", "不惟詩社頓光輝，枝上分明過於昔。"]'),
('b7b8b326-3a15-4cfd-8ead-c6108fedb84a','次韵君俞病中見寄','李之儀','宋','宋诗','song-poetry','','[]','老眼逢春如有隔，不覺花前手頻拭。',195,'全唐诗/poet.song.54000.json','["老眼逢春如有隔，不覺花前手頻拭。", "昔陪韋杜尺五天，此地去天今幾尺。", "東家有客貪春甚，酒作衾裯花作枕。", "瘦逼休文臂漸消，渴近相如尤殢飲。", "賞心直以花爲命，醉頭只恐扶難正。", "春歸每恨太忙生，不惜一春常似病。", "我老無用終安之，屢欲從君獨較遲。", "方將結束窮勝致，投懽祗許春相知。", "詩來苦訴不自樂，春固惱人多索寞。", "何妨强襲起應劉，間促扁舟尋李郭。", "君不見樂羊功名方煜煜，歸來謗書已盈篋。", "爭如隨地任低昂，漫浪猗玕盡元結。"]'),
('25e522b4-6bba-4ecc-9726-a0c696ef4a6f','題步雲亭','李之儀','宋','宋诗','song-poetry','','[]','昨夜風高蟬半咽，起來知是白露節。',195,'全唐诗/poet.song.54000.json','["昨夜風高蟬半咽，起來知是白露節。", "玉面少年窄袖衫，袖裏新詩似冰雪。", "幾日炎炎如甑中，今朝忽覺超樊籠。", "不惟氣候已八月，更得冰雪開心胸。", "謝公山人詩筆奇，問君何緣得此詩。", "報我我欲步雲去，山人許我因留題。", "君作斯亭幾許高，擬推皓魄翻銀濤。", "誰謂姮娥落君手，坐遣山人詩思勞。", "君不見梅老句出天地窄，曾謂山人真太白。", "采石月下憶相逢，笑披錦袍弄明月。", "十年明月歸謫仙，姮娥豈得在君邊。", "何妨邀取山人去，卒歲扶携醉笑間。"]'),
('e8f70d34-97aa-4c13-b681-810e497cb034','題渭濱亭','李之儀','宋','宋诗','song-poetry','','[]','廣張三千六百釣，太公欲與文王親。',96,'全唐诗/poet.song.54000.json','["廣張三千六百釣，太公欲與文王親。", "文王不爲熊羆獵，卜年七百終何人。", "開元天子降步輦，當日何如渭濱見。", "是同是異不可詰，一等風雲符虎變。", "吾君好賢軼前古，處處鵷鸞刷修羽。", "觀君命意非苟然，他日風流須再睹。"]'),
('3828710b-6756-4e3a-8be0-34e9355477ca','題山堂','李之儀','宋','宋诗','song-poetry','','[]','二年江南客，對面不見山。',120,'全唐诗/poet.song.54000.json','["二年江南客，對面不見山。", "負我愛山心，兀兀塵埃間。", "一聞說山心便喜，欲插修翰遽飛起。", "君家乃是山中居，永日青山同徙倚。", "流泉涓涓薜蘿暗，明月時時窺枕簟。", "三伏清霜带雪來，不斷烟雲擁欄檻。", "只恐居山興易闌，萬壑波濤翻等閒。", "知有心期難得否，憑君借與畫圖看。"]'),
('b5e2ec6c-52f4-45d0-8f82-7c589d36d8d7','送儲子椿參假太學時泊舟金陵風亭','李之儀','宋','宋诗','song-poetry','','[]','金陵二月春，江上連日雨。',124,'全唐诗/poet.song.54000.json','["金陵二月春，江上連日雨。", "暖風初報一番晴，綠淺紅深紛無數。", "與君已是隔年別，相逢又作臨分語。", "感君情重故可歌，送君心折不成舞。", "五年相從如一日，物物講評窮髮縷。", "愛君正如韝上鷹，畏君何翅文中虎。", "未飯已知必下趙，憑軾會觀終報楚。", "逡巡照眼綠袍新，更約十分同一舉。"]'),
('cb494d1c-b2de-4b0f-973b-b69e16950dac','走筆贈報寧老','李之儀','宋','宋诗','song-poetry','','[]','半山老人筆如椽，落筆直欲拏雲烟。',64,'全唐诗/poet.song.54000.json','["半山老人筆如椽，落筆直欲拏雲烟。", "東亭右軍不復見，龍跳虎卧誰爭先。", "姑溪六月汗流水，邂逅清風頓如洗。", "他時問法到山前，應許神光得吾髓。"]'),
('1aeabdc7-81e7-4215-a9f0-882063d2c580','和郭功甫遊采石','李之儀','宋','宋诗','song-poetry','','[]','卒歲愔愔無地雪，三首新詩報明發。',224,'全唐诗/poet.song.54000.json','["卒歲愔愔無地雪，三首新詩報明發。", "使君近作采石遊，勝踐傳聞驚久缺。", "亢陽便有欲雪意，和氣先期振巖穴。", "想見旌旗錦繡張，如從元君朝北闕。", "後携一老何奇哉，朱顔鶴髮超塵埃。", "噭呼江上來席上，迤邐萬古隨雲開。", "騎鯨仙人不敢避，玉鏡臺郎俄復迴。", "分明月下遇賞歎，將軍新自天邊來。", "逡巡落筆轟春雷，落花亂點荒池臺。", "沈埋蓁莽見一旦，名高此地真當才。", "從來不許說前輩，寄聲魚鳥休驚猜。", "直疑乘槎叩月窟，又若登臨望天台。", "酒行已徹更須酌，醉倒寧辭無算杯。", "卓然一段極則事，遣我擊節因誰催。"]'),
('bc1f9bd5-f640-4405-8c23-f06b879ca588','采石三題 捉月亭','李之儀','宋','宋诗','song-poetry','','[]','我昔揚帆下廬阜，落帆采石春欲暮。',192,'全唐诗/poet.song.54000.json','["我昔揚帆下廬阜，落帆采石春欲暮。", "江南江北只見山，欲識錦袍無問處。", "夜深明月來青天，天水茫茫月連霧。", "想見扁舟捉月時，江心見月如相遇。", "醉魂不制月可捉，捉得便將天外去。", "月在人亡天莫詰，彷彿風流誰與晤。", "邇來水落洲渚出，隔岸潮迴疑可步。", "聒耳啁啾不得聞，對案腥臊難下筯。", "多情禪客饒佳趣，粉飾餘光扶墜緒。", "欲回古月換今人，到此翛然忘世慮。", "從來喜誦騎鯨句，亦復買田相近住。", "會當載酒十分圓，同指虛無問征路。"]'),
('d920421c-553b-459a-a0ee-6e15e875d463','采石三題 賞詠亭','李之儀','宋','宋诗','song-poetry','','[]','爨下得餘薪，便可歌南風。',96,'全唐诗/poet.song.54000.json','["爨下得餘薪，便可歌南風。", "參差長路鐸，鼓樂俄相同。", "一棄一流落，悠然會天工。", "始知盛衰際，遇與不遇中。", "風清月正好，爽晤聊從容。", "豈意接心期，賞歎如雲龍。", "千載瞬息爾，轉盼歸虛空。", "何適非適然，神交付冥鴻。"]'),
('48cabce5-449d-41b3-a327-dc802901cf71','采石三題 鑑然亭','李之儀','宋','宋诗','song-poetry','','[]','溫公天下士，百計興艱危。',120,'全唐诗/poet.song.54000.json','["溫公天下士，百計興艱危。", "大厦勢已傾，意欲一木支。", "功名等山岳，德澤均雨露。", "奈何談笑間，而取鬼神怒。", "鬼神豈不鑒，忠義當扶持。", "一見亦何傷，冥路俄與期。", "似非理所安，端恐數應盡。", "邂逅不可逃，紛紛遂爲信。", "孔子昔有言，既敬亦須遠。", "三復而三思，臨風更三歎。"]'),
('a8c32045-a86d-4508-baf7-2c9cc542d949','七言古風寄題薛公尉氏逍遙閣兼送伯成知縣宣德解印當塗直書民言耳非所謂詩也','李之儀','宋','宋诗','song-poetry','','[]','長身少髯復多骨，憶在兒時獲相識。',384,'全唐诗/poet.song.54000.json','["長身少髯復多骨，憶在兒時獲相識。", "滿朝善類推老成，鄉曲名流誦才德。", "爾來契闊四十年，停鸞峙鵠欣相傳。", "我方却歸不自得，但覺和氣如春天。", "往日朝門炙可熱，今朝吏爨幾無烟。", "追呼輩伍殆千指，一旦束手蠶如眠。", "父老相傳語且泣，岌岌流離遽安集。", "省事以來無此君，豫恐他時莫能及。", "尺紙胡爲來北闕，樂境危城俄見敚。", "覆盆雖光亦蹔爾，所惜時間未能雪。", "稍傳遠近或歎喜，歎者吾民喜者吏。", "吏至酌酒更相賀，畢竟卷舒須在我。", "父老沾襟嗟薄福，此理冥冥定誰坐。", "異時得君逾所聞，杳杳健鶻盤霜旻。", "信矣此地不可久，空使遺愛傳邦人。", "邦人姑止聽我語，逍遙閣去天尺五。", "長身仙翁昔遊戲，日日烟雲泛罇俎。", "仙翁久已朝紫皇，功行不泯鍾諸郎。", "扶疏密蔭被所至，遂令此閣如甘棠。", "我昔西畿數來往，日脚闌干猶可想。", "塵埃滿袂阻登臨，白髮心期負真賞。", "六月炎炎汗如洗，江南雨多拍隄水。", "旗開鼓響船欲發，超然爽意因君起。", "驊騮一跌愈莫止，大鵬會展滄溟翅。"]'),
('769231b6-a819-45d1-a380-4bc0ea1df5b4','送芝老','李之儀','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江頭春色已可掬，風雨惱人常不足。',64,'全唐诗/poet.song.54000.json','["江頭春色已可掬，風雨惱人常不足。", "筆刀俱來紙上春，牆外落紅爭䔩䔩。", "忽然別我下廬山，蓮社風流指顧間。", "爲我寄聲陶五柳，少留佳處共追攀。"]'),
('75b6b518-7495-4060-98d5-af507add6df2','題王德循書院壁','李之儀','宋','宋诗','song-poetry','','[]','熱不就惡木枝，渴不飲盜泉水。',60,'全唐诗/poet.song.54000.json','["熱不就惡木枝，渴不飲盜泉水。", "古人不可期，歲月姑相委。", "不愛爾井泉百尺深，不愛爾庭樹千里陰。", "相看豈持一飯報，長嘯聊爲猛虎吟。"]'),
('0f4bf11e-0cb9-4d3d-a046-80a8f13fa91e','近得石菖蒲胡伯鎮見之謂必以錦石資藉乃可以久遽徹所有爲貺仍枉佳句輒次韵奉謝','李之儀','宋','宋诗','song-poetry','','[]','倒屣得小異，不言四時備。',72,'全唐诗/poet.song.54000.json','["倒屣得小異，不言四時備。", "遺我百明珠，書窗遽增氣。", "石盆叢秀轉光輝，携挈衰慵絕塵世。", "更煩藻思玄維持，紙上盆中盡珍琲。", "他時相對擘麟脯，何必方平爲紹介。"]'),
('06326652-c741-47b1-8c8e-1c15b4faa99d','丁德儒置酒適與陳君俞聯坐聊賦小詩爲君俞謝因以贖先起之罪','李之儀','宋','宋诗','song-poetry','','[]','春風不解事，吼地如雷霆。',132,'全唐诗/poet.song.54000.json','["春風不解事，吼地如雷霆。", "誰知一席間，笑語燈熒熒。", "主人意彌敦，設置不少停。", "而我槁木然，感慨時自驚。", "多情接勝友，孤朗如初星。", "微吟間相警，似欲慰獨醒。", "我老百不堪，已分如漂萍。", "邂逅因事樂，尚或有此形。", "不慚引去先，得意耳暫清。", "展轉尋斷夢，間關媿微生。", "何當萬里浪，相與同滄溟。"]'),
('68e37c4d-3f01-4f2d-82d3-d8f70f5ee44f','贈劉九思山人','李之儀','宋','宋诗','song-poetry','','[]','我行亦偶然，君來定何謂。',168,'全唐诗/poet.song.54000.json','["我行亦偶然，君來定何謂。", "風高浪如山，聞者亦已畏。", "而君從一葉，過我乃特地。", "郵亭六日俱，臨行尤自媿。", "朝出纔辨色，夜歸或霑醉。", "殘燈不見人，待我獨忘睡。", "語款多破顔，情極幾屑涕。", "屈指再相從，便作新井計。", "我擔既弛肩，君駕亦方稅。", "不覺涉四年，俯仰纔一喟。", "每見意每加，終始不少替。", "顧匪求名頑，豈不懷此義。", "凡生等飄蓬，何物非委蛻。", "爲我謝故人，隨方聊自慰。"]'),
('84794893-4e82-45f6-b867-613afa3cd763','題繁川徐氏孝嚴亭','李之儀','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','戀戀欲報恩，歲月猶過隙。',144,'全唐诗/poet.song.54000.json','["戀戀欲報恩，歲月猶過隙。", "常恐寸草暉，終負陽和力。", "萬鍾非所養，所重在以色。", "庶幾參與騫，不獨慕今昔。", "千尋用或短，乃未及咫尺。", "哀哉過隙心，淚盡墳草碧。", "坐見食亦睹，幽明固無隔。", "蒸嘗雖其時，要是未爲得。", "詩書聖人事，力久真自積。", "卷舒豈他人，忠孝均我職。", "尚容表龜趺，過者必此式。", "長江會生塵，德輝何可及。"]'),
('a8d665ca-daae-472c-a667-10f519156950','次韵秦處度同登黄山','李之儀','宋','宋诗','song-poetry','','[]','艱生縲紲餘，特爾脫魑魅。',96,'全唐诗/poet.song.54000.json','["艱生縲紲餘，特爾脫魑魅。", "殊方窟飄蓬，未免遊戲事。", "眼力到毛髮，抉剔盡奇秘。", "邂逅平生歡，笑語當歌吹。", "曲環豈人謀，明滅殆天吏。", "慰我雲烟期，有靦鴻鵠志。", "百年一瞬爾，幸此半日地。", "聊攄廣莫心，無作雍門淚。"]'),
('1172e65e-6cde-4bcc-8783-67fb8c7f9531','處度再和前詩見寄復次韵報之頃有所約今不逮悲愴無已題于褒禪方丈','李之儀','宋','宋诗','song-poetry','','[]','愛山平生心，殆若鬼所魅。',96,'全唐诗/poet.song.54000.json','["愛山平生心，殆若鬼所魅。", "茲遊媿不早，危至失吾事。", "佳辰秋正晴，有物不自秘。", "晶熒麗初陽，浮動薦微吹。", "幅巾方袍接，固可稱傲吏。", "躋攀敢惜力，卜築豈無志。", "稽首定明老，願借一席地。", "何在眼中人，不覺衣上淚。"]'),
('c6599d6f-21ab-4c80-825c-7c2ce09fbbde','次韵陳君俞携酒見過','李之儀','宋','宋诗','song-poetry','','[]','野人欣莫逆，君子戒多上。',144,'全唐诗/poet.song.54000.json','["野人欣莫逆，君子戒多上。", "幸爾違朝市，聊復圖蕙帳。", "薄田幾負郭，山水分背向。", "巾車俯秋成，舒嘯會隨杖。", "吾友真可人，輕舟數相訪。", "投懷失枯槁，達意信摇蕩。", "時哉固難得，觸境沈波浪。", "謂我來歲寒，種種不少創。", "杯盤挽氣類，論辨極戶量。", "敢辭屢舉白，自喜老彌壯。", "回頭易陳迹，傾倒乃惆悵。", "樂事須勉旃，何適非醖釀。"]'),
('a217a73b-9ecd-471e-aa24-4c7cebcb259b','迎暉閣','李之儀','宋','宋诗','song-poetry','','[]','霜風吹我衣，日短歸路長。',120,'全唐诗/poet.song.54000.json','["霜風吹我衣，日短歸路長。", "放懷即可家，何適非吾鄉。", "稍聞東南隅，勝致寓一方。", "超然世外人，雞黍隨低昂。", "簷甍闢無際，戶牖延初光。", "孰云日月久，但知歲時康。", "每逢會心處，萬境不得藏。", "何當駕修輪，飛雲共回翔。", "淋漓非所期，遠目聊徜徉。", "庶幾蟹眼白，打出鵝兒黄。"]'),
('0852ae2a-3b87-44e8-b84b-b9fb52233aa8','和遊一人泉','李之儀','宋','宋诗','song-poetry','','[]','新詩解人頤，秀若披雲鬟。',168,'全唐诗/poet.song.54000.json','["新詩解人頤，秀若披雲鬟。", "突然不可揖，平地翻波瀾。", "褰衣媿招携，每見輒汗顔。", "況茲天際遊，物理知難攀。", "一來金陵居，終歲不得閒。", "勝踐固疇昔，欲往獨見刪。", "命駕等人爾，底事獨我慳。", "豈非勒移靈，不許污名山。", "因詩想其人，愛來直仍彎。", "裂臍那復惜，頓足已滯頑。", "清甘似可飽，忽遽誰其還。", "何當强扶老，寄迹雲霞間。", "要須君意果，莫遣我盟寒。", "曉來雨脚斷，去夢已班班。"]'),
('8f61bc3d-1350-489e-bfb6-ae2f13890edb','秀遠堂次趙德孺韵','李之儀','宋','宋诗','song-poetry','','[]','愛山依山住，如山不少下。',156,'全唐诗/poet.song.54000.json','["愛山依山住，如山不少下。", "山中所有多，惟取不容捨。", "烟雲實交遊，松竹乃保社。", "尚欠目所窮，披翦寧問檟。", "廓然宇宙寬，信矣和無寡。", "隠隠徹四垂，萬象入坯冶。", "初疑彩間錯，又若墨勻洒。", "造化非適然，一一類見假。", "吾友端可人，韵勝不少野。", "更將桃李俱，參差移拱把。", "時哉須自勉，歲月甚奔馬。", "得難未易失，詎有長年者。", "何妨倒載歸，日日無虛斝。"]'),
('3b3ca0fe-050a-452d-bddd-ca005fa640b7','中隠菴次趙德孺韵','李之儀','宋','宋诗','song-poetry','','[]','退之以文鳴，詩友得侯喜。',168,'全唐诗/poet.song.54000.json','["退之以文鳴，詩友得侯喜。", "聲名力與俱，雖尊未勇耳。", "潢池詎青山，孰辨都與鄙。", "菴成誰振之，句出鬧如市。", "千仞寧我高，充實信我美。", "坐令菴內人，前車云可軌。", "禮樂有先後，後進則君子。", "執方而昧圓，俱野那復史。", "伐柯固執柯，疇克求諸邇。", "蒸之既匪薪，采焉又非芑。", "近交韓與侯，步驟亦常恥。", "一醫消息盡，布毛自何起。", "要須六月息，不息不爲已。", "敢問二詩人，如何得意旨。"]'),
('acdc616e-0196-46db-aa33-f1a61e61a10e','莊居值雨偶得十詩示秦處度  其一','李之儀','宋','宋诗','song-poetry','','[]','累日雨不止，風高如作寒。',48,'全唐诗/poet.song.54000.json','["累日雨不止，風高如作寒。", "三分雖過二，忽忽便向闌。", "一身百憂集，況可計先懽。", "不見是無悶，念此聊自寬。"]'),
('556bf24b-c95d-4b45-ad9c-1bcc454104d9','莊居值雨偶得十詩示秦處度  其二','李之儀','宋','宋诗','song-poetry','','[]','滿眼多是水，歲事從可知。',48,'全唐诗/poet.song.54000.json','["滿眼多是水，歲事從可知。", "早時謂有餘，今空未免饑。", "一雨又三日，見者皆攢眉。", "天作人承之，到此終何爲。"]'),
('2efebd33-6b04-4e01-b898-70d07b104922','莊居值雨偶得十詩示秦處度  其三','李之儀','宋','宋诗','song-poetry','','[]','我雖非故侯，通籍三十年。',48,'全唐诗/poet.song.54000.json','["我雖非故侯，通籍三十年。", "孰不夷險半，而我終歲難。", "念非跣弗視，不覺乘波瀾。", "餘生豈所期，我君信如天。"]'),
('0fb3779a-a1be-4bad-a9a2-bd202e467337','莊居值雨偶得十詩示秦處度  其四','李之儀','宋','宋诗','song-poetry','','[]','平生三四友，一一人中英。',48,'全唐诗/poet.song.54000.json','["平生三四友，一一人中英。", "況逢不世主，唾手可太平。", "參差十年間，契闊而死生。", "相見復何語，但有淚如傾。"]'),
('c2ee06b7-a801-4bbb-a446-14e1c0c0b469','莊居值雨偶得十詩示秦處度  其五','李之儀','宋','宋诗','song-poetry','','[]','死生固可嗟，一謫輒不返。',48,'全唐诗/poet.song.54000.json','["死生固可嗟，一謫輒不返。", "君恩非不深，奈爾道路遠。", "反初不忍歌，折臂信能遣。", "已矣何足論，幸子真入眼。"]'),
('6d3a8564-9be1-45ff-9249-21795408aaba','莊居值雨偶得十詩示秦處度  其六','李之儀','宋','宋诗','song-poetry','','[]','念我宜州兄，見時論弟昆。',48,'全唐诗/poet.song.54000.json','["念我宜州兄，見時論弟昆。", "詩書固分路，翰墨俄同門。", "人誰不歸來，獨沾死後恩。", "萬里一銘旌，猶能葬家原。"]'),
('6fd1b27e-7819-4b10-aa49-9857da8c3fc3','莊居值雨偶得十詩示秦處度  其七','李之儀','宋','宋诗','song-poetry','','[]','夕郎天下士，異同親見之。',48,'全唐诗/poet.song.54000.json','["夕郎天下士，異同親見之。", "欲掩不可得，交口終何爲。", "百汰剛愈精，魑魅今尚疑。", "浮雲空去來，皎皎端所期。"]'),
('8654243d-981c-40cf-9b80-bed2727c5715','莊居值雨偶得十詩示秦處度  其八','李之儀','宋','宋诗','song-poetry','','[]','不返故鄉義，何妨陸子居。',48,'全唐诗/poet.song.54000.json','["不返故鄉義，何妨陸子居。", "昔游既有約，是豈人所圖。", "我嘗邀此卜，蹭蹬不自如。", "憑將一掬淚，聊寄夜臺書。"]'),
('5505201b-1301-48ee-9dc6-3a5d7217e6a2','莊居值雨偶得十詩示秦處度  其九','李之儀','宋','宋诗','song-poetry','','[]','向晚風斗轉，場上稻已芽。',48,'全唐诗/poet.song.54000.json','["向晚風斗轉，場上稻已芽。", "問雨何薄相，偏來戲吾家。", "蟋蟀牀下吟，絡緯林中誇。", "戒寒謂稍疏，行矣逢此嗟。"]'),
('f476c1f3-57f1-41d9-88be-d2bc41b37d98','莊居值雨偶得十詩示秦處度  其一○','李之儀','宋','宋诗','song-poetry','','[]','競爽聯夜光，一箇乃明月。',48,'全唐诗/poet.song.54000.json','["競爽聯夜光，一箇乃明月。", "吾友不可見，頼爾相怡悅。", "蒹葭空非倚，聲聞乃不輟。", "啜菽安暮年，足以免絕突。"]'),
('7d584fab-ee9d-4884-8c87-9377291a1cb0','題楊子儀虎圖','李之儀','宋','宋诗','song-poetry','','[]','秋陰報初寒，慘慘日遽晚。',96,'全唐诗/poet.song.54000.json','["秋陰報初寒，慘慘日遽晚。", "有客自宣城，明爽叩昏懶。", "手持兩巨軸，六幅從而展。", "披圖畫如生，竟軸詩盡選。", "平生說匡鼎，今日真到眼。", "何止辨騧驪，于焉識淄澠。", "愛之不能已，欲挂恨壁短。", "猶冀逢他時，更疑探深遠。"]'),
('d9f73d1e-b8a7-44f6-8efc-d228900a38f8','送人','李之儀','宋','宋诗','song-poetry','','[]','冥冥天邊鴻，蕩蕩風中雲。',96,'全唐诗/poet.song.54000.json','["冥冥天邊鴻，蕩蕩風中雲。", "一笑偶相逢，擊節聊送君。", "我室豈無酒，胡爲不開罇。", "所貴樂文字，固非異蕕薰。", "天門直牛渚，南北如相分。", "想君月下吟，未厭俚語聞。", "霜空夜自明，江月寒微昏。", "會當借饑鯨，永謝五濁渾。"]'),
('ad6a5be9-66cc-4a5d-9981-df14ca4b5856','書長干僧房','李之儀','宋','宋诗','song-poetry','','[]','昨日方得書，經年不相見。',48,'全唐诗/poet.song.54000.json','["昨日方得書，經年不相見。", "書來必累幅，分明如見面。", "雖同雨千花，略不通一線。", "誰云非吉祥，便是金毛現。"]'),
('c15cae4b-2b0d-4b19-b659-e297fba8b764','和人雪意','李之儀','宋','宋诗','song-poetry','','[]','雪意與春約，野情因物裁。',204,'全唐诗/poet.song.54000.json','["雪意與春約，野情因物裁。", "輒將無窮思，聊摛有限才。", "雲容忽破碎，山色如招回。", "携持固夙昔，端爲此濟來。", "歲晚君羈旅，微君誰我陪。", "祇恐造化工，特地吹葭灰。", "一剖不復收，寂爾爲之胚。", "戢戢競秀發，翩翩絕嫌猜。", "恍然徙倚間，浩蕩心胸開。", "境界適何許，次第分隅隈。", "高足超日觀，塗如下離堆。", "四顧始無間，忽覺驚初雷。", "有形均難悉，無物非蒿萊。", "却應求仙源，失路迷天台。", "波臣復笑屈，市門徒德梅。", "庶幾未始得，掇拾同舉杯。", "攘袂即千古，一醉姑相媒。"]'),
('69d4f918-5a11-44e1-9915-f75ee71e51d2','和人感懷','李之儀','宋','宋诗','song-poetry','','[]','高山在平地，高山地焉知。',288,'全唐诗/poet.song.54000.json','["高山在平地，高山地焉知。", "明珠出深淵，明珠淵豈期。", "高明屬在人，惟要須其時。", "物理固如此，了不差毫釐。", "身世端自窘，歲月相奔馳。", "所以得黽勉，吾人惟能詩。", "我非知詩者，平昔竊好之。", "每出每可愧，未易皆塤篪。", "而君不我鄙，論極牙解頤。", "六年如一日，不取笑則疑。", "彼烏足爲計，有類寧同嗤。", "一朝召命至，閭里增光輝。", "不曰人可賢，但從外物移。", "我賢君亦賢，誰能窮是非。", "我欲挽君留，留君竟何爲。", "聊作感慨別，肯效兒女悲。", "陳人不自信，流品須維持。", "誰謂廊廟姿，如我品乃宜。", "江充與丙吉，厚薄惟異施。", "其後七葉貂，陰功終表儀。", "是等代不乏，浪爾分騧驪。", "時哉君何失，儀鳳方臨池。", "爲我寄聲謝，擊壤正自嬉。", "勉旃夔龍事，賡載冀勿隳。"]'),
('ca761135-b65d-414a-9207-9d9269da1504','次韵東坡所和滕希靖雪浪石詩古律各一  其一','李之儀','宋','宋诗','song-poetry','','[]','風波末路方奔屯，屹然不動誰如尊。',160,'全唐诗/poet.song.54000.json','["風波末路方奔屯，屹然不動誰如尊。", "豈知胸中皦十日，顧盼不接無重昏。", "東觀海市俯弱水，南登赤壁凌江村。", "斯文未喪天豈遠，出沒狐鼠徒千門。", "綸巾羽扇晚自得，已聞漠北幾亡魂。", "由來好趣入造化，地靈特出雲濤根。", "生平到處苦再歷，隠隠似有屐齒痕。", "玻璃鏡裏萬象發，金粟堂中千偈論。", "會須白玉潄寒水，更借落月傾金盆。", "咄嗟菱溪成底物，混沌空夸竅鑿存。"]'),
('abe2f19c-aebd-4bea-b810-de4e672cb14e','次韵東坡所和滕希靖雪浪石詩古律各一  其二','李之儀','宋','宋诗','song-poetry','','[]','平生所願識荆州，別乘還容接勝流。',64,'全唐诗/poet.song.54000.json','["平生所願識荆州，別乘還容接勝流。", "異日崩騰驚海面，新詩清絕似槎頭。", "常嗟盛事千年隔，誰謂餘光一旦收。", "便覺詩源得三昧，目中無復有全牛。"]'),
('dd87dcb1-7089-49b5-a831-8a4cc5feeeaf','甘露堂歌','李之儀','宋','宋诗','song-poetry','','[]','炎天熇熇如湧湯，使君置酒甘露堂。',240,'全唐诗/poet.song.54000.json','["炎天熇熇如湧湯，使君置酒甘露堂。", "無風但覺冷徹骨，坐來彷彿飛青霜。", "使君顧客指新榜，天假此應來輝光。", "八十里叟感盛事，獻頌請名相激昂。", "我非取專已上報，堯仁舜智方當陽。", "邇來瑞應發處處，中臺第一彤雲章。", "吾邦雖僻亦影響，明德所祐真無疆。", "已而轉盼欲受簡，慚非叟比疇能當。", "輒因勝遇强黽勉，庶幾擊壤同揄揚。", "吾君之澤不可象，使君之惠何可忘。", "才高名重偶暫屈，遺愛他日逾甘棠。", "嗟予落莫徒自感，乍鳴乍已如寒螿。", "安時逐境姑委化，隨緣致力聊爲鄉。", "時逢載酒問難字，未擬持箠操羣羊。", "但知今日不易得，縱不能飲須空觴。"]'),
('1c1c3d6b-3c7f-4679-af6f-a522a51ad06f','白鈐轄席上琵琶歌','李之儀','宋','宋诗','song-poetry','','[]','青海傳烽沙遶塞，謀將橐戈身不介。',308,'全唐诗/poet.song.54000.json','["青海傳烽沙遶塞，謀將橐戈身不介。", "却携紅袖弄烟月，醉笑溪山窮物外。", "文章聲名家世事，投筆收功無十載。", "天子幾嗟相見晚，暫許南來聊曠快。", "一時賓客多可人，坐令五月如深春。", "畫棟潭潭簾半捲，濛濛香霧無纖塵。", "雲披霞散爛紅綠，滉漾無處投精神。", "秦樓風輕雁初泊，玉指如流乍前却。", "捍撥當胸拍屢催，一段風光來濩索。", "雖無儀鳳與舞獸，擊拊分明諧振躍。", "緱嶺排空午夜凉，杳杳鸞吟上寥廓。", "逡巡舞袖迴飛雪，紅茸毯襯鴉頭襪。", "落花飛絮互繽紛，流星掣電爭明滅。", "主人情不已，下客歡正濃，更邀婭姹持金鍾。", "從來酒戶落人後，瀲灧不覺隨手空。", "金張燕接平生慣，照眼今朝真未見。", "敢辭醉倒菊花偏，只恐銀潢低曉箭。", "鈞天一夢固依稀，欲問桃源路已迷。", "何時再到紅茸地，更遣游絲惹住伊。"]'),
('158fa333-762c-4237-bba7-ed9943afac73','雷塘行','李之儀','宋','宋诗','song-poetry','','[]','鞭長不能及馬腹，有限生涯時苦促。',131,'全唐诗/poet.song.54000.json','["鞭長不能及馬腹，有限生涯時苦促。", "空使後人悲前人，雷塘春草年年綠。", "誰知秀色若可餐，風光付與初憑肩。", "力殫四海笑未已，眉黛一螺當幾錢。", "君不見黄金棟樑回首蠹，漠漠胡沙青塚暮。", "么絃欲斷空自知，千金漫買長門賦。", "膏油續盡天須曉，石土餘壘可長保。", "就令並蒂永不分，也應終恨雷塘草。"]'),
('8e58f188-f0e8-4748-879a-441a682f4902','讀吳思道藏海詩集傚其體','李之儀','宋','宋诗','song-poetry','','[]','唐末詩人自一家，剪裁風月間鶑花。',64,'全唐诗/poet.song.54000.json','["唐末詩人自一家，剪裁風月間鶑花。", "憑陵墮緒篇篇勝，點綴餘妍字字斜。", "遠水連天來怨笛，爛霞烘日带棲鴉。", "法書警句真如此，流落桑榆重歎嗟。"]'),
('3a0063b1-df6c-4dcb-8456-0a7df3988357','次韵東坡還自嶺南','李之儀','宋','宋诗','song-poetry','','[]','憑陵歲月固難堪，食蘗多來味却甘。',64,'全唐诗/poet.song.54000.json','["憑陵歲月固難堪，食蘗多來味却甘。", "時雨纔聞徧中外，卧龍相繼起東南。", "天邊鶴駕瞻仙袂，雲裏詩牋带海嵐。", "重見門生應不識，雪髯霜鬢兩毿毿。"]'),
('e15beefa-485d-43dd-833e-e30249cc150a','寄邵暘叔發運','李之儀','宋','宋诗','song-poetry','','[]','德門平昔仰高陽，自是芝蘭根本香。',64,'全唐诗/poet.song.54000.json','["德門平昔仰高陽，自是芝蘭根本香。", "未許藩籬承妙晤，聊因文字借餘光。", "艤舟月下逢桓守，盤馬樓前見庾郎。", "冬杪相期定如約，爲君雲影認鸞凰。"]'),
('4172d64b-fc80-47c3-89cf-8f28818de1cd','次韵東坡沉香石詩','李之儀','宋','宋诗','song-poetry','','[]','海南枯朽插天長，歲久峰巒带蘚蒼。',64,'全唐诗/poet.song.54000.json','["海南枯朽插天長，歲久峰巒带蘚蒼。", "變化那知斲山骨，儀刑空只在人腸。", "幾因皦日疑鎸蠟，試沃清泉覺弄香。", "切莫輕珉亡什襲，須防偷眼誤摧剛。"]'),
('1bc22620-fc10-41ee-a2b6-e50029b7b8b5','送曾端伯之官濟北','李之儀','宋','宋诗','song-poetry','','[]','貂蟬七葉想前人，四世三公表一門。',64,'全唐诗/poet.song.54000.json','["貂蟬七葉想前人，四世三公表一門。", "虎步龍驤推贊冊，瑶環瑜珥見旁孫。", "琅琅廟器真無敵，衮衮淮流信有源。", "敝帚不堪終舊物，吐茵行欲奉餘尊。"]'),
('f6b46e57-3efc-4051-800c-031ec4766a28','濟上閒居','李之儀','宋','宋诗','song-poetry','','[]','閉閣焚香萬慮澄，莫云身似打包僧。',64,'全唐诗/poet.song.54000.json','["閉閣焚香萬慮澄，莫云身似打包僧。", "功名了未榮三事，理性容先契一燈。", "丹竈鶴歸休炷火，茶甌客訪旋敲冰。", "倦來却有登臨興，上徹層樓最上層。"]'),
('2ea06168-b4ad-4763-8513-d107494fe50f','告別子通','李之儀','宋','宋诗','song-poetry','','[]','謝庭蘭玉舊聞名，早歲風流接二兄。',64,'全唐诗/poet.song.54000.json','["謝庭蘭玉舊聞名，早歲風流接二兄。", "白璧無瑕尊士望，青雲有路藹鄉評。", "簞瓢弗改真天樂，簪紱相高半學生。", "授館不爲經宿去，知心黄憲異袁閎。"]'),
('2b4ccda6-9e28-443d-8c0b-57498fc3ca26','和儲子椿竹  其一','李之儀','宋','宋诗','song-poetry','','[]','何物能令意灑然，陰森常對出簷竿。',64,'全唐诗/poet.song.54000.json','["何物能令意灑然，陰森常對出簷竿。", "排槍立戟誰爲況，招月吟風好細看。", "幾度驚回窗下夢，新來添得雨中寒。", "傷心不見東坡老，縱有鵝溪下筆難。"]'),
('ca2d6c81-5261-4d69-9df9-9979c68fa388','和儲子椿竹  其二','李之儀','宋','宋诗','song-poetry','','[]','楚楚相親豈偶然，依依隨處自成竿。',64,'全唐诗/poet.song.54000.json','["楚楚相親豈偶然，依依隨處自成竿。", "固應表見風塵外，莫作尋常草木看。", "好事借名真有謂，多言雖巧不能寒。", "相思乍可食無肉，一日無君恰似難。"]'),
('2d2024c9-2fde-4b81-a719-36992a60e7ff','和子椿七夕','李之儀','宋','宋诗','song-poetry','','[]','何用封侯曲似鈎，且將膚寸等岑樓。',64,'全唐诗/poet.song.54000.json','["何用封侯曲似鈎，且將膚寸等岑樓。", "佳時未用傾河鼓，爽氣先期勝蓐收。", "月影正迷千古恨，雨聲還助五更愁。", "王孫賞詠元無敵，又見詩中第一流。"]'),
('09009fed-6e41-4ed0-a973-1453c331649c','題蘭皋','李之儀','宋','宋诗','song-poetry','','[]','萬綠交陰別有天，艤舟重到尚依然。',64,'全唐诗/poet.song.54000.json','["萬綠交陰別有天，艤舟重到尚依然。", "回頭白髮三千丈，倒指青編二十年。", "賞詠未論臺閣舊，維持今見子孫賢。", "何當□□披陳迹，再把重衾託醉眠。"]'),
('8b8cfe07-3331-429a-bf17-93c519af82ca','戲子微兼次韵陳君俞寄題蘭皋','李之儀','宋','宋诗','song-poetry','','[]','和風暖日作霜天，冰雪相投豈偶然。',64,'全唐诗/poet.song.54000.json','["和風暖日作霜天，冰雪相投豈偶然。", "特枉新詩詠陳迹，便同佳趣賞當年。", "學優曼倩三冬足，才過荆州十部賢。", "爲問醉衾應好在，莫教癡望似蠶眠。"]'),
('50244b73-5f9a-4d60-8762-84a940b17c24','題{巩/言}老小軒','李之儀','宋','宋诗','song-poetry','','[]','高步毗盧頂上身，旋開窗牖外風塵。',64,'全唐诗/poet.song.54000.json','["高步毗盧頂上身，旋開窗牖外風塵。", "石菖蒲是從來友，龍焙茶爲近日親。", "不見同行木上座，常留伴睡竹夫人。", "艱難歷盡無餘事，問佛方知有此因。"]'),
('133df6de-2d04-4132-a712-c636ee7fe8ae','因過墳山齋僧值雪遂賦小詩','李之儀','宋','宋诗','song-poetry','','[]','霜露悲傷老益增，輒憑精意託真乘。',64,'全唐诗/poet.song.54000.json','["霜露悲傷老益增，輒憑精意託真乘。", "舞花忽報難遭瑞，佳氣冥符不盡燈。", "薝葡園中紛一色，兜羅世界結千層。", "五天應供非虛語，從此雲頭日日升。"]'),
('1977b335-b50d-4367-88f4-11f07911265d','送宣上人遊方','李之儀','宋','宋诗','song-poetry','','[]','七軸蓮經誦已通，定將何事作家風。',64,'全唐诗/poet.song.54000.json','["七軸蓮經誦已通，定將何事作家風。", "當知法界重重意，盡在雲遊步步中。", "金臂見時猶是妄，玉毫光處未爲功。", "路頭全記文殊指，須着工夫子細窮。"]'),
('fc6f5187-329f-4448-91e0-a0bd054ac901','次韵郭功甫從何守遊白雲寺','李之儀','宋','宋诗','song-poetry','','[]','已仕因循已過三，買田歸去不須參。',64,'全唐诗/poet.song.54000.json','["已仕因循已過三，買田歸去不須參。", "高明漸擬凌清漢，皎潔方知在碧潭。", "試酌甘泉來覺晚，已躋絕頂尚猶貪。", "便應從此都無事，祇有君恩未報慚。"]'),
('6fe50f81-4f89-485e-9e2e-26d931ab0ff5','題白紵山','李之儀','宋','宋诗','song-poetry','','[]','回見黄梅雨後天，烟林常在笑談邊。',64,'全唐诗/poet.song.54000.json','["回見黄梅雨後天，烟林常在笑談邊。", "早時欲到不自果，今日初來端有緣。", "無復新聲傳玉齒，空餘殘照滿金田。", "不知誰是雲霞侶，聊揖高風一悵然。"]'),
('79584c06-d30e-497b-b15f-dc480fee84ab','石端若以朱絲欄見邀作而偶失所在久方得之喜而賦詩寄丁希韓因以見及遂申前志次韵','李之儀','宋','宋诗','song-poetry','','[]','斷雁沈蹤共倚欄，定應齊客解偷關。',64,'全唐诗/poet.song.54000.json','["斷雁沈蹤共倚欄，定應齊客解偷關。", "忽驚遼鶴排空至，何啻廉珠昨夜還。", "假寵已慚名下誤，强顔終愧筆頭慳。", "江流有盡情無盡，須把高風付子山。"]'),
('d4e6f113-2d04-401a-939c-5129cbc3dff5','再領玉局昔東坡翰林作詩送戴蒙有玉局他年第幾人之句後自嶺外歸遂領玉局予復官亦得之坡今亡矣悵然有懷','李之儀','宋','宋诗','song-poetry','','[]','東坡因地夙相親，玉局終爲繼戴人。',64,'全唐诗/poet.song.54000.json','["東坡因地夙相親，玉局終爲繼戴人。", "祿仕豈知承末軌，恩光又許襲前塵。", "青蠅附驥元非援，白玉無瑕晚更真。", "泉下有靈應首肯，不隨凡劣易緇磷。"]'),
('a5c8535f-3821-436f-a56a-b01bd32413ff','次韵葛大川喜王君相過并寄吳思道','李之儀','宋','宋诗','song-poetry','','[]','君恩曾未報纖埃，倦緒淹時鬰不開。',64,'全唐诗/poet.song.54000.json','["君恩曾未報纖埃，倦緒淹時鬰不開。", "高義不忘轅下舊，好音常自日邊來。", "欣逢雅好非空至，頓感陽春泛酒迴。", "早晚退朝紅蘂下，細談陳迹共餘盃。"]'),
('c1b4b746-97cb-4699-b9d6-f7136e5274af','呂吉甫第乃謝鎮西故居中間常爲佛剎而雙檜則舊物也劉夢得有詩因賦其韵','李之儀','宋','宋诗','song-poetry','','[]','故國悲凉古木奇，勢分庭下蔚相差。',64,'全唐诗/poet.song.54000.json','["故國悲凉古木奇，勢分庭下蔚相差。", "霜根半露出林虎，晝影全舒破賊旗。", "寶界曾迴鋪地色，節旄還映插雲枝。", "劉郎風韵知難敵，儒帥端能表異時。"]'),
('2af24cb7-4fad-41d7-b398-de4b92c36315','題張湛然兄弟所居壁時謁之不見','李之儀','宋','宋诗','song-poetry','','[]','樂全老子如星日，真一仙人似鳳鸞。',64,'全唐诗/poet.song.55000.json','["樂全老子如星日，真一仙人似鳳鸞。", "早歲光明均照耀，異時文彩避高寒。", "低回氣類追千劫，邂逅風流得二難。", "環堵蕭然清徹骨，却疑深雪卧袁安。"]'),
('5b30786d-d928-4bb1-88a5-728a53eb75b8','李去言相別二年忽得書知在吳中答書偶成','李之儀','宋','宋诗','song-poetry','','[]','宦路相逢一笑休，共知身世兩虛舟。',64,'全唐诗/poet.song.55000.json','["宦路相逢一笑休，共知身世兩虛舟。", "楚材有用誰青眼，趙將無功枉白頭。", "會見姓名通北闕，何妨風韵冠南州。", "求田接武如鳧鷖，只欠元龍百尺樓。"]'),
('4a0968cb-855f-45fc-a457-54d8dd18e11c','與珪元白相別之次日大雪火邊有懷其人','李之儀','宋','宋诗','song-poetry','','[]','上人偶作十日留，才別便覺如三秋。',64,'全唐诗/poet.song.55000.json','["上人偶作十日留，才別便覺如三秋。", "應覺擁爐華藏客，不知對雪姑溪愁。", "清詩字字吟可老，冷日愔愔誰見投。", "媿我霜髯不用剪，寒灰撥盡欲何求。"]'),
('8af9bd24-58fe-4fef-ad17-65d0acdf992f','次儲子椿金陵作別韵','李之儀','宋','宋诗','song-poetry','','[]','千里波濤一葉中，急難平日但聞風。',64,'全唐诗/poet.song.55000.json','["千里波濤一葉中，急難平日但聞風。", "自非積習有天得，那復間關特地同。", "樂事放懷須命酒，生涯何處不飄蓬。", "先歸只作尋常別，切莫樽前感斷鴻。"]'),
('46b2554a-51ea-45ec-a138-bfd5f6275043','又次子椿同君俞三詩  其一','李之儀','宋','宋诗','song-poetry','','[]','倦途回首已無牛，獨向田間涉早秋。',64,'全唐诗/poet.song.55000.json','["倦途回首已無牛，獨向田間涉早秋。", "倚仗固知同失馬，攀援猶恐昧操舟。", "漸逢陌上相推醉，尚有空中未下鷗。", "可是道邊無葬地，肯將身世曲如鈎。"]'),
('0c8c9d5e-683a-4c4e-b5f1-4d625894cf0e','又次子椿同君俞三詩  其二','李之儀','宋','宋诗','song-poetry','','[]','西來不復見青牛，問遍生涯兩鬢秋。',64,'全唐诗/poet.song.55000.json','["西來不復見青牛，問遍生涯兩鬢秋。", "但受郢人夸鼻斲，豈知蒙叟是腰舟。", "柱頭寂寞千年鶴，波面分明一點鷗。", "不向虛中問消息，磻溪終老但垂鈎。"]'),
('853683f8-db07-4ffc-b7e8-78ddb3ab8868','又次子椿同君俞三詩  其三','李之儀','宋','宋诗','song-poetry','','[]','隠隠山林似卧牛，紛紛鐮擔喜逢秋。',64,'全唐诗/poet.song.55000.json','["隠隠山林似卧牛，紛紛鐮擔喜逢秋。", "虛名漫託三春柳，實際須歸萬斛舟。", "未信此生真野馬，且將餘日寄江鷗。", "崎嶇精衛人空笑，終恐長鯨上直鈎。"]'),
('70d2971f-3963-41b4-8259-e7803dcb4f11','次韵子椿金陵相會詩','李之儀','宋','宋诗','song-poetry','','[]','濛濛小雨落征帆，漠漠烟雲遠近山。',64,'全唐诗/poet.song.55000.json','["濛濛小雨落征帆，漠漠烟雲遠近山。", "屬意幾回真入夢，欲來常恨澀如灣。", "家程豈復嗟留滯，物外何妨且往還。", "便恐都人入圖畫，却應難寫是高閒。"]'),
('34466616-b919-4b27-90f4-ea5dd77bb749','次韵子椿遊雨花臺同長老德正','李之儀','宋','宋诗','song-poetry','','[]','勝遊自有經年約，佳客難同信步來。',64,'全唐诗/poet.song.55000.json','["勝遊自有經年約，佳客難同信步來。", "無復風烟翳寒日，漸催花柳映高臺。", "雲光故事空陳迹，玉樹遺音失舊哀。", "今昔循環等相視，欲尋歸路更遲回。"]'),
('c4480183-374e-4e6f-af85-d221011e2151','又次莊居見貽佳什','李之儀','宋','宋诗','song-poetry','','[]','茫茫巨浸託船歸，風不充帆氣易衰。',64,'全唐诗/poet.song.55000.json','["茫茫巨浸託船歸，風不充帆氣易衰。", "猶喜歲寒逢逆旅，不將人事異當時。", "從他老去知何用，由是終焉豈自遺。", "獨有東阡南陌意，莫辭扶杖數相期。"]'),
('2e5be87e-4aca-439b-a085-7ab7199fa879','用聖行韵和呈幾仲','李之儀','宋','宋诗','song-poetry','','[]','牢落郊原正早收，書來起我頓風流。',64,'全唐诗/poet.song.55000.json','["牢落郊原正早收，書來起我頓風流。", "絃歌韵裏識琴賤，鴻鵠飛時逢奕秋。", "極目烟雲來指顧，何時談笑共沈浮。", "文章落筆驚人眼，新有聲名舊姓侯。"]'),
('b77fbffc-721b-48c8-b3e3-fc52f1048df5','和人見寄二首  其一','李之儀','宋','宋诗','song-poetry','','[]','雍容閒雅許君都，萬緒相逢一笑無。',64,'全唐诗/poet.song.55000.json','["雍容閒雅許君都，萬緒相逢一笑無。", "休把盛衰觀世諦，且將言語共詩圖。", "人亡人得同吹吷，潮落潮生等據梧。", "只恐後庭歌不盡，曲終翻被鬼揶揄。"]'),
('2a91c4a5-e0dd-4c76-88b4-897b7ed53af8','和人見寄二首  其二','李之儀','宋','宋诗','song-poetry','','[]','傾蓋相逢惜別離，等閒談笑盡心期。',64,'全唐诗/poet.song.55000.json','["傾蓋相逢惜別離，等閒談笑盡心期。", "它年終解如今日，此念常應寄異時。", "餘事不妨多蠟屐，放懷贏得盛留詩。", "早携桃葉尋歸路，準擬花間倒接䍦。"]'),
('6981cb26-3400-4309-89df-e1bf84511eaf','澄虛堂','李之儀','宋','宋诗','song-poetry','','[]','公子高明悟劫灰，鼎開軒語致幽懷。',64,'全唐诗/poet.song.55000.json','["公子高明悟劫灰，鼎開軒語致幽懷。", "縈雲疊巘鑱天去，極目滄波入坐來。", "千首詩成談笑裏，百分酒盡筦絃催。", "自憐曾是高堂客，欲賦慚無宋玉才。"]'),
('84a146af-bf99-479b-a683-31864b784095','和子椿','李之儀','宋','宋诗','song-poetry','','[]','一番霖雨下商巖，末路方收破冢帆。',64,'全唐诗/poet.song.55000.json','["一番霖雨下商巖，末路方收破冢帆。", "雞肋未能忘甽畝，驪珠還見發囊函。", "潤分餘浸回枯轍，色借陽春起陋緘。", "自是亨嘉相際會，便應從此出塵凡。"]'),
('11bdb8e1-4344-4bcc-811f-dcf257224ba5','莊居寄友人','李之儀','宋','宋诗','song-poetry','','[]','槐黄時節早相期，留滯田園阻蹔依。',64,'全唐诗/poet.song.55000.json','["槐黄時節早相期，留滯田園阻蹔依。", "聞道程文太超軼，却因詩句接光輝。", "君能活計如公理，我愧生涯負表微。", "已向青山託遺老，不應專有謝玄暉。"]'),
('cace55bb-7e0c-4519-aac5-d5851aa18b8f','和友人見寄三首  其一','李之儀','宋','宋诗','song-poetry','','[]','明月平時敢自因，特高蘭玉信吾人。',64,'全唐诗/poet.song.55000.json','["明月平時敢自因，特高蘭玉信吾人。", "便從緱嶺如無媿，更許毗耶約問津。", "每見似醺千日酒，不言常備四時春。", "妙雲豈獨南遊契，又喜鍾山近得鄰。"]'),
('7ad6e5b4-3b03-4784-ba55-68cc40f1f6d4','和友人見寄三首  其二','李之儀','宋','宋诗','song-poetry','','[]','俗駕難回固有因，勒移終愧北山人。',64,'全唐诗/poet.song.55000.json','["俗駕難回固有因，勒移終愧北山人。", "不辭冒雨投歸步，始信忘形是要津。", "一笑未容披軟語，十分先覺報新春。", "定應偏契王郎便，消得從來願卜鄰。"]'),
('818d8e6f-aff1-4ca4-8efc-cb4300e01bb4','和友人見寄三首  其三','李之儀','宋','宋诗','song-poetry','','[]','除却吟詩總是塵，道人應笑可憐人。',64,'全唐诗/poet.song.55000.json','["除却吟詩總是塵，道人應笑可憐人。", "固知參請能成佛，未到升騰且咽津。", "村落風烟常似臘，禪房燈火已如春。", "會須隨例餐䭔子，聊借明窗暫作鄰。"]'),
('4f023d9b-fa5d-4c29-b698-c5876b7c578d','舊懷二首  其一','李之儀','宋','宋诗','song-poetry','','[]','陳迹回頭似夢餘，花應長好但人無。',64,'全唐诗/poet.song.55000.json','["陳迹回頭似夢餘，花應長好但人無。", "詩成固已名千古，墓上誰傾飯一盂。", "流落丹青驚始見，形容筆墨竟難圖。", "公孫自是天同派，漫託周人載碩膚。"]'),
('38ad98ab-8f0d-4844-9e71-abc6eae64ccb','舊懷二首  其二','李之儀','宋','宋诗','song-poetry','','[]','花存人往祗天知，目暗心摇却自疑。',64,'全唐诗/poet.song.55000.json','["花存人往祗天知，目暗心摇却自疑。", "尚想漢庭傳詔令，如登魯廟見樽彝。", "一時鸚鵡娛賓賦，百世甘棠美召詩。", "安得殘春逢海上，盡須衰淚灑新枝。"]'),
('37bec810-3106-4111-9f7b-0b84aad862f6','送人入館閣','李之儀','宋','宋诗','song-poetry','','[]','天祿崢嶸北斗齊，享窮人欲去無梯。',64,'全唐诗/poet.song.55000.json','["天祿崢嶸北斗齊，享窮人欲去無梯。", "自非終賈名偏重，祇恐蓬瀛到却迷。", "鉛槧異時森杞梓，功名他日看虹蜺。", "中朝若問姑溪老，但道摧頹一木雞。"]'),
('6c4449b9-2c4c-4b32-8c59-02bb40faf2e8','邂逅故人  其一','李之儀','宋','宋诗','song-poetry','','[]','湖山勝處得君家，懷祖曾於膝上誇。',64,'全唐诗/poet.song.55000.json','["湖山勝處得君家，懷祖曾於膝上誇。", "不見多年應宦遠，相逢何事却天涯。", "朱絃無復來湘水，駿骨分明産渥洼。", "聞道賢勞多野處，新醅聊寄傲霜花。"]'),
('72c8cb33-eaa7-42e6-8c18-90eb58dc5661','邂逅故人  其二','李之儀','宋','宋诗','song-poetry','','[]','已將身世等浮雲，又向江邊得故人。',64,'全唐诗/poet.song.55000.json','["已將身世等浮雲，又向江邊得故人。", "數日暝寒埋雪意，一番佳境爲時新。", "村醅淡薄聊資笑，洞戶深閒自有春。", "已幸鄰封同寄老，却應風月費精神。"]'),
('8a7448de-e5db-4c17-9daa-f921dd48ebd8','金陵懷古二首  其一','李之儀','宋','宋诗','song-poetry','','[]','焰燧何勞鼓萬牛，聊將一带付幽流。',64,'全唐诗/poet.song.55000.json','["焰燧何勞鼓萬牛，聊將一带付幽流。", "纔聞浮鷁來波上，已見牽羊出石頭。", "舊穴依然披信汐，古祠誰爲薦時羞。", "功名到了成何事，擾擾空移夜壑舟。"]'),
('a8cd5002-8b4d-430e-a09b-0f1165b4731c','金陵懷古二首  其二','李之儀','宋','宋诗','song-poetry','','[]','霜天日晚獨沈吟，潮上風來別是音。',64,'全唐诗/poet.song.55000.json','["霜天日晚獨沈吟，潮上風來別是音。", "恃險戰爭休想舊，凭高臨眺且論今。", "數聲雁蹙千年恨，一片帆驚萬里心。", "不是江山解磨折，却應人物自升沈。"]'),
('ca4cc61c-b8e5-42ac-983c-f1a5365b5395','和人見寄','李之儀','宋','宋诗','song-poetry','','[]','壯志崢嶸不自神，低回聊此接波臣。',64,'全唐诗/poet.song.55000.json','["壯志崢嶸不自神，低回聊此接波臣。", "雖非腰重真騎鶴，猶勝途窮强泣麟。", "擊節久懷洲上晚，空樽未放網邊春。", "固知遺老能相契，翻愧公輸作幸民。"]'),
('37d5ac7e-ba9b-4c7a-8e18-db7bf825da4c','邯鄲叢臺','李之儀','宋','宋诗','song-poetry','','[]','禾黍離離露一丘，淡烟輕靄夕陽秋。',64,'全唐诗/poet.song.55000.json','["禾黍離離露一丘，淡烟輕靄夕陽秋。", "微基西枕邯山盡，往事東隨漳水流。", "御輦金車何處去，閒花野草幾時休。", "可憐全趙繁華地，留作行人萬古愁。"]'),
('26049f53-73cb-474a-8284-ed3e2cc68f64','久雨次韵君俞','李之儀','宋','宋诗','song-poetry','','[]','塵埃肺腑屢更時，淫雨平欺素頷垂。',64,'全唐诗/poet.song.55000.json','["塵埃肺腑屢更時，淫雨平欺素頷垂。", "忽覺光輝慰岑寂，坐令華茂轉離披。", "中痟未厭徒空壁，雅意安能系赤墀。", "獨有晴明陪擊節，回腸尤在不爲詩。"]'),
('321f6736-1618-4f7c-b874-37693d1abd96','次韵君俞瑞香','李之儀','宋','宋诗','song-poetry','','[]','占盡韶華異衆芳，分明絕艷降昭陽。',64,'全唐诗/poet.song.55000.json','["占盡韶華異衆芳，分明絕艷降昭陽。", "肯同繁杏攙春色，漫道幽蘭有國香。", "大葉尚疑攢處髻，馬嵬猶認去時囊。", "牡丹獨賞慈恩句，只解金盃比發粧。"]'),
('b4e00f87-e56f-4cb4-a17d-ee826391112c','次韵君俞四首  其一','李之儀','宋','宋诗','song-poetry','','[]','文章老去豈能神，猶有殘膏占舊名。',64,'全唐诗/poet.song.55000.json','["文章老去豈能神，猶有殘膏占舊名。", "賦就賈生空自感，詩成侯喜近聞聲。", "拾塵已信非嘗飯，撒豆終知不是兵。", "多謝嘉篇慰岑寂，便思約伴問歸程。"]'),
('8a2f2b05-2f13-4eec-a0fd-48e303d09b7b','次韵君俞四首  其二','李之儀','宋','宋诗','song-poetry','','[]','合浦圓光降下胎，豫章千尺本天材。',64,'全唐诗/poet.song.55000.json','["合浦圓光降下胎，豫章千尺本天材。", "未能海運參摶翼，聊復舟行共覆杯。", "白髮情懷雖草莽，青春消息自條枚。", "何妨接武窮幽致，莫待風光却見催。"]'),
('857f15a6-0137-40d7-9d7a-fd7e1298a49b','次韵君俞四首  其三','李之儀','宋','宋诗','song-poetry','','[]','語解驚人固有神，始知無不是虛名。',64,'全唐诗/poet.song.55000.json','["語解驚人固有神，始知無不是虛名。", "方觀去接天邊翼，何事猶諧爨下聲。", "齊晉近能通歃血，江黄詎敢議鏖兵。", "老來肺腑都荆棘，頓欲薅鋤不計程。"]'),
('34273d8e-d6fc-4544-9e97-1cc1df1869c7','次韵君俞四首  其四','李之儀','宋','宋诗','song-poetry','','[]','熊掌如何得豹胎，棄常嗜異信難材。',64,'全唐诗/poet.song.55000.json','["熊掌如何得豹胎，棄常嗜異信難材。", "端能不學邯鄲步，正可同嘗沆瀣杯。", "有意良圖休我老，他年吉卜佇君枚。", "雲間日下容相契，且置燃萁特地催。"]'),
('dfedfd4b-7fc6-48cc-8b1d-fbd2a9498d55','堤上閒步二首  其一','李之儀','宋','宋诗','song-poetry','','[]','風旌江木信漂浮，散策騰騰亦謬悠。',64,'全唐诗/poet.song.55000.json','["風旌江木信漂浮，散策騰騰亦謬悠。", "未必縈回能擢勝，却疑平遠解供愁。", "年衰易感難留日，機盡應無不下鷗。", "渡口舟橫晚潮急，一番佳意憶蘇州。"]'),
('41f6fb77-e059-4a6c-8770-0922d87cb538','堤上閒步二首  其二','李之儀','宋','宋诗','song-poetry','','[]','暖風輕蹙浪花浮，留滯江城媿謝悠。',64,'全唐诗/poet.song.55000.json','["暖風輕蹙浪花浮，留滯江城媿謝悠。", "吟苦空多屈原恨，賦殘猶剩庾郎愁。", "漸因卜築投歸鷺，聊托潺湲習戲鷗。", "可笑麤官殺風景，滿船絲管載凉州。"]'),
('98b624a0-ce37-438b-a5a7-9f729b2fa331','題韋深道寄傲軒','李之儀','宋','宋诗','song-poetry','','[]','南窗何似北窗凉，寄傲來風各有方。',64,'全唐诗/poet.song.55000.json','["南窗何似北窗凉，寄傲來風各有方。", "千古光輝如昨日，一時收拾付新堂。", "已驚醆裏醅初綠，更覺籬邊菊漸黄。", "就使主人官即顯，此門高興定難忘。"]'),
('ebc7af1b-6a33-44b9-b672-a76924f45323','次韵君俞兼簡少孫六首  其一','李之儀','宋','宋诗','song-poetry','','[]','連璧兼金盡出倫，雪髯霜鬢信陳人。',64,'全唐诗/poet.song.55000.json','["連璧兼金盡出倫，雪髯霜鬢信陳人。", "能忘枘鑿方圓異，許接風雲變化新。", "絕韵淹時勞極目，虛齋窮日但凝塵。", "何當一笑披環堵，頼月吟哦未厭貧。"]'),
('32398a41-b91d-433c-b974-88263e2adf21','次韵君俞兼簡少孫六首  其二','李之儀','宋','宋诗','song-poetry','','[]','殘編弊藁掩還開，好意經年不暫來。',64,'全唐诗/poet.song.55000.json','["殘編弊藁掩還開，好意經年不暫來。", "伏櫪已應真款段，脫鞲終擬謝低回。", "頗傳共坐侵斜月，更想微吟薦罰杯。", "居士從來少風味，獨將愁眼望初梅。"]'),
('64a09c27-f8d7-4c80-8288-335c6f15aaea','次韵君俞兼簡少孫六首  其三','李之儀','宋','宋诗','song-poetry','','[]','莫羨財多石季倫，任從閭里笑長人。',64,'全唐诗/poet.song.55000.json','["莫羨財多石季倫，任從閭里笑長人。", "五湖浪迹名終在，六印懸腰眼暫新。", "且樂歌呼隨瀝斝，不妨文字洗留塵。", "年來頓覺珠璣富，萬戶侯家却是貧。"]'),
('0d807dd3-e99f-4ec0-b482-dbad9f1a4cfb','次韵君俞兼簡少孫六首  其四','李之儀','宋','宋诗','song-poetry','','[]','愔愔懷抱不曾開，忽忽還添一歲來。',64,'全唐诗/poet.song.55000.json','["愔愔懷抱不曾開，忽忽還添一歲來。", "燈火香花隨贊祝，兒孫旛勝共徘徊。", "休誇路寢當前拜，誰得屠蘇最後杯。", "何物相期同一醉，爲君催發檻前梅。"]'),
('4d273f0d-28d6-473c-998e-6839a0f89ac1','次韵君俞兼簡少孫六首  其五','李之儀','宋','宋诗','song-poetry','','[]','定應春到今日幾，但覺耳邊多醉人。',64,'全唐诗/poet.song.55000.json','["定應春到今日幾，但覺耳邊多醉人。", "已分餘生不如舊，却應佳句漸能新。", "悲來徒有縈心淚，情盡空驚滿眼塵。", "到得錐無真我輩，一簞猶是作家貧。"]'),
('e7296467-0be3-4934-bc50-f37625ca93a8','次韵君俞兼簡少孫六首  其六','李之儀','宋','宋诗','song-poetry','','[]','書空懶作咄咄語，催老祗怪駸駸來。',64,'全唐诗/poet.song.55000.json','["書空懶作咄咄語，催老祗怪駸駸來。", "斷夢已將愁共遠，離魂不覺淚驚回。", "病餘想見嶄巖玉，歡處猶懷宛轉杯。", "能伴晴和着屐否，深山應有未凋梅。"]'),
('05beff7a-d805-440f-ba32-226737f3a3d0','觀東坡集','李之儀','宋','宋诗','song-poetry','','[]','今朝又讀東坡集，記得原州鞫獄時。',64,'全唐诗/poet.song.55000.json','["今朝又讀東坡集，記得原州鞫獄時。", "千首高吟賡欲遍，幾多强韵押無遺。", "固知才氣原非敵，獨有心期老不欺。", "淚盡九原無路見，冰霜他日看青枝。"]'),
('847909b2-9921-47d9-8dbb-ab67aad29672','再次韵奉送禹欽且堅再來之約  其一','李之儀','宋','宋诗','song-poetry','','[]','涔涔梅雨漲江濱，耿耿僧房借鉢人。',64,'全唐诗/poet.song.55000.json','["涔涔梅雨漲江濱，耿耿僧房借鉢人。", "秀色驚回隨念到，孤懷贏得暫時新。", "何妨一笑空諸有，更覺三摩浄六塵。", "憂患年來倍傷感，送君衰淚不容貧。"]'),
('ca8bb6ce-82ae-4740-a996-44476072cb1d','再次韵奉送禹欽且堅再來之約  其二','李之儀','宋','宋诗','song-poetry','','[]','相逢懷抱各全開，蔚結才舒倏又來。',64,'全唐诗/poet.song.55000.json','["相逢懷抱各全開，蔚結才舒倏又來。", "傾倒已辜將進酒，追隨休賦上林回。", "臨分莫作楚愁歎，故事須詢河朔杯。", "看取滁翁宜自警，空將遺恨感蘇梅。"]'),
('8bff7dca-9345-497f-ac75-677318e8fc76','襲前韵再簡少孫四首  其一','李之儀','宋','宋诗','song-poetry','','[]','由來氣類即天倫，孰謂劉琨獨可人。',64,'全唐诗/poet.song.55000.json','["由來氣類即天倫，孰謂劉琨獨可人。", "稍隔相從更無味，幾因拈起又還新。", "席間誰致龍皮異，雪裏常懷鶴羽塵。", "祗欲期君拾瑶草，庾郎三韭未爲貧。"]'),
('ab04f120-6249-4185-8cff-c433c043f216','襲前韵再簡少孫四首  其二','李之儀','宋','宋诗','song-poetry','','[]','雪意埋雲蔚不開，新春還傍故春來。',64,'全唐诗/poet.song.55000.json','["雪意埋雲蔚不開，新春還傍故春來。", "未堪骯髒倚門立，聊復差池接羽回。", "得喪但知求失馬，盛衰贏取付傳杯。", "風流二妙天憐我，種玉秧中更插梅。"]'),
('03ca801c-80a0-48f3-ae4e-2d170473f479','襲前韵再簡少孫四首  其三','李之儀','宋','宋诗','song-poetry','','[]','子默清真本絕倫，羊曇仍是箇中人。',64,'全唐诗/poet.song.55000.json','["子默清真本絕倫，羊曇仍是箇中人。", "林泉不作南風競，旗幟還因對壘新。", "金礦躍罏元有艷，冰壺瑩月舊無塵。", "何妨再葺昆陽戰，尋邑師行固不貧。"]'),
('25786015-90f4-4d55-9bf4-377b42b28288','襲前韵再簡少孫四首  其四','李之儀','宋','宋诗','song-poetry','','[]','記得金樽特地開，舉頭新歲又重來。',64,'全唐诗/poet.song.55000.json','["記得金樽特地開，舉頭新歲又重來。", "銀潢已分經年隔，玉節猶期舊臘回。", "千汲浪迷雲表夢，百分愁寄燭殘杯。", "醉鄉誰謂無消息，已覺歌聲傍落梅。"]'),
('0a7baed7-c885-46a6-b579-f3c84e9ab1a2','次韵雪','李之儀','宋','宋诗','song-poetry','','[]','臘日頻年未嘗雪，今春雪與臘俱來。',64,'全唐诗/poet.song.55000.json','["臘日頻年未嘗雪，今春雪與臘俱來。", "暖歸白傅金蕉葉，寒逼溫郎玉鏡臺。", "幾處歡聲動絲竹，一番佳思近離堆。", "新詩不以尋梅見，萬里豐登氣已回。"]'),
('40d61ad1-a45f-409d-8d6a-d8180ae56c55','題張約之長春閣','李之儀','宋','宋诗','song-poetry','','[]','江山信美亦人同，寒暑隨時興易窮。',64,'全唐诗/poet.song.55000.json','["江山信美亦人同，寒暑隨時興易窮。", "寓意果能超物境，養花長欲占春風。", "何須戶外屨常滿，自樂尊中酒不空。", "可笑道人猶有恨，一番紅盡一番紅。"]'),
('91ae625d-ca81-49bc-9b4b-aa510928bbd2','後圃','李之儀','宋','宋诗','song-poetry','','[]','鵓鳩呼婦天欲雨，杏子退花鶑未雛。',64,'全唐诗/poet.song.55000.json','["鵓鳩呼婦天欲雨，杏子退花鶑未雛。", "庭前已覺綠半毯，酒面忽有紅雙鳬。", "芳物戀客不忍去，主人好賢誰復如。", "會應百歲享此樂，何妨畫作重屏圖。"]'),
('45596535-b124-4b76-9428-7fe96ba70b0f','寄題子椿野軒','李之儀','宋','宋诗','song-poetry','','[]','江山秀氣表吾人，輦下開軒得趣新。',64,'全唐诗/poet.song.55000.json','["江山秀氣表吾人，輦下開軒得趣新。", "不擬舊遊離几席，常令每況隔埃塵。", "客來談笑無非楚，紙上文章近過秦。", "分我一枝頻見約，乘槎行欲問通津。"]'),
('3ec98160-e16d-417a-a0b9-3082cdd9d973','避暑無地偶過君俞聊資華屋廣蔭以揖主人之勝綢繆禮意遂至抵暮君俞有詩因次韵二首  其一','李之儀','宋','宋诗','song-poetry','','[]','無功衛鶴偶乘軒，虐暑從誰解倒懸。',64,'全唐诗/poet.song.55000.json','["無功衛鶴偶乘軒，虐暑從誰解倒懸。", "頓覺御風凌絕境，似逢調瑟認華年。", "回光已幸參東壁，裂地何須得酒泉。", "自惜抑揚非瓦礫，倦途終愧失陶甄。"]'),
('308d0e79-ec2d-4910-9fbb-ad19249e2aec','避暑無地偶過君俞聊資華屋廣蔭以揖主人之勝綢繆禮意遂至抵暮君俞有詩因次韵二首  其二','李之儀','宋','宋诗','song-poetry','','[]','十輪楊惲舊軒軒，四壁相如似磬懸。',64,'全唐诗/poet.song.55000.json','["十輪楊惲舊軒軒，四壁相如似磬懸。", "豈謂投懷忘晚節，每容佳處共流年。", "笑談璀璨風生坐，翰墨縱橫思湧泉。", "土苴固難重就器，轉鈞尤幸識精甄。"]'),
('a0a543b3-b80d-46d1-a4f3-f20fe3deb940','歸自錢塘伏蒙君俞特枉佳句欽歎不已聊賦來韵','李之儀','宋','宋诗','song-poetry','','[]','吳山陳迹已飛埃，投老還驚病眼開。',64,'全唐诗/poet.song.55000.json','["吳山陳迹已飛埃，投老還驚病眼開。", "似泛靈槎海邊去，却因華表鶴歸來。", "情移客枕收殘夢，恨着江梅戀故臺。", "便覺新篇資六翮，飄飄真是子虛才。"]'),
('5a149e6f-292c-4986-916b-765f795c1bfa','贈金陵榮天和','李之儀','宋','宋诗','song-poetry','','[]','生涯已定不干時，收拾工夫且作詩。',64,'全唐诗/poet.song.55000.json','["生涯已定不干時，收拾工夫且作詩。", "瀨水方來弔東野，同安初喜識丘遲。", "兼將佛事資三昧，又喜風騷出一枝。", "投老相逢能幾許，何堪得句每相期。"]'),
('1ee3f686-7a9f-4cdd-aa31-e40650975b7e','劉君以地里之學各邂逅相遇求詩爲別因賦長句','李之儀','宋','宋诗','song-poetry','','[]','久聞秘術獨超羣，肯向青囊學景純。',64,'全唐诗/poet.song.55000.json','["久聞秘術獨超羣，肯向青囊學景純。", "解使山川如在掌，須知禍福不由人。", "論功合附天仙籍，底事猶隨客路塵。", "滿眼峰巒應有待，何妨裁剪出精神。"]'),
('6d79ffff-14f0-4a31-a5d1-6726c533ef43','伯鎮客居傷春佳句輒賦元韵二首  其一','李之儀','宋','宋诗','song-poetry','','[]','休論莫莫與休休，老眼逢春且暫留。',64,'全唐诗/poet.song.55000.json','["休論莫莫與休休，老眼逢春且暫留。", "未必餘寒更能久，祇因殘蘂易爲揉。", "及時行樂何妨剩，感物興懷漫自愁。", "南北生涯等羈旅，定應無着是清流。"]'),
('35ddedcc-6623-4e54-97c8-7f702e27bb9f','伯鎮客居傷春佳句輒賦元韵二首  其二','李之儀','宋','宋诗','song-poetry','','[]','紛紛到底不如休，空把閒心見便留。',64,'全唐诗/poet.song.55000.json','["紛紛到底不如休，空把閒心見便留。", "昨日白消行處去，今朝綠遍定誰揉。", "且從寂滅翻千偈，安用深湛詠四愁。", "我坐言多欲無語，每慚佳思枉詩流。"]'),
('e5b9cc1d-a977-4e6e-8453-e5013ae53c77','次韵夾竹桃花','李之儀','宋','宋诗','song-poetry','','[]','料理愁懷落那邊，桃花烘日竹含烟。',64,'全唐诗/poet.song.55000.json','["料理愁懷落那邊，桃花烘日竹含烟。", "牆紅密約連昌曉，夏木深藏繡嶺天。", "籃轝造門如會面，漁舟失路想當年。", "因君詠出黄筌筆，從此風光生彩牋。"]'),
('8b2a3ca2-e1bf-43b4-98b2-e2a75fa68259','次韵聞笛','李之儀','宋','宋诗','song-poetry','','[]','涓涓水咽衆山泉，隠隠雷驚二月天。',64,'全唐诗/poet.song.55000.json','["涓涓水咽衆山泉，隠隠雷驚二月天。", "共喜春工能應候，方知節物似烹鮮。", "倦途所欠無多子，勝日相逢又一年。", "好是羣花應競發，不須留待柳三眠。"]'),
('c79ed2b8-c46f-4fe5-a9a2-5f5aba269696','和郭功甫贈陳待制致仕二首  其一','李之儀','宋','宋诗','song-poetry','','[]','十年朝馬望前程，晚作琳宮物外人。',64,'全唐诗/poet.song.55000.json','["十年朝馬望前程，晚作琳宮物外人。", "徹骨清風真有韵，醉心常德本來淳。", "新栽松菊開三徑，舊檢方書備六陳。", "不是詩翁形美頌，丹青難寫自由身。"]'),
('893a3da7-fc13-40aa-946d-4c0b0538926d','和郭功甫贈陳待制致仕二首  其二','李之儀','宋','宋诗','song-poetry','','[]','南北紛紛不覺塵，鴛鴦湖水解留人。',64,'全唐诗/poet.song.55000.json','["南北紛紛不覺塵，鴛鴦湖水解留人。", "乳浮香焙誰同試，螘泛家篘分外淳。", "禪寂久因師粲可，婚姻便可繼朱陳。", "莫從舊路尋歸夢，占取東籬採菊身。"]'),
('d3c0caed-1e58-4b9c-929d-bb7ba605d4dc','和人三首  其一','李之儀','宋','宋诗','song-poetry','','[]','昂昂野鶴固難羣，皎皎冰壺不受塵。',64,'全唐诗/poet.song.55000.json','["昂昂野鶴固難羣，皎皎冰壺不受塵。", "一笑每逢青眼舊，多情空愧白頭新。", "西風未用高紈扇，東道應容岸角巾。", "珍重長謠倚雲瑟，瀟湘誰是賞音人。"]'),
('58020820-cd2d-43bb-a685-e36601ddff88','和人三首  其二','李之儀','宋','宋诗','song-poetry','','[]','經年牢落別離羣，準擬歸來拂路塵。',64,'全唐诗/poet.song.55000.json','["經年牢落別離羣，準擬歸來拂路塵。", "妙語獨從書上得，歡悰猶欠坐中新。", "頗聞洛下傳佳句，更喜嵩陽識墊巾。", "幾欲軍門示巾幗，老來猶更不如人。"]'),
('d60a7019-32e5-4d50-8930-fd56add9e409','和人三首  其三','李之儀','宋','宋诗','song-poetry','','[]','荆溪風物記當時，吹絮河豚下箸遲。',64,'全唐诗/poet.song.55000.json','["荆溪風物記當時，吹絮河豚下箸遲。", "綠滿金田朝應供，紅殘朱檻夜論詩。", "幅巾已託遺民後，杓柄猶懷象骨疑。", "早晚雲間見金臂，空懸翠竹漫抽枝。"]'),
('f6fa6cc5-db8f-4d10-bacc-6d74a9ef8f0e','次韵採蓮','李之儀','宋','宋诗','song-poetry','','[]','聞道栽成十畝蓮，便思挑出杖頭錢。',64,'全唐诗/poet.song.55000.json','["聞道栽成十畝蓮，便思挑出杖頭錢。", "定知荇菜參差處，不是决明顔色鮮。", "紅日半移芳草岸，清歌低泛木蘭船。", "驚心未得同真賞，空媿諸豪白玉篇。"]'),
('724467c4-d08f-4174-a0e9-96282b3b6627','復次韵  其一','李之儀','宋','宋诗','song-poetry','','[]','國西華麗占池蓮，曾記開樽奉賜錢。',64,'全唐诗/poet.song.55000.json','["國西華麗占池蓮，曾記開樽奉賜錢。", "幾欲漂流勞滯念，又驚紅綠映澄鮮。", "主人無間容聯步，勝日何妨更買船。", "滿挹香風振歸袂，更煩佳思出新篇。"]'),
('cbc190b3-af24-4ed0-9365-bd38fac72164','復次韵  其二','李之儀','宋','宋诗','song-poetry','','[]','幕府風流舊泛蓮，裔孫家世掩青錢。',64,'全唐诗/poet.song.55000.json','["幕府風流舊泛蓮，裔孫家世掩青錢。", "別開眼界霞爭爛，分得秋光菊未鮮。", "燈陣有心欺醉帽，珠盤何日瀉歸船。", "錦囊示我鏘金句，空媿巴吟綴後篇。"]'),
('dee35880-d701-4e5d-959c-d59bb76b15ef','次韵子椿莊居述懷','李之儀','宋','宋诗','song-poetry','','[]','偶因秋蘂記初春，增損元無爾自貧。',64,'全唐诗/poet.song.55000.json','["偶因秋蘂記初春，增損元無爾自貧。", "病骨蕭條驚歲晚，新詩來往媿情親。", "未應謝傅終垂涕，誰爲劉公是可人。", "艾火呻吟對摇落，不堪庭草又還新。"]'),
('319b5103-bff6-43fa-99ad-66c470c61ac0','次韵早秋','李之儀','宋','宋诗','song-poetry','','[]','衝衝時序一郵亭，睡美從今氣不蒸。',64,'全唐诗/poet.song.55000.json','["衝衝時序一郵亭，睡美從今氣不蒸。", "便好心期金葉酒，乍驚夢在玉壺冰。", "栽松種竹來三徑，效策輸龜待十朋。", "百尺樓高誰與共，倦途初喜接陳登。"]'),
('83fbb413-fbbc-4152-89d3-64eac5016e5d','同子椿遊三品石詩井尋三閣故基久之因以次韵','李之儀','宋','宋诗','song-poetry','','[]','桑柘丘墟輦路長，景陽依舊在山陽。',64,'全唐诗/poet.song.55000.json','["桑柘丘墟輦路長，景陽依舊在山陽。", "石標官品名常在，井記胭脂迹半荒。", "吊古漫勞興感慨，寄懷聊以共彷徉。", "相看等是未推枕，何日同驚夢後粱。"]'),
('9497c256-838d-41a9-940a-520f86988ba8','陪曾延之泛舟歷湖至苦竹寺次韵陳致君席上所賦','李之儀','宋','宋诗','song-poetry','','[]','已凉時節未霜前，十里平湖共酒船。',64,'全唐诗/poet.song.55000.json','["已凉時節未霜前，十里平湖共酒船。", "巖岫湧寒清澈水，芰荷翻浪綠連天。", "百年過眼真聊爾，一笑投懷豈適然。", "獨有黄花似迴避，定緣紅粉不能先。"]'),
('a92a0265-fb0b-4543-84d5-81e0816ba299','宿大乘贈祖燈','李之儀','宋','宋诗','song-poetry','','[]','倦游知止未知還，平日生涯只在山。',64,'全唐诗/poet.song.55000.json','["倦游知止未知還，平日生涯只在山。", "金碧喜逢雲外境，文章重見管中斑。", "篆烟縈曉留無寐，寶鐸吟風笑不閒。", "他日歸棲雖有地，勝遊終寄夢魂間。"]'),
('2f142d83-79ec-4bf8-ba91-b37000adaa9a','賞心亭','李之儀','宋','宋诗','song-poetry','','[]','賞心亭角倚欄桿，虎住龍蹲自屈蟠。',64,'全唐诗/poet.song.55000.json','["賞心亭角倚欄桿，虎住龍蹲自屈蟠。", "無復埋金銷勝氣，空餘飛鷺識前灘。", "百年名在人何處，萬里潮平雨送寒。", "幾向後庭更白紵，不堪殘照下魚竿。"]'),
('53bf231d-d958-4c6c-b087-40c6533e4ade','延之云累日把酒止在相近處殊不快人意坐間命徧索城內外可以延處之地將往因之得城南張氏園秋花斑駮可喜遂劇飲待月上戴花作樂而歸市猶未徹觀者如堵次致君韵','李之儀','宋','宋诗','song-poetry','','[]','累日相看似處陰，今朝乘興共追尋。',64,'全唐诗/poet.song.55000.json','["累日相看似處陰，今朝乘興共追尋。", "曲欄方沼爭留步，秀色新啼總會心。", "酒面屢從羅綺發，花心休被雪霜侵。", "燭城醉路凌初月，但覺人山一徑深。"]'),
('82ac6f84-0a3e-474f-94ca-550b9b126678','偶書二首  其一','李之儀','宋','宋诗','song-poetry','','[]','閉門只欲渾無事，門外何嘗有事來。',64,'全唐诗/poet.song.55000.json','["閉門只欲渾無事，門外何嘗有事來。", "生計不須憂水旱，仕途休更問梯媒。", "身安種種皆三樂，客到時時共一杯。", "此外華巖是歸處，眼前樓閣竟誰開。"]'),
('c1786e5d-34a3-4062-b8bd-441e3e5b2b37','偶書二首  其二','李之儀','宋','宋诗','song-poetry','','[]','小山相對數椽地，樂與心期境自多。',64,'全唐诗/poet.song.55000.json','["小山相對數椽地，樂與心期境自多。", "有酒未妨同客醉，無情到了任君魔。", "採薇行歌亦勞矣，飲水曲肱還會麽。", "只恐時來把不住，更看究竟事如何。"]'),
('5a3d40f0-ea72-422b-a802-231dcc41be76','贈人','李之儀','宋','宋诗','song-poetry','','[]','落得清閒與物疏，扃門終日似山居。',64,'全唐诗/poet.song.55000.json','["落得清閒與物疏，扃門終日似山居。", "案頭新有歸田賦，架上元留緯世書。", "紫府未須窮秘簡，丹山重見引名雛。", "詔恩咫尺來相繼，還許頻爲賀客無。"]'),
('722db094-0a3b-461d-b4c5-bd9ab383849f','和兩翁軒','李之儀','宋','宋诗','song-poetry','','[]','何處又傳金椀出，幾人爭看玉山頹。',64,'全唐诗/poet.song.55000.json','["何處又傳金椀出，幾人爭看玉山頹。", "幽情不是風期舊，異境難從指顧開。", "猿鶴已回塵外駕，烟雲休造眼中衰。", "未妨一老同巾履，香火終年謝劫灰。"]'),
('ac653b0e-57e0-44e1-883e-3e6cde09573a','次韵珪首座','李之儀','宋','宋诗','song-poetry','','[]','陰重爐紅欲雪天，氤氳香篆不藏烟。',64,'全唐诗/poet.song.55000.json','["陰重爐紅欲雪天，氤氳香篆不藏烟。", "南遊步步如同歷，西竺層層有舊緣。", "未覺鴉聲驚戶外，似傳梅信到窗前。", "老來酒量無消息，負此佳時一慨然。"]'),
('3e9ba3b5-eaff-4573-a4ec-595e601eb5a2','和錦繡亭','李之儀','宋','宋诗','song-poetry','','[]','漂泊生涯寄一萍，勝遊長記錦花亭。',64,'全唐诗/poet.song.55000.json','["漂泊生涯寄一萍，勝遊長記錦花亭。", "山來已訝天能巧，春到方知地更靈。", "雖許登臨追曳尾，却應顔色未忘形。", "何妨共保千年約，白帽回頭笑管寧。"]'),
('fd8b5e70-52cf-43ef-8642-a91ed74a0aff','吳思道相送同宿崇因二首  其一','李之儀','宋','宋诗','song-poetry','','[]','端門風月十年拋，垂老山林寄一瓢。',64,'全唐诗/poet.song.55000.json','["端門風月十年拋，垂老山林寄一瓢。", "可得故人來市脚，共尋陳迹到江郊。", "麥黄且置塵中累，眉白欣投世外交。", "只恐話長清夜短，明朝去路不相饒。"]'),
('067e55aa-03a2-4849-aea9-55b6301ef3e1','吳思道相送同宿崇因二首  其二','李之儀','宋','宋诗','song-poetry','','[]','形單影隻久相拋，鼎食端能勝飲瓢。',64,'全唐诗/poet.song.55000.json','["形單影隻久相拋，鼎食端能勝飲瓢。", "已分餘材辜北闕，元非不雨自西郊。", "求田聊復同中隠，玩世寧嫌凟下交。", "千古平泉有遺恨，漫勞精爽畏文饒。"]'),
('d4dc6092-0a1b-44c0-8279-9752572031a8','寄僧','李之儀','宋','宋诗','song-poetry','','[]','得皮得髓漫多門，實際圓融理自存。',64,'全唐诗/poet.song.55000.json','["得皮得髓漫多門，實際圓融理自存。", "諭意當時纔一笑，還卿千日見三孫。", "維持佛法元無事，建立家山盡有文。", "占斷乾坤今鼎足，會多哮吼慰傳聞。"]'),
('519bb9fc-93c5-4c4e-a7a5-aeb739ce2a5c','寄題吳思道橫翠堂','李之儀','宋','宋诗','song-poetry','','[]','紅塵擾擾功名地，不礙詩人得趣幽。',64,'全唐诗/poet.song.55000.json','["紅塵擾擾功名地，不礙詩人得趣幽。", "何必千巖連萬壑，能令六月似三秋。", "茶甌變乳隨湯泛，香篆縈雲盡日浮。", "時覺東城添紙價，應知得句勝封侯。"]'),
('ec97202f-ddaa-4500-ba72-ffa29638b51c','簡劉君秉','李之儀','宋','宋诗','song-poetry','','[]','劉郎本是風塵外，畫舸新從越上來。',64,'全唐诗/poet.song.55000.json','["劉郎本是風塵外，畫舸新從越上來。", "聞說露芽如爪活，更多溪楮截肪開。", "雪消鼎面聲頻涌，鵝轉池心首屢回。", "洗滌睡魔臨二景，敢辭瓦礫換瓊瑰。"]'),
('cff21c1e-2e43-40e6-9ac8-9fc84628c45d','八月十一日九月六日二十四日三夢過趙仲强家坐中人物笑語一一如平時因寄長句庶蒙藻思見酬因投一會面之慰也','李之儀','宋','宋诗','song-poetry','','[]','憶陪金醆醉紅顔，回首風光杳靄間。',64,'全唐诗/poet.song.55000.json','["憶陪金醆醉紅顔，回首風光杳靄間。", "老去未忘三級浪，近來頻夢八重關。", "雲烟舊路到何日，燈火虛堂真似山。", "只恐斷魂收不得，更須佳句與招還。"]'),
('b1e9562c-573a-4bdb-b284-532a8157726c','水中登王德循月閣','李之儀','宋','宋诗','song-poetry','','[]','龍宮海藏固聞誇，偶襲初凉泛客槎。',64,'全唐诗/poet.song.55000.json','["龍宮海藏固聞誇，偶襲初凉泛客槎。", "層檻迥高臨落日，洞房無數盡浮家。", "閭閻可想知何在，天水相連杳莫涯。", "借我華嚴記殘帙，欲將因地付袈裟。"]'),
('37ef778f-f292-473b-81d8-8f1e38cc635c','德循詩律甚佳方幸拭目因作拙句以勉之','李之儀','宋','宋诗','song-poetry','','[]','唐人好詩乃風俗，語出工夫各一家。',64,'全唐诗/poet.song.55000.json','["唐人好詩乃風俗，語出工夫各一家。", "前輩相因多自任，後來無復更相誇。", "半山老子偏遊戲，真一仙人每歎嗟。", "傍出豫章登一格，憑君細與辨龍蛇。"]'),
('64d2707e-a177-41fd-807f-e3747ba97d94','之儀家當塗七年矣屢過禪岳山下望高山塔欲一遊輒不果異時山主懃公大師與其子宣上人相過因往報之取路回遠薄晚方到遂留宿棟宇一新舍次皆得其便而宏麗高朗唯見者知焉又復規範齊肅鐘鼓應接問之乃懃一力所就絲蓄粒聚未嘗毫髮資之人此尤難者感歎不已因賦二小詩  其一','李之儀','宋','宋诗','song-poetry','','[]','窣堵頻經眼，伽藍未息肩。',48,'全唐诗/poet.song.55000.json','["窣堵頻經眼，伽藍未息肩。", "多情兩父子，同住一雲烟。", "繚繞尋幽徑，從容慰昔年。", "本無留客意，投分且遷延。"]'),
('ec32d5d5-77d0-4add-9a30-f1e4d2a34501','之儀家當塗七年矣屢過禪岳山下望高山塔欲一遊輒不果異時山主懃公大師與其子宣上人相過因往報之取路回遠薄晚方到遂留宿棟宇一新舍次皆得其便而宏麗高朗唯見者知焉又復規範齊肅鐘鼓應接問之乃懃一力所就絲蓄粒聚未嘗毫髮資之人此尤難者感歎不已因賦二小詩  其二','李之儀','宋','宋诗','song-poetry','','[]','去往如流水，興衰似轉肩。',48,'全唐诗/poet.song.55000.json','["去往如流水，興衰似轉肩。", "新工幾奪目，舊爨僅留烟。", "願起三千劫，功收十八年。", "兒孫盡龍象，家世自綿延。"]'),
('cc3d7b0d-e6fa-43a3-bc33-31fa3c9c556e','藏雲山居  其一','李之儀','宋','宋诗','song-poetry','','[]','鳥語晚更好，山風秋轉凉。',48,'全唐诗/poet.song.55000.json','["鳥語晚更好，山風秋轉凉。", "心閒日自永，簟冷夢尤長。", "赤薦新舂稻，清添舊蔭香。", "此身歸有地，去路尚何妨。"]'),
('127b542c-9a56-4980-820c-5abfc23a85e3','藏雲山居  其二','李之儀','宋','宋诗','song-poetry','','[]','雨後山尤好，秋來方此時。',48,'全唐诗/poet.song.55000.json','["雨後山尤好，秋來方此時。", "心清覺老健，步懶欲歸遲。", "林響驚鼷鼠，風閒叫畫眉。", "善人吾豈敢，去此尚何之。"]'),
('c364a824-ff2b-465b-b217-7c89c8e5730e','山居夏日','李之儀','宋','宋诗','song-poetry','','[]','金鏁籠窗日，黄繒蔽柳蟬。',48,'全唐诗/poet.song.55000.json','["金鏁籠窗日，黄繒蔽柳蟬。", "戀鶑忘日轉，借榻就凉偏。", "好作宿山計，難堪被俗牽。", "歸途迎晚照，豫促渡頭船。"]'),
('bd9672cb-e3bf-4c2e-b094-93cd7389718c','誠上人遊方既歸林下焚香誦經以嚴報地相見欣然留不欲去遂賦小詩','李之儀','宋','宋诗','song-poetry','','[]','委曲披高下，虛明得靜深。',48,'全唐诗/poet.song.55000.json','["委曲披高下，虛明得靜深。", "佛香平日願，經卷本來心。", "地據三車上，塵無一點侵。", "出山應有恨，何處似如今。"]'),
('91bb2385-46cf-40e2-8ccd-cd6a5c9b007f','宿青山坊君錫館置甚款時方興圩','李之儀','宋','宋诗','song-poetry','','[]','命駕追彭澤，開懷得士龍。',48,'全唐诗/poet.song.55000.json','["命駕追彭澤，開懷得士龍。", "殘寒偏惱客，小雨未妨農。", "已幸同歸轍，何勞更賃舂。", "川原如故里，疑是舊栽松。"]'),
('a3df6917-81e2-4f11-afb9-aacccb32f838','將過黄池中路寒甚風猛不可行復歸青山坊投宿','李之儀','宋','宋诗','song-poetry','','[]','過午風雖惡，此心難自安。',48,'全唐诗/poet.song.55000.json','["過午風雖惡，此心難自安。", "如何一時頃，遂變十分寒。", "忍聽僵夫訴，還思昨夜歡。", "祇應賢地主，猶作故侯看。"]'),
('749cba30-8a1c-434b-a909-02378a099265','次韵俞希賢大暑家居寄天寧二老','李之儀','宋','宋诗','song-poetry','','[]','靜退陶彭澤，風流支道林。',48,'全唐诗/poet.song.55000.json','["靜退陶彭澤，風流支道林。", "論歡雖暫阻，投分本來深。", "客舍汗如洗，僧軒雲正陰。", "莫因俗眼礙，終負勝遊心。"]'),
('130d2ea5-a5fd-48d1-a40c-be3130a74b4b','和答友人二首  其一','李之儀','宋','宋诗','song-poetry','','[]','比日逢春社，占龍得賁山。',48,'全唐诗/poet.song.55000.json','["比日逢春社，占龍得賁山。", "雖能素願合，未放老身閒。", "家世綿延遠，功名指顧間。", "自應天有助，一到一開顔。"]'),
('7569e1b7-cdc7-4ba6-bd3b-6c8efb1fe030','和答友人二首  其二','李之儀','宋','宋诗','song-poetry','','[]','春來自多雨，行處只逢山。',48,'全唐诗/poet.song.55000.json','["春來自多雨，行處只逢山。", "賦分皆可樂，貪生常不閒。", "人歸挑菜處，鳥語落梅間。", "翻恨新增酒，何從解醉顔。"]'),
('bf9c4626-fb55-4201-8bf1-ca2c4e28393d','食笋二首  其一','李之儀','宋','宋诗','song-poetry','','[]','燕雀初爲友，烽烟近卜鄰。',48,'全唐诗/poet.song.55000.json','["燕雀初爲友，烽烟近卜鄰。", "不嫌千語聒，只怕一籠新。", "病眼常如睡，歸心喜似人。", "柈餐猶見笋，未省已無春。"]'),
('93324d3d-d25a-442c-b8d9-f95eddf4a08d','食笋二首  其二','李之儀','宋','宋诗','song-poetry','','[]','疏簾不礙日，缺甃宛如塘。',48,'全唐诗/poet.song.55000.json','["疏簾不礙日，缺甃宛如塘。", "默坐千名佛，忘形一炷香。", "卷中貪味永，鏡裏任顔蒼。", "飲後纔推枕，逡巡又夕陽。"]'),
('1f264733-35df-498a-9d30-d6928063c172','謝陳無己相訪','李之儀','宋','宋诗','song-poetry','','[]','下直來天祿，柴荆故遠求。',48,'全唐诗/poet.song.55000.json','["下直來天祿，柴荆故遠求。", "論心日恨短，歸路雨無憂。", "紅葉繽紛晚，黄花爛縵秋。", "會須尋此況，擊節再相酬。"]'),
('bb88fcb7-be8d-444e-8a7f-b46d577eac14','昨日偶到北觀蒙君俞元載元發明叔惠然見過','李之儀','宋','宋诗','song-poetry','','[]','勝日欣相得，曠懷誰與同。',48,'全唐诗/poet.song.55000.json','["勝日欣相得，曠懷誰與同。", "如何四君子，肯顧一衰翁。", "林杪收殘雨，簷牙遞好風。", "歸時不須問，更待月如弓。"]'),
('ecf227f3-bd2e-4f35-8db9-52bf5ec9a5f3','回酒','李之儀','宋','宋诗','song-poetry','','[]','莫笑和州酒，和州酒却醇。',48,'全唐诗/poet.song.55000.json','["莫笑和州酒，和州酒却醇。", "聊資千歲祝，用贊一陽春。", "柳信渦將報，梨晴點向真。", "醉尋平日路，好在武陵人。"]'),
('12e92019-5e54-4759-ae72-fdf5474f850f','書長干僧房','李之儀','宋','宋诗','song-poetry','','[]','異日延禪地，今朝選佛場。',48,'全唐诗/poet.song.55000.json','["異日延禪地，今朝選佛場。", "真身瘞堅固，層級韵琅當。", "雨灑家家潤，燈傳處處光。", "曾將一則語，要路截諸方。"]'),
('8fc3a69b-89ff-4484-9319-3a4fae5acfac','無題三首  其一','李之儀','宋','宋诗','song-poetry','','[]','邂逅俱青眼，招携媿白頭。',48,'全唐诗/poet.song.55000.json','["邂逅俱青眼，招携媿白頭。", "穿林猶畏日，坐石忽驚秋。", "不作崎嶇倦，幾成汗漫遊。", "臨分懷杜老，月湧大江流。"]'),
('edec70df-1b4a-4203-8d36-54fb134182a1','無題三首  其二','李之儀','宋','宋诗','song-poetry','','[]','步武高低外，生涯夢寐中。',48,'全唐诗/poet.song.55000.json','["步武高低外，生涯夢寐中。", "不知三徑足，信是一生窮。", "觸目如逢舊，隨緣似有功。", "便應參羽翼，何異注魚蟲。"]'),
('fb761069-de76-4035-8b64-284c1a498f94','無題三首  其三','李之儀','宋','宋诗','song-poetry','','[]','軒廡千尋碧，江山一抹紅。',48,'全唐诗/poet.song.55000.json','["軒廡千尋碧，江山一抹紅。", "微吟接僚友，健啖趁羣童。", "戀別猶能暫，論懽昔已通。", "更憑將此況，遠問霅溪翁。"]'),
('3c14b6bc-967e-464b-8058-8030617f254f','題歷陽天慶觀自然菴','李之儀','宋','宋诗','song-poetry','','[]','一日復一日，新年即舊年。',48,'全唐诗/poet.song.55000.json','["一日復一日，新年即舊年。", "本來無欠少，强自起攀緣。", "妙悟通三境，清風寄七絃。", "昇騰如未果，且作地行仙。"]'),
('ad8f4ae0-06d2-4e43-bd93-b1e634065700','自大乘將遊湯泉道中','李之儀','宋','宋诗','song-poetry','','[]','迢迢山路永，漠漠曉風昏。',48,'全唐诗/poet.song.55000.json','["迢迢山路永，漠漠曉風昏。", "雨歇鳩呼婦，年豐稻有孫。", "旅懷悲暮齒，野飯寄前村。", "只恐今宵夢，憑誰續斷魂。"]'),
('bd880ae3-5873-49a1-91f3-cb12ea2a4d85','雨中過明覺招上人輒留小詩','李之儀','宋','宋诗','song-poetry','','[]','雨路如投洗，山行似踏繩。',48,'全唐诗/poet.song.55000.json','["雨路如投洗，山行似踏繩。", "深閒逢竹院，歡喜得詩僧。", "語款疑繅繭，心明自有燈。", "難忘惜別處，高義等丘陵。"]'),
('b9fcf0a8-bee2-4755-95f3-80d21a5412c0','宿滴水巖懷趙德麟和壁間韵','李之儀','宋','宋诗','song-poetry','','[]','瀑水瀉靈竇，鏗鏘韶濩音。',48,'全唐诗/poet.song.55000.json','["瀑水瀉靈竇，鏗鏘韶濩音。", "樹深猿嘯月，山迥鳥歸林。", "一曲廣陵散，再歌梁甫吟。", "天邊有鴻雁，莫寄此時心。"]'),
('f5967cce-9749-46b9-a0bf-d5b4f131234e','夜行鞏洛道上','李之儀','宋','宋诗','song-poetry','','[]','夜久露華重，寒鴉不肯棲。',48,'全唐诗/poet.song.55000.json','["夜久露華重，寒鴉不肯棲。", "月推銀海上，斗過玉繩西。", "風脫林衣瘦，山擎雲帽低。", "流螢三四點，趁隊過前溪。"]'),
('2eaf714b-cb2d-4b99-9527-87b5b322132b','題李欽之承事宅','李之儀','宋','宋诗','song-poetry','','[]','松竹龐公宅，丘墳倚相家。',48,'全唐诗/poet.song.55000.json','["松竹龐公宅，丘墳倚相家。", "和聲敦雁序，秀色茂蘭芽。", "魯秉方如昔，淮流詎可涯。", "躊躇不欲去，寒日任西斜。"]'),
('1caa501e-9d1f-4edc-a9fc-62b5ea90e3b2','離宣城','李之儀','宋','宋诗','song-poetry','','[]','倦客登舟際，江城欲暮時。',48,'全唐诗/poet.song.55000.json','["倦客登舟際，江城欲暮時。", "恨長山自遠，心速棹歸遲。", "村市明魚火，嚴城起鼓鼙。", "詩成真有助，新月上天涯。"]'),
('d434107c-7896-4274-b645-e072c997f7d0','秋日遊青山訪太白墓二首  其一','李之儀','宋','宋诗','song-poetry','','[]','潦倒忘衰日，風流襲墊巾。',48,'全唐诗/poet.song.55000.json','["潦倒忘衰日，風流襲墊巾。", "未能分朽骨，還此挹餘塵。", "弔古無千載，傷心爲一顰。", "依稀如到眼，氣類信吾人。"]'),
('04ca6bfa-f8cc-4ca9-a8f6-44154a335d99','秋日遊青山訪太白墓二首  其二','李之儀','宋','宋诗','song-poetry','','[]','淹時苦炎暑，此日遇初秋。',48,'全唐诗/poet.song.55000.json','["淹時苦炎暑，此日遇初秋。", "舊籍存千畝，彝倫詠九疇。", "但能尋曠蕩，何必事深幽。", "未媿遼東笑，真成知北遊。"]'),
('61d152a1-0d7d-41ce-8052-341c5aae752b','遊青山因過西莊','李之儀','宋','宋诗','song-poetry','','[]','青山忽相值，一笑脫征衫。',72,'全唐诗/poet.song.55000.json','["青山忽相值，一笑脫征衫。", "未就三都賦，聊尋五柳潛。", "並遊雖得意，作闊更愁兼。", "問字終忘倦，言歸但小慚。", "旁求須作相，未聘且耕巖。", "贈別無多語，禔身要律貪。"]'),
('06c80b6d-c207-4955-b88b-8cd0155e5c69','同榮天和遊石城','李之儀','宋','宋诗','song-poetry','','[]','茲遊久寂寞，勝士偶陪隨。',48,'全唐诗/poet.song.55000.json','["茲遊久寂寞，勝士偶陪隨。", "竹暗笋初熟，江深鱸正肥。", "但須頻結社，何必訪題詩。", "會有重來日，還應記此時。"]'),
('fd93b6a3-624d-4046-ad0f-fe3bb699e0c5','謝人送魚','李之儀','宋','宋诗','song-poetry','','[]','珍重黄池秀，風流迥出塵。',48,'全唐诗/poet.song.55000.json','["珍重黄池秀，風流迥出塵。", "多情念羈旅，脫網寄鮮鱗。", "掀動龍蛟宅，驚回匕箸春。", "丹青如得便，更擬問通津。"]'),
('77602efc-95d4-4f71-ab9e-fafd49bcf628','題齊雲亭','李之儀','宋','宋诗','song-poetry','','[]','凌空登白紵，此地與雲齊。',48,'全唐诗/poet.song.55000.json','["凌空登白紵，此地與雲齊。", "一覽衆山小，方知人世低。", "暫留蝴蝶夢，終負杜鵑啼。", "回向禪關客，何當別有梯。"]'),
('6ee20835-36c3-4032-a022-6d3843eb5284','賀時相生辰','李之儀','宋','宋诗','song-poetry','','[]','錫羨來經世，儲休表降神。',120,'全唐诗/poet.song.55000.json','["錫羨來經世，儲休表降神。", "雲間瞻鸑鷟，天上識麒麟。", "藴藉三冬學，形容萬古春。", "班庭傾玉筍，鎮廟契金人。", "帝載熙明格，朝簽絕擬倫。", "淵源參密幄，同德在斯民。", "有作皆前用，無言不緒陳。", "光華榮斝壽，蕃錫會昌辰。", "寵接張侯異，年頒衛武均。", "江干空引睇，無路襲餘塵。"]'),
('ad6e5de9-091f-4c33-9980-36e50e91a603','登山未還范景仁以詩見促次韵二首  其一','李之儀','宋','宋诗','song-poetry','','[]','撲面烟霞曉更嘉，偶隨藜杖訪仙家。',32,'全唐诗/poet.song.55000.json','["撲面烟霞曉更嘉，偶隨藜杖訪仙家。", "斜陽不見登山屐，獨遶長溪折夜花。"]'),
('419865c1-609f-489b-a91f-1b689ed90cb1','登山未還范景仁以詩見促次韵二首  其二','李之儀','宋','宋诗','song-poetry','','[]','危牆烟際聳層城，潮落沙頭眼更明。',32,'全唐诗/poet.song.55000.json','["危牆烟際聳層城，潮落沙頭眼更明。", "不覺歸舟犯牛斗，天風吹下步虛聲。"]'),
('1c457bcc-114b-403d-82a4-52f9a116ccd4','次韵景仁海次西還二首  其一','李之儀','宋','宋诗','song-poetry','','[]','留滯初春寂寞濱，眼明歸路一番新。',32,'全唐诗/poet.song.55000.json','["留滯初春寂寞濱，眼明歸路一番新。", "何妨更作重來計，枝上微紅解惱人。"]'),
('80eccd57-5082-4abc-ab35-358a788f217b','次韵景仁海次西還二首  其二','李之儀','宋','宋诗','song-poetry','','[]','二月春陰到水濱，秋風重見玉蟾新。',32,'全唐诗/poet.song.55000.json','["二月春陰到水濱，秋風重見玉蟾新。", "無端擾擾來還去，只恐沙鷗解笑人。"]'),
('ebc430a3-5821-44ee-89d0-e6275514ba7e','又次韵','李之儀','宋','宋诗','song-poetry','','[]','尋春何惜駐征鞍，只怕春歸不怕寒。',32,'全唐诗/poet.song.55000.json','["尋春何惜駐征鞍，只怕春歸不怕寒。", "故國山川無限思，我來仍得雨中看。"]'),
('76426f40-8348-478a-9d84-817e286686cc','柏臺自述四首  其一','李之儀','宋','宋诗','song-poetry','','[]','窮日愔愔已死灰，似沈眢井念昭回。',32,'全唐诗/poet.song.55000.json','["窮日愔愔已死灰，似沈眢井念昭回。", "一聲霹靂起平地，頓覺青天萬里開。"]'),
('3ed2dc2c-8215-4a95-94fb-893713c6b45e','柏臺自述四首  其二','李之儀','宋','宋诗','song-poetry','','[]','鑽龜打瓦不曾休，金注昏人豈自由。',32,'全唐诗/poet.song.55000.json','["鑽龜打瓦不曾休，金注昏人豈自由。", "誰謂純誠無感格，會逢公議報私讎。"]'),
('3e2fd76f-0931-4410-b06f-639f2ca5cb99','柏臺自述四首  其三','李之儀','宋','宋诗','song-poetry','','[]','一夢揚州似隔生，輕舟未往但貪程。',32,'全唐诗/poet.song.55000.json','["一夢揚州似隔生，輕舟未往但貪程。", "莫年觳觫兒童念，風物依稀媿此情。"]'),
('9922ca40-2c6a-40ad-ad03-3cce5d93ff53','柏臺自述四首  其四','李之儀','宋','宋诗','song-poetry','','[]','熬熬內火戰驕陽，鶴唳風聲便着忙。',32,'全唐诗/poet.song.55000.json','["熬熬內火戰驕陽，鶴唳風聲便着忙。", "波浪翻天誰與渡，却應甘井是慈航。"]'),
('3eaf1007-fb5c-4379-b4a8-b476543fc2b6','江西莊上久雨','李之儀','宋','宋诗','song-poetry','','[]','去秋欲雨不得雨，今春望晴還未晴。',32,'全唐诗/poet.song.55000.json','["去秋欲雨不得雨，今春望晴還未晴。", "螻蟻尚知爲自便，强將私意與天爭。"]'),
('21dba2b5-f225-4b68-80c0-7dbdde5cd00d','路西莊絕句','李之儀','宋','宋诗','song-poetry','','[]','麥未登場已插秧，更憂雨過水還傷。',32,'全唐诗/poet.song.55000.json','["麥未登場已插秧，更憂雨過水還傷。", "一生能着幾量屐，白髮蕭蕭祇管忙。"]'),
('78932362-db9b-42c8-b82f-fc63c546e987','宿采石','李之儀','宋','宋诗','song-poetry','','[]','江聲隠隠風前恨，雁陣喧喧枕畔愁。',32,'全唐诗/poet.song.55000.json','["江聲隠隠風前恨，雁陣喧喧枕畔愁。", "更覺孤衾如潑水，始知今夜宿山頭。"]'),
('105f2037-502e-4130-af57-1704b5d6090e','寄西莊梅道者','李之儀','宋','宋诗','song-poetry','','[]','因緣時節本相期，只恐蹉跎醉似泥。',32,'全唐诗/poet.song.55000.json','["因緣時節本相期，只恐蹉跎醉似泥。", "洗盡從前留意處，何憂金臂不提携。"]'),
('137cf3c6-84b6-413a-a615-d616e04768fe','偶書二首  其一','李之儀','宋','宋诗','song-poetry','','[]','元宵燈火鬧遊人，偶向忙中得此身。',32,'全唐诗/poet.song.55000.json','["元宵燈火鬧遊人，偶向忙中得此身。", "浄几明窗塵不到，弄黄先見一枝春。"]'),
('13607599-e12b-4b1e-bb57-5ff963450f79','偶書二首  其二','李之儀','宋','宋诗','song-poetry','','[]','通中玉冷夢偏長，花影籠階月浸廊。',32,'全唐诗/poet.song.55000.json','["通中玉冷夢偏長，花影籠階月浸廊。", "挽斷羅巾留不住，覺來猶有去時香。"]'),
('1dfeda81-b180-4f6e-9d5d-e68113413f00','瑞竹即事三絕  其一','李之儀','宋','宋诗','song-poetry','','[]','芭蕉葉密柿陰濃，散髮西窗到晚鐘。',32,'全唐诗/poet.song.55000.json','["芭蕉葉密柿陰濃，散髮西窗到晚鐘。", "霹靂一聲三尺水，旱天方信有真龍。"]'),
('a0c73209-2de5-44ae-be54-b1bcaa177236','瑞竹即事三絕  其二','李之儀','宋','宋诗','song-poetry','','[]','纖絺不掛汗如傾，一霎風來夢乍驚。',32,'全唐诗/poet.song.55000.json','["纖絺不掛汗如傾，一霎風來夢乍驚。", "自是人心有凉思，强將庭葉作秋聲。"]'),
('a9753e6d-47f3-4bbc-9dbd-fe6989e97e1d','瑞竹即事三絕  其三','李之儀','宋','宋诗','song-poetry','','[]','鴨脚初成綠未齊，芭蕉仍在柿陰西。',32,'全唐诗/poet.song.55000.json','["鴨脚初成綠未齊，芭蕉仍在柿陰西。", "推遷節物均如此，眼界何須苦自迷。"]'),
('b7125f43-08bb-4069-8928-9015cebc50d4','書扇','李之儀','宋','宋诗','song-poetry','','[]','會稽陳迹久荒蕪，流落江城墨未枯。',32,'全唐诗/poet.song.55000.json','["會稽陳迹久荒蕪，流落江城墨未枯。", "好向溪邊示行客，問人能出百錢無。"]'),
('dd534664-ab8c-49f6-bf74-76f748e51654','題郭熙畫扇  其一','李之儀','宋','宋诗','song-poetry','','[]','蹇馿破帽聳鳶肩，石裏長松欲到天。',32,'全唐诗/poet.song.55000.json','["蹇馿破帽聳鳶肩，石裏長松欲到天。", "六月塵埃汗如洗，始知立意不徒然。"]'),
