('e25a7c2e-ba88-4897-8b40-7b0a23d6e30c','偶題六絕  其四','李之儀','宋','宋诗','song-poetry','','[]','數卷新遊蜀苑詩，長安僻巷得相隨。',32,'全唐诗/poet.song.55000.json','["數卷新遊蜀苑詩，長安僻巷得相隨。", "草堂雪夜携琴處，況似青城館裏時。"]'),
('d2409a29-4f6e-4888-92fe-0994822fc4e2','偶題六絕  其五','李之儀','宋','宋诗','song-poetry','','[]','不覺六月初八日，還是去年瓜熟時。',32,'全唐诗/poet.song.55000.json','["不覺六月初八日，還是去年瓜熟時。", "鞭藉竟誰能致曲，定自昭昭終可期。"]'),
('e75aa369-1077-4d80-9aac-dbb403bdb587','訪瑫上人值喫葱茶','李之儀','宋','宋诗','song-poetry','','[]','軟火明窗紙帳低，一聲初報午來雞。',32,'全唐诗/poet.song.55000.json','["軟火明窗紙帳低，一聲初報午來雞。", "葱茶未必能留坐，爲愛高人手自提。"]'),
('0fe36718-1138-45ca-a956-2543481e6f23','七夕','李之儀','宋','宋诗','song-poetry','','[]','銀漢風休月對絃，靈橋長掛罷星填。',32,'全唐诗/poet.song.55000.json','["銀漢風休月對絃，靈橋長掛罷星填。", "從今祇恐情先老，無復佳期又隔年。"]'),
('c92bdcc1-3957-48b0-a610-3ba1771664df','東山','李之儀','宋','宋诗','song-poetry','','[]','南山不見見東山，白鷺時時自往還。',32,'全唐诗/poet.song.55000.json','["南山不見見東山，白鷺時時自往還。", "爲問天公幾時雨，定因薄相故能慳。"]'),
('bedc47e9-012d-479c-9cf2-11653e47306d','閒坐','李之儀','宋','宋诗','song-poetry','','[]','鴉銜遺秉趁饑鷹，老牸時傳喚犢聲。',32,'全唐诗/poet.song.55000.json','["鴉銜遺秉趁饑鷹，老牸時傳喚犢聲。", "凡物有生皆有樂，不堪孤坐淚縱橫。"]'),
('b90c2900-fccc-4d98-87a2-d2be5f138477','壬辰春試終場王德循置酒登月閣邀丁希韓甚歡夜分方罷','李之儀','宋','宋诗','song-poetry','','[]','寶炷芬敷散瑞烟，月移花影上欄桿。',32,'全唐诗/poet.song.55000.json','["寶炷芬敷散瑞烟，月移花影上欄桿。", "角聲又報梅花弄，只恐歸時夜更寒。"]'),
('c74ad430-27f1-4a20-a9ad-d6232c8f4e9e','清明日浄因莊早飯罷遂遊洪福有懷巨載元確因致別約  其一','李之儀','宋','宋诗','song-poetry','','[]','老禪期客煮園蔬，少憩西鄰日轉初。',32,'全唐诗/poet.song.55000.json','["老禪期客煮園蔬，少憩西鄰日轉初。", "萬白千紅好時節，斷魂空付兩龍駒。"]'),
('eb5d93f4-5779-459f-9ae0-d8eed7ec0c38','清明日浄因莊早飯罷遂遊洪福有懷巨載元確因致別約  其二','李之儀','宋','宋诗','song-poetry','','[]','憶尋春色過何郎，西寺傳來墨有香。',32,'全唐诗/poet.song.55000.json','["憶尋春色過何郎，西寺傳來墨有香。", "安得蒹葭真倚玉，再邀花影上迴廊。"]'),
('b1ffbc98-bc00-4d7c-a8ab-68a7263a5494','同榮天和遊石城','李之儀','宋','宋诗','song-poetry','','[]','樹密山深鎮雨凉，西州陳迹舊丹陽。',32,'全唐诗/poet.song.55000.json','["樹密山深鎮雨凉，西州陳迹舊丹陽。", "相逢莫話當時事，且約清心感妙香。"]'),
('50e9319d-3e08-405e-bd32-12a1ea22f670','謁錢公振李與幾','李之儀','宋','宋诗','song-poetry','','[]','軟火明窗一炷香，歲交時節夜來霜。',32,'全唐诗/poet.song.55000.json','["軟火明窗一炷香，歲交時節夜來霜。", "須知錢李饒風味，却媿巴歌污錦囊。"]'),
('a558b3b1-8ec3-4673-bff3-6743de13738e','再過李欽之宅憶希武','李之儀','宋','宋诗','song-poetry','','[]','客窗孤被探深寒，一夢從來已六年。',32,'全唐诗/poet.song.55000.json','["客窗孤被探深寒，一夢從來已六年。", "獨有可人無復見，尊前旋笑尚依然。"]'),
('16bbcacc-c549-43cb-b0ef-17d5ba1434fd','題李仲山金影軒','李之儀','宋','宋诗','song-poetry','','[]','金影風光小洞天，藍橋有路隔雲烟。',32,'全唐诗/poet.song.55000.json','["金影風光小洞天，藍橋有路隔雲烟。", "玉壺叩盡應能語，早晚光明照座邊。"]'),
('02ec2ebe-080e-4e70-b291-5bf8f3835013','題黄蘗泉','李之儀','宋','宋诗','song-poetry','','[]','住菴老子不復見，傳法阿師追不回。',32,'全唐诗/poet.song.55000.json','["住菴老子不復見，傳法阿師追不回。", "飲水能知大愚意，一拳真是打爺來。"]'),
('f3566383-d21a-4e32-8ec9-c33ea5ba57cb','次韵贈答洪覺範五首  其一','李之儀','宋','宋诗','song-poetry','','[]','念盡已知木偶，多聞早慰詩流。',28,'全唐诗/poet.song.55000.json','["念盡已知木偶，多聞早慰詩流。", "北海幸君知舉，東家未我爲丘。"]'),
('c57ba356-f634-46ea-a86f-2c8ca589eaf5','次韵贈答洪覺範五首  其二','李之儀','宋','宋诗','song-poetry','','[]','豈爲彌天蓋世，却來作戲逢場。',28,'全唐诗/poet.song.55000.json','["豈爲彌天蓋世，却來作戲逢場。", "可是因人爾爾，要非皆我堂堂。"]'),
('d6fbbf92-8e6e-4927-b3cb-d1562a71e85d','次韵贈答洪覺範五首  其三','李之儀','宋','宋诗','song-poetry','','[]','問舍求田底事，乘流遇坎方時。',28,'全唐诗/poet.song.55000.json','["問舍求田底事，乘流遇坎方時。", "且向忙中作繭，敢從作者論詩。"]'),
('8472ea97-1feb-4cfa-a6cb-e57f22e4f0b6','次韵贈答洪覺範五首  其四','李之儀','宋','宋诗','song-poetry','','[]','立玉無因再倚，坐荆偶此同班。',28,'全唐诗/poet.song.55000.json','["立玉無因再倚，坐荆偶此同班。", "老去誰開東閣，朝來空對西山。"]'),
('52d711a8-fcdc-4c75-8230-c24f40a16121','次韵贈答洪覺範五首  其五','李之儀','宋','宋诗','song-poetry','','[]','俛仰誰爲荆棘，崢嶸漫自波濤。',28,'全唐诗/poet.song.55000.json','["俛仰誰爲荆棘，崢嶸漫自波濤。", "休說花磚步日，旦尋烟雨飛鵃。"]'),
('bc7e7029-6101-4158-ae7a-2fd6a45b060c','題畫扇','李之儀','宋','宋诗','song-poetry','','[]','白頰饒春思，梅梢喜可知。',24,'全唐诗/poet.song.55000.json','["白頰饒春思，梅梢喜可知。", "聲聲催爛漫，定是雪晴時。"]'),
('30e63dc3-3662-470e-9e8a-bf68359ca12c','東坡挽詞','李之儀','宋','宋诗','song-poetry','','[]','從來憂患許追隨，末路文詞特見知。',64,'全唐诗/poet.song.55000.json','["從來憂患許追隨，末路文詞特見知。", "肯向虞兮悲蓋世，空慚賜也可言詩。", "炎荒不死疑陰相，漢水相招本素期。", "月墮星沈豈人力，輝光他日看豐碑。"]'),
('ecd99618-8cba-4168-adb8-7bd632812262','石敏若挽詞','李之儀','宋','宋诗','song-poetry','','[]','萬年風采屬當時，墮地能班世有兒。',64,'全唐诗/poet.song.55000.json','["萬年風采屬當時，墮地能班世有兒。", "夢筆方傳符昔應，玉樓何事遽先期。", "無由負弩瞻前導，空歎騎鯨去不疑。", "老矣無從忘肉味，餘音猶幸接吹箎。"]'),
('f5a091d2-b4fe-407c-91ab-bc1427db69a1','李希武挽詞','李之儀','宋','宋诗','song-poetry','','[]','十年枯木不知春，每向尊前得可人。',64,'全唐诗/poet.song.55000.json','["十年枯木不知春，每向尊前得可人。", "申叔共瞻雲外翼，元賓豈是轍中鱗。", "揚帆巨浸方期遠，摧輻窮途定有因。", "後學從誰識頭角，祇應遺藁是通津。"]'),
('03549827-5ff9-4936-9d3b-fe01fdd6b0e4','濮道甫挽詞二首  其一','李之儀','宋','宋诗','song-poetry','','[]','暮雨江邊寄一犁，多情鄰老共差池。',64,'全唐诗/poet.song.55000.json','["暮雨江邊寄一犁，多情鄰老共差池。", "平生意氣幾如俠，晚日詩書更有兒。", "社酒方期終歲樂，葵蕭俄感送人悲。", "紛紛窮達都歸盡，誰復聲名是舊時。"]'),
('28b6f83c-0bbf-48c3-bbcd-8017e0d7e8a9','濮道甫挽詞二首  其二','李之儀','宋','宋诗','song-poetry','','[]','倜儻胸襟孰可侔，生平行樂自優游。',64,'全唐诗/poet.song.55000.json','["倜儻胸襟孰可侔，生平行樂自優游。", "坐忘更漏棋盈局，醉徹笙歌月滿樓。", "千頃田園常富足，幾朝冠蓋舊交遊。", "佳城今日悲埋玉，亙古傳名信不休。"]'),
('cd4246f9-57ea-4912-b615-38096bedc676','郭功甫妻孫夫人挽詞','李之儀','宋','宋诗','song-poetry','','[]','率己名無媿，成家德可尊。',48,'全唐诗/poet.song.55000.json','["率己名無媿，成家德可尊。", "蘋蘩招婿婦，翰墨見兒孫。", "孰不承慈訓，俱來哭寢門。", "詩人難再得，彤管負詳論。"]'),
('5a382a4a-e1bb-4992-a4ea-ab8508135e04','李府君挽詞','李之儀','宋','宋诗','song-poetry','','[]','賣藥韓康伯，著書河上公。',48,'全唐诗/poet.song.55000.json','["賣藥韓康伯，著書河上公。", "幻同聊復爾，緣散却歸空。", "獨有鄉人淚，難勝薤露風。", "我來嗟已晚，猶及想冥鴻。"]'),
('16c3d4ac-5dd3-42c7-9645-07b966818917','弔王承議二首  其一','李之儀','宋','宋诗','song-poetry','','[]','崎嶇南北舊相聞，晚困羈縲託後塵。',64,'全唐诗/poet.song.55000.json','["崎嶇南北舊相聞，晚困羈縲託後塵。", "盜賊餘風如振槁，里閭和氣似深春。", "雀巢絕探終能鷇，烏喙雖長自不伸。", "所去見思猶可想，九泉齎恨彼何人。"]'),
('bc24c079-0343-4590-8e14-68976e2013f2','弔王承議二首  其二','李之儀','宋','宋诗','song-poetry','','[]','征西墓上木成圍，伯氏傳孤出更奇。',64,'全唐诗/poet.song.55000.json','["征西墓上木成圍，伯氏傳孤出更奇。", "皂蓋朱輪誰不擁，青天白日晚方知。", "功名不掛非由種，賻賵終辭信有兒。", "空指丹青訪陳迹，倦懷尤恨得君遲。"]'),
('9415d84e-835b-4d0c-b7c3-dcac480cebbd','自作傳神贊  其一','李之儀','宋','宋诗','song-poetry','','[]','似則似，是則不是。',39,'全唐诗/poet.song.55000.json','["似則似，是則不是。", "縱使擠之九泉下，也須出得一頭地。", "休論捉月騎鯨，到了衆人皆醉。"]'),
('fa70d275-698a-42b6-81d4-8581182703a2','自作傳神贊  其二','李之儀','宋','宋诗','song-poetry','','[]','時雌時雄，時白時黑。',48,'全唐诗/poet.song.55000.json','["時雌時雄，時白時黑。", "不是徐翁異身，又非豐干指出。", "蓋優哉游哉，聊以卒歲。", "浮沈於物，而不膠於物者也。"]'),
('1753b3db-6cf2-456b-ae8f-e96930f19290','自作傳神贊  其三','李之儀','宋','宋诗','song-poetry','','[]','孰從而圖，孰從而狀。',48,'全唐诗/poet.song.55000.json','["孰從而圖，孰從而狀。", "大千俱空，况爾幻妄。", "直須壁立千仞，要且事無一向。", "雖然覿面相呈，便是本來形相。"]'),
('f3856dd3-bd11-4117-b7ae-2c17a08e4bfb','自作傳神贊  其四','李之儀','宋','宋诗','song-poetry','','[]','意中迥有千般思，筆下原無一點塵。',32,'全唐诗/poet.song.55000.json','["意中迥有千般思，筆下原無一點塵。", "自笑頑冥一村老，忽從今日換精神。"]'),
('3c4a99c0-69fc-4a22-8a1b-a9f163c550d7','折渭州畫像贊','李之儀','宋','宋诗','song-poetry','','[]','龍章鳳姿，燕頷虎頸。',140,'全唐诗/poet.song.55000.json','["龍章鳳姿，燕頷虎頸。", "巍巍堂堂，弗嚴而整。", "山納海容，霜根雪節。", "可畏而親，力莫之斡。", "吾私淑諸，一代之英。", "多取益給，欲掩滋明。", "長庚未艾，白氣何來。", "精爽如在，佳城不開。", "出卯則角，墮地而班。", "豈無所遺，騄驥方閑。", "高牙赤舄，惟叔惟虎。", "有之似之，千載一武。", "赳赳桓桓，彼徒見誚。", "他日凌烟，實先前詔。"]'),
('999008f7-1855-4f86-b5dc-05dff6c89b99','沈存中畫像贊','李之儀','宋','宋诗','song-poetry','','[]','先天弗違，聖時以乘。',80,'全唐诗/poet.song.55000.json','["先天弗違，聖時以乘。", "人謀鬼謀，其誰其能。", "彼雖淵密，我則揆敘。", "萬目交張，維綱之舉。", "展也吾人，一世絕擬。", "孰友多文，宛在中沚。", "用此以通，亦以是窮。", "自崖反矣，凜然孤風。"]'),
('01181acc-7e07-43fb-9269-6c929eee075c','保寧機道者傳神贊  其一','李之儀','宋','宋诗','song-poetry','','[]','一回拈起一回新，覿面相逢那處親。',64,'全唐诗/poet.song.55000.json','["一回拈起一回新，覿面相逢那處親。", "口似含珠聲似虎，情如止水意如春。", "一心爲法無餘事，四海如公有幾人。", "祇恐丹青傳未盡，更須圓相助精神。"]'),
('4925fdbc-fdc3-4ad3-8472-fbc1a026e75f','保寧機道者傳神贊  其二','李之儀','宋','宋诗','song-poetry','','[]','萬點寒鴉，一輪秋月。',52,'全唐诗/poet.song.55000.json','["萬點寒鴉，一輪秋月。", "時節因緣，因誰漏泄。", "眼光如電舌如雷，遶頷鬚眉滿頭雪。", "若問人間大導師，踏着稱鎚硬似鐵。"]'),
('6fdc7ea5-a335-40bb-b5c1-8c92b19bd513','崇因欽老贊','李之儀','宋','宋诗','song-poetry','','[]','真如會中，相見了也。',70,'全唐诗/poet.song.55000.json','["真如會中，相見了也。", "崇因堂上，因甚出來。", "一滴曹溪，初無二味。", "大冶精金，豈有他色。", "雖然畫得分明，要須重新注出。", "十二面相忽然開，不是僧繇誰得會。"]'),
('231d7f27-9118-4787-a3a6-ab10f9dbec7a','凈慈璘老贊','李之儀','宋','宋诗','song-poetry','','[]','法雲會中，多聞第一。',58,'全唐诗/poet.song.55000.json','["法雲會中，多聞第一。", "瑞竹堂上，說法無雙。", "降徑山龍，則雨必應候。", "祝崇寧壽，則香不妄拈。", "將謂有多少神通，元來只這般面目。"]'),
('f5276826-4b28-4b52-83d1-d4e5e1146579','西菴璞老真贊','李之儀','宋','宋诗','song-poetry','','[]','一住姑熟溪頭，三據寶華玉座。',65,'全唐诗/poet.song.55000.json','["一住姑熟溪頭，三據寶華玉座。", "草木無不沾恩，緇素幾多證果。", "世人盡愛西菴璞，誰知屢試紅爐火。", "雖然覿面相呈，也要從頭覷破。", "咄，鈍置殺人。"]'),
('a46dadf2-fec7-4297-892d-b8949c186151','儲居士真贊','李之儀','宋','宋诗','song-poetry','','[]','敏以自求，仁而樂施。',89,'全唐诗/poet.song.55000.json','["敏以自求，仁而樂施。", "鄉黨懷其恕，朋友畏其義。", "悟幻妄之不留，惟精進之是利。", "故能告所厚而表其行，斂衆美以昌其嗣。", "尚慮吾志之未孚，遂復有形於夢寐。", "嗚呼，斯豈今人之願力歟，見者寧不知媿。"]'),
('a4c66186-b19c-45bf-b90e-8ca5c2ab35ec','李太白畫像贊','李之儀','宋','宋诗','song-poetry','','[]','舉目一世空無人，當時何有高將軍。',64,'全唐诗/poet.song.55000.json','["舉目一世空無人，當時何有高將軍。", "龍鶱鳳翥固莫群，晴天萬里惟孤雲。", "冥冥何地非埃塵，我欲從之嗟此身。", "形容不到浪自分，坐令魯叟悲獲麟。"]'),
('9bdaf51f-9770-4964-9ac3-6c5fee8a041e','東坡先生贊  其一','李之儀','宋','宋诗','song-poetry','','[]','東坡仙人，岷峨異稟。',60,'全唐诗/poet.song.55000.json','["東坡仙人，岷峨異稟。", "道日而升，弗類斯擯。", "有繼皇皇，期之奠枕。", "誰其止之，成是貝錦。", "天作人遠，言何從諗。", "聞已聳然，見孰不凜。"]'),
('a40726ed-492d-4afe-9369-0abf75058c91','東坡先生贊  其二','李之儀','宋','宋诗','song-poetry','','[]','天作斯文，萬物所印。',80,'全唐诗/poet.song.55000.json','["天作斯文，萬物所印。", "時慘時舒，與天同運。", "其誰特立，卓哉吾人。", "黄且落矣，蔚然常春。", "見險弗止，自信無悶。", "求仁得仁，於我何怨。", "光時顯被，外薄四夷。", "載瞻載仰，百世之師。"]'),
('64363d36-c808-4f42-8e01-68d77e293b4f','靈巖愿老真贊','李之儀','宋','宋诗','song-poetry','','[]','法不孤起，隨處有人。',61,'全唐诗/poet.song.55000.json','["法不孤起，隨處有人。", "一花既開，無地不春。", "現滿月相，轉大法輪。", "似雷雨作解，如山川出雲。", "不向人偏衫襟裏喫飯，而於孤峰頂上化身。"]'),
('8cbd900a-a260-4230-8ba0-1b08f69c070b','靈源禪師真贊','李之儀','宋','宋诗','song-poetry','','[]','滔滔汩汩，莫知其出。',89,'全唐诗/poet.song.55000.json','["滔滔汩汩，莫知其出。", "汪汪洋洋，隨圓隨方。", "故八萬四千偈不離於當處，而五千四十八卷皆作戲於逢場。", "山谷老人所以强名之而無媿，姑溪居士又從而雪上加霜。", "咄，只這便是靈源叟，何須更上炤默堂。"]'),
('c68c0dcb-ef0e-4911-aac8-3331db575ce1','報恩邦禪師真贊','李之儀','宋','宋诗','song-poetry','','[]','荆山美璞，霜天一鶚。',44,'全唐诗/poet.song.55000.json','["荆山美璞，霜天一鶚。", "可薦郊廟，志存寥廓。", "逢場作戲，隨病予藥。", "信與佛祖齊肩，直是摸索不着。"]'),
('c3aa4f3b-f847-4522-825d-a258e43da9a6','李伯時馬贊','李之儀','宋','宋诗','song-poetry','','[]','竹批雙耳，風激四蹄。',40,'全唐诗/poet.song.55000.json','["竹批雙耳，風激四蹄。", "振尾頓鬣，會於一時。", "惟伯時父，神而明之。", "千載相遇，非公而誰。"]'),
('40d07999-6d6b-4bdb-81c8-40faddcbf50f','畫龜贊','李之儀','宋','宋诗','song-poetry','','[]','鱗介所宗，壽無與京。',49,'全唐诗/poet.song.55000.json','["鱗介所宗，壽無與京。", "納錫以薦，曳尾而行。", "與其託之於死骨，孰若遂性以爲生。", "余私淑諸，蓋將卒歲以沉冥。"]'),
('880884db-62d7-4d7e-8cca-a2ace5de884b','須菩提贊','李之儀','宋','宋诗','song-poetry','','[]','敷座而坐，如日初曉。',40,'全唐诗/poet.song.55000.json','["敷座而坐，如日初曉。", "護念付屬，一時俱了。", "非此老人，其誰能表。", "漫自形容，本無欠少。"]'),
('a599dbd5-e372-4247-80fd-6b5531ef3af1','慧林正老真贊','李之儀','宋','宋诗','song-poetry','','[]','高坐清凉道場，截斷東南路口。',66,'全唐诗/poet.song.55000.json','["高坐清凉道場，截斷東南路口。", "一萬菩薩列在下風，天下衲僧聞者稽首。", "挺超佛越祖之意氣，有抽釘拔楔之妙手。", "拶得額頭汗出，又向王舍城中哮吼。"]'),
('f501c6ac-fab0-4d37-a6e8-a6db336199dc','布袋和尚贊','李之儀','宋','宋诗','song-poetry','','[]','盛着底是病，拈出底是藥。',54,'全唐诗/poet.song.55000.json','["盛着底是病，拈出底是藥。", "衆生以相見我，却道風狂顛錯。", "秋來葉落歸根，春去鳥啼花落。", "只這便是生涯，說甚重重樓閣。"]'),
('b806766e-a7f9-4c4e-a19e-c96806b9a5db','俞秀老畫贊','李之儀','宋','宋诗','song-poetry','','[]','青山白雲中人，對面若不相識。',53,'全唐诗/poet.song.55000.json','["青山白雲中人，對面若不相識。", "笑我吟詠自如，終□□□居士身得度，住平常人窠窟。", "誰謂半山多□口，却作豐干指出。"]'),
('a72be6ba-6b2b-4d0e-aeac-567088631864','俞清老畫贊','李之儀','宋','宋诗','song-poetry','','[]','說着便知姓名，見者誰不歡喜。',56,'全唐诗/poet.song.55000.json','["說着便知姓名，見者誰不歡喜。", "雖如自起自倒，要乃無此無彼。", "冥冥三板緣中，隨處逢場作戲。", "欲問涅槃一路，頭頭只在這裏。"]'),
('01d12617-f6c5-4ff8-995b-24ef52a28171','寶覺昕長老畫贊','李之儀','宋','宋诗','song-poetry','','[]','法雲地中得度，慧炬光裏法身。',56,'全唐诗/poet.song.55000.json','["法雲地中得度，慧炬光裏法身。", "在處淘金揀玉，隨緣運栰通津。", "偏解抽釘拔楔，更能因語識人。", "且道有相無相，休云是真非真。"]'),
('462d9b59-c947-411d-ad87-1f32c98dfc40','壽寧宣老贊','李之儀','宋','宋诗','song-poetry','','[]','石霜山中二虎，後世兒孫無數。',56,'全唐诗/poet.song.55000.json','["石霜山中二虎，後世兒孫無數。", "堂堂大爲古佛，一身普照寰宇。", "別出壽寧一枝，又作慈雲法雨。", "他時侍立坐邊，往往呵佛駡祖。"]'),
('f48f3135-1fe9-4fc9-bbc0-b97d8d0d1f85','爲僧作石菖蒲贊','李之儀','宋','宋诗','song-poetry','','[]','葉磨數仞劍，惟有清風剪不斷。',44,'全唐诗/poet.song.55000.json','["葉磨數仞劍，惟有清風剪不斷。", "根亂一窩絲，纏定白雲寒不散。", "水無沙，石無苔，師乎一片心清哉。"]'),
('cd0d4c66-c81c-4982-8e6b-dd23e67e2d5a','爲人作真贊  其一','李之儀','宋','宋诗','song-poetry','','[]','王良不作，世絕麒麟。',100,'全唐诗/poet.song.55000.json','["王良不作，世絕麒麟。", "是可欺邪，豈無後人。", "誰其似之，維烈武孫。", "武則似矣，而濟以文。", "氣已萬里，方爾就秣。", "風雲其時，會如兔脫。", "儼然是則，現居士身。", "幅巾白拂，無一點塵。", "以無塵故，始終一如。", "顯忠數功，固非兩途。"]'),
('bd008bb0-0a90-4968-9f92-cc83c0bcafc5','爲人作真贊  其二','李之儀','宋','宋诗','song-poetry','','[]','茅茨爲居，脫粟爲餐。',88,'全唐诗/poet.song.55000.json','["茅茨爲居，脫粟爲餐。", "牛衣自暖，徒行亦鞍。", "凡人皆友，是酒可歡。", "略不踐迹，未嘗恤言。", "山林城市，隨遇即安。", "一旦義重，殺生非難。", "彼强增飾，寧知吾全。", "蓋庶幾不淫不移不屈者，而以樂吾之天。"]'),
('d697ef0d-22f8-41e7-b199-d8cfde9ee7a2','文忠公畫像贊','李之儀','宋','宋诗','song-poetry','','[]','霜空無雲，秋天澄霧。',40,'全唐诗/poet.song.55000.json','["霜空無雲，秋天澄霧。", "照然政通，何勞鐘簴。", "儼然望之，希世一遇。", "萬折方東，逢坡益注。"]'),
('8d4c749b-2b4e-4e61-a404-309f1ce1c330','爲僧作真贊','李之儀','宋','宋诗','song-poetry','','[]','虎頭燕頷，將軍之相。',68,'全唐诗/poet.song.55000.json','["虎頭燕頷，將軍之相。", "雪檜霜松，山僧之容。", "以是而見，胡來漢現。", "捩轉面目，瞻之不足。", "盛哉七百聚徒，何殊在網之魚。", "若也向此提撕，却成土上加泥。"]'),
('66592b40-9ff8-44c9-a5a0-c9f465127cf8','吳思道朝服畫像贊','李之儀','宋','宋诗','song-poetry','','[]','可畏而親，不扶而直。',40,'全唐诗/poet.song.55000.json','["可畏而親，不扶而直。", "藝表士林，望高王國。", "如在廣庭，鵠立柱石。", "翼翼眉間，嘗滿黄色。"]'),
('dd6bf68e-0148-461c-9494-8dced9ac7148','又道服贊','李之儀','宋','宋诗','song-poetry','','[]','濃眉深眼，出塵之相。',68,'全唐诗/poet.song.55000.json','["濃眉深眼，出塵之相。", "幅巾燕服，經世之狀。", "有時收沙界於一粒粟，忽然乘長風破萬里浪。", "固知透過六輪，可謂森羅萬象。", "本誰鼻端揮斤，先生信是神匠。"]'),
('e6db92bf-1490-4059-9b45-86e1dece3ba7','晚過王晉卿第移坐池上松杪凌霄爛開','李之儀','宋','宋诗','song-poetry','','[]','清風習習醒毛骨，華屋高明占城北。',128,'全唐诗/poet.song.55000.json','["清風習習醒毛骨，華屋高明占城北。", "胡床偶伴庾江州，萬蓋摇香俯澄碧。", "陰森老樹藤千尺，刻桷雕楹初未識。", "忽傳繡障半天來，舉頭不是人間色。", "方疑絢塔燈炤燿，更覺麗天星的歷。", "此時遙望若神仙，結綺臨春猶可憶。", "徘徊欲去輒不忍，百種形容空嘆息。", "亂點金鈿翠被張，主人此况真難得。"]'),
('ac71ecf2-4ec9-4af5-b272-dfad68dd8e29','題王子重出李成所畫山水','李之儀','宋','宋诗','song-poetry','','[]','主人邀我登閒軒，軒前景物祗欠山。',224,'全唐诗/poet.song.55000.json','["主人邀我登閒軒，軒前景物祗欠山。", "坐來慘澹若不足，引我忽到營丘間。", "營丘山水天下知，全齊十二雄一時。", "舊遊歷歷如到眼，吾宗筆力窮高低。", "峰雲巖靄互隠現，老木蒼藤紛綵絢。", "瓏璁特幹勢將壓，奇崛欲夸人未見。", "石磴流泉似幽噎，洞穴縱橫乍明滅。", "舉頭樓觀俯懸崖，定須六月臨飛雪。", "行人初踏山前路，款段衝寒怯回顧。", "蹇馿亦自樂平地，嚲耳徐行方得趣。", "日西平遠連何處，極目蒼茫天欲暮。", "行人端是我前身，斗覺精神相會聚。", "百年瞬息竟誰真，此老應無一點塵。", "主人等是風塵外，豈是閒軒久住人。"]'),
('c9904585-460d-4ef2-9b4b-cc0461e1493d','觀子重鐘隠鷄鷹圖就借傳本畫乃文康舊物','李之儀','宋','宋诗','song-poetry','','[]','千年老木根半拔，叉牙枯枝鬭金鐵。',208,'全唐诗/poet.song.55000.json','["千年老木根半拔，叉牙枯枝鬭金鐵。", "蒼鷹見鷄豈復捨，伺隙必拿將雷掣。", "鷄知不免怖且死，銅觜窺鷹反噪聒。", "陰風慘慘天爲改，殺氣憑陵欲翻海。", "畫工已證三昧因，造化精神智能采。", "江南山水多異人，遁迹往往隨風塵。", "等閒應現非一化，流落終爲絕世珍。", "王公盛德天下歸，想見乾興天聖時。", "進賢退佞乃所嗜，不使異趣侵毫釐。", "喻公爲鷹固不可，排擊奸邪力尤果。", "開圖凜凜毛髮驚，滯蔚頓攄如破鎖。", "公孫勝致有餘風，十年凈土常相同。", "擬借傳摹應見從，意欲因畫時見公。"]'),
('60fdccc4-5f87-4642-878b-ae80f6142845','次韵胡希聖登毗陵東山亭','李之儀','宋','宋诗','song-poetry','','[]','君不見狐裘相齊望前古，後日執鞭固欣慕。',326,'全唐诗/poet.song.55000.json','["君不見狐裘相齊望前古，後日執鞭固欣慕。", "煙雲得趣更飄蕭，常使高人恨無路。", "闌干崢嶸擅空闊，寒日低回得循步。", "朱輪想見不可從，南國小棠疑未去。", "百年暴輝實之賓，俯盛仰衰情易新。", "孤懷直欲共傾倒，衣上元無一點塵。", "又不見三千珠履春申君，十年天祿揚子雲。", "極目平原草縈骨，秋月春風愁殺人。", "五湖歸去辨之蚤，擊鼓撞鐘猶恨少。", "險語緩絲一劍休，九衢相視空草草。", "荆州萬里控上流，歌舞翻風甚飛鳥。", "回首蒼梧隔暮雲，南狩不歸何可叫。", "解后相逢情更親，芻狗疇能誇已陳。", "欲書醉語致多感，好事今無載酒人。", "班班微陽度密竹，嘖嘖寒雀喧荒榛。", "韋郎所紀十無一，安得遺老酬諮詢。", "蹭蹬難堪隨末俗，健論愛君如剪竹。", "寧人負我無負人，咄咄老瞞徒四目。", "直絃易斷曲未終，鳳髓難容斷誰續。", "白首胡君到孤獨，在何分金齊鮑叔。"]'),
('cdcacb70-a4fe-4ed8-8be9-b349889b9e9b','送李仲益赴濠梁司戶','李之儀','宋','宋诗','song-poetry','','[]','烱然五府不受塵，深山大澤猛虎蹲。',64,'全唐诗/poet.song.55000.json','["烱然五府不受塵，深山大澤猛虎蹲。", "豫章千尺若可抉，滄溟萬里疑平吞。", "秋天一鶚禰正平，人物南州龐士元。", "莫詠濠梁好風月，當知猿臂出吾門。"]'),
('3fed87f5-fef6-4968-93b6-f95f7891f920','閩僧饋紅糟炒笋','李之儀','宋','宋诗','song-poetry','','[]','食飽舐指老更深，饑腸南北常欹崟。',128,'全唐诗/poet.song.55000.json','["食飽舐指老更深，饑腸南北常欹崟。", "曾作閩山對岸客，海舶供看常相尋。", "一路埃塵春幾換，葷羶裂腦愁舉桉。", "淮陵巨海不多程，多情誰殺能鳴雁。", "道人雅好逾千金，短茁漬味羞春林。", "呼兒績飯不知飽，未徹已到閩山陰。", "孤風冷石常齒齒，不忘南音似君子。", "寂寞相求義愈高，豈特今朝共鄰里。"]'),
('97e46974-fe0e-4da3-a1d9-095b28f930d2','胡希聖在毗陵有詩私送比過山陽復以其韵送之','李之儀','宋','宋诗','song-poetry','','[]','寒雲四塞客日短，一壺臍裂洪疇中。',208,'全唐诗/poet.song.55000.json','["寒雲四塞客日短，一壺臍裂洪疇中。", "君家大門我父黨，覓白聊復相過從。", "和香索料多甲煎，幽蘭幾弄理孤桐。", "爾來行李偶南北，齒齒不見雲間峰。", "登山臨水不無思，獨笑往往捫長松。", "蓬門春晚燕語好，書幌迤邐來清風。", "五府带垢一洗盡，萬里古色開愁胸。", "輞川何在廣文死，比比孺子誇有功。", "楚人僅免二日苦，却嗟白璧埋蒿蓬。", "逡巡取酒敘契闊，百川赴吸驚長虹。", "風流未愧正始後，淪落丘范評無鍾。", "君才有用豈特爾，我亦相將成老翁。", "騏驎得路即千里，會看拭目天邊鴻。"]'),
('514be900-ea0f-42d4-8349-df1b8b6bebcf','登鸛雀樓','李之儀','宋','宋诗','song-poetry','','[]','大河南奔山北走，臍裂天涯懶回首。',64,'全唐诗/poet.song.55000.json','["大河南奔山北走，臍裂天涯懶回首。", "撞鐘擊鼓醉橫參，恃險英雄骨已朽。", "歲暮風烟尤可悲，功名白髮不相期。", "重來好是當晴日，應有鷄羣翡翠兒。"]'),
('19600b47-62d4-45e3-9107-0c86637d5c6d','送鄭産莊','李之儀','宋','宋诗','song-poetry','','[]','酌君白玉杯，送君正黄梅。',225,'全唐诗/poet.song.55000.json','["酌君白玉杯，送君正黄梅。", "長安風沙瞇人眼，君行暫詣黄金臺。", "劇辛已老樂毅去，荆棘平地多龍媒。", "九重深沉四海遠，快便誰許參雲雷。", "黄金臺高不易上，并州雄節幾塵埃。", "當時勳業皎白日，餘風表表皆雄才。", "龍睛豕腹實異相，肝膈上下羅瓊瑰。", "丹青萬物大門婿，妙論爾汝無嫌猜。", "同時舒卷一門盛，將見烈火生寒灰。", "十年早飛不足歎，青雲自此亨途開。", "我暫追隨極天末，有酒取醉長追陪。", "離亭雨足綠蔽眼，健帆危挂寒風催。", "黄金臺不知幾千尺，勸君窣衣直上首莫回。", "時和歲豐亦足被君賜，還須遠過青山隈。"]'),
('f3b23724-fa90-4160-8020-34d8cbf8a2a9','晚步汴堤始見春色次夜與蔡君規鄭希仁同飲進奏官舍','李之儀','宋','宋诗','song-poetry','','[]','昨日行河堤，柳色綠如埽。',190,'全唐诗/poet.song.55000.json','["昨日行河堤，柳色綠如埽。", "只疑晚煙罩寒林，細看始知春已到。", "春來本不與我期，病中蹉却春來時。", "塵埃雨過風不起，但見紅紫咄咄陵高枝。", "年年見春隨分喜，今年見春略無意。", "泊然相遇等幻化，況是客愁如夢裏。", "前年隨春入都門，去年探春海上村。", "今年作客還到此，萬里漂浮誰與論。", "故人邂逅羅酒樽，白髮相逢情更親。", "身世崎嶇有底急，終日裂臍如歸雲。", "倚門幾夜環連夢，勃窣稚子行逡巡。", "扁舟早晚東南奔，車馬紛紛愁殺人。"]'),
('1800a6ba-0ca3-4147-b09e-eab86920373e','送俞叔通歸四明','李之儀','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','終軍棄關繻，李斯逐黄犬。',240,'全唐诗/poet.song.55000.json','["終軍棄關繻，李斯逐黄犬。", "功名事業自有時，咄嗟所得亦蹇淺。", "雷奔電掣千里雨，魚變爲龍如掌反。", "侯嬴抱關誰復論，公子感之在一言。", "擔簦屐履遍列國，平揖相印須臾間。", "簀中不死魏齊困，口中舌在天應旋。", "莫嘆髀肉消，休悲釜生魚。", "揮斥八極神不變，秦人豈識照乘珠。", "氣吁虹蜺亙天地，有時一笑海可枯。", "泰山排雲天下小，紛紛何足論賢愚。", "得君本如此，君知我無朱。", "幾年飛鳴共搶榆，長慙瓦礫參璠璵。", "都城踰月同朝晡，蹩然別我還舊廬。", "引君一杯酒，洗君衣上塵。", "我歌雖促非酸辛，未忍祝別惟加飧。", "直教探取虎穴子，西來射策黄金門。"]'),
('6243c6a0-8179-462d-a7f9-88440f5d71ed','次韵孔經甫題剡縣史氏競秀堂','李之儀','宋','宋诗','song-poetry','','[]','天姥迤邐沃州緊，萬壑千巖相汲引。',192,'全唐诗/poet.song.55000.json','["天姥迤邐沃州緊，萬壑千巖相汲引。", "崢嶸不知盡何如，撐突雲煙隨望隕。", "來蹲去伏搏虎豹，上圓下妥蒸芝菌。", "溪流縈紆湛寒玉，飛泉滴瀝調金軫。", "天造神藏發有時，眼力收羅一朝盡。", "連甍接桷插星斗，檻欄分明噓老蜃。", "薄遊曾向畫圖見，幾欲微吟寫秋蚓。", "登臨更想新醅熟，紫蕨堆盤參竹笋。", "排坐歌呼來謫仙，落筆篇章陵醉尹。", "晴春雪霽夜月滿，此樂誰能計畦畛。", "到者如行避世村，回首紛紛只堪哂。", "因君歸興不自持，安得陵風跨蒼隼。"]'),
('61dba4f3-4c81-4756-b988-9fbaa9c0f9c9','兼江祥瑛上人能書自以爲未工又能詩而求予詩甚勤予以爲非所當病也爲賦一首勉之使進于道云','李之儀','宋','宋诗','song-poetry','','[]','得句如得仙，悟筆如悟禪。',157,'全唐诗/poet.song.55000.json','["得句如得仙，悟筆如悟禪。", "彈丸流轉即輕舉，龍蛇飛動真超然。", "禪瑛迺醉，我顧慙道玄。", "戲將字畫當杖拂，與子憑軾相周旋。", "筆若運矛矟，手如致裨偏。", "眼能援桴鼓，心爲制中權。", "棄捐尺度廢繩削，似曲還直非方圓。", "適當庖丁善刀後，但見滿紙銀鈎連。", "心眼手筆俱不用，擬向底處觀其全。", "思量不可到，此地無中邊。", "政似觀瀾亭上夜深後，滿空白月孤光懸。"]'),
('11a29255-b3b2-470b-ad7a-0a6cca185ac5','次韵王性之見寄佳句','李之儀','宋','宋诗','song-poetry','','[]','文質相乘徒野史，拔山塞海終軍死。',240,'全唐诗/poet.song.55000.json','["文質相乘徒野史，拔山塞海終軍死。", "早時妄作不朽計，掇拾餘疏自綱紀。", "跳梁甃缺固無有，白首何堪墮牛李。", "冥行觸柱猶欲前，布襪青鞋從茲始。", "春風罾頭問時魚，莫雨洲中吟白芷。", "爾來蹭蹬十二年，尚向牛角驚鬭蟻。", "亭亭日沒見初月，宛是角巾逢綺里。", "萬頃烟波渺天末，十丈霜松騰澗底。", "幾從窈窕泛斗槎，終愧婆娑參珮蘂。", "晚來鵲話頗不凡，俄報翩翩航一葦。", "元龍豪氣不少除，樓卧超然遽思起。", "問途直指三峰去，盤馬樓前萬人喜。", "亟發健句壓欲倒，似不見容已無齒。", "便期脫帽灑風腴，豫宿寒舂絜雲子。", "定應一笑非等閒，更想筆端如瀉水。"]'),
('58a80be3-cc6e-4792-b6a5-bee2b0f2ab66','唐公兄惠顧海上既行輒有詩奉送','李之儀','宋','宋诗','song-poetry','','[]','憶昨扁舟下京口，六月江頭浪如吼。',224,'全唐诗/poet.song.55000.json','["憶昨扁舟下京口，六月江頭浪如吼。", "一笑還尋浮玉叟，山半飛雲似招手。", "月明上船縈宿酒，倒摘沈星疑犯斗。", "夜深歸夢徹東吳，覺來落月穿疏牖。", "山僧流連强終日，黄昏歸鳥凌風疾。", "玉骨蕭森病枕餘，一語才交復相失。", "先生高節如古人，薄宦淹回行路塵。", "海城寄食不自給，暫喜持盃同探春。", "春風花草來踆踆，微紅淡綠意旋新。", "相從白髮情未壓，底事促別聲悲辛。", "淮陵欲到嗟無因，想見蔓草縈龍鱗。", "浦光亭南拍隄水，冉冉落日低孤墳。", "到時春色應已遲，滿樹黄鸝初囀時。", "憑將一曲原頭淚，爲洒南墳松樹枝。"]'),
('8b780b2c-eeac-4235-967d-2a3406c6c360','阮公嘯臺次韵辛正叔','李之儀','宋','宋诗','song-poetry','','[]','有口莫飲盜泉水，有手莫探驪龍珠。',164,'全唐诗/poet.song.55000.json','["有口莫飲盜泉水，有手莫探驪龍珠。", "秋風冷落千古意，追風絕足誰能拘。", "白雲青山避世樂，擊鼓撞鐘廊廟居。", "等閒舒卷四海爲之動，豈憚一一從吹竽。", "君看事事絕天險，阿房宮在空荒墟。", "野人不識貴者帝，直欲炙背同向茅簷隅。", "由來土苴漫優劣，亹亹傳習隨有無。", "當時一嘯亦偶爾，至今登覽煩嗟歔。", "吾人妙質素所畏，感嘆陳迹追盈虛。", "涇清渭濁固可辨，未應到海君能殊。"]'),
('c14b1481-f7d7-4343-9c74-be7748fb976c','王爲道東軒梅花小桃相次弄色置酒見邀出琉璃盆浸花貯酒半移即花既辭留名壁間','李之儀','宋','宋诗','song-poetry','','[]','搔髮滿爪垢，撲衣滿襟塵。',344,'全唐诗/poet.song.55000.json','["搔髮滿爪垢，撲衣滿襟塵。", "百年信幾時，吾生苦紛紜。", "黄河源從天上流，忽然河底爲沙丘。", "張良身不滿三尺，從使沛公君列侯。", "淮陰小兒亦何者，俛首無辭出胯下。", "晨炊蓐食爲得計，一飯千金豈無價。", "相君之背貴莫言，前趨鼎鑊何等閒。", "使爲故主已梟首，奏事猶如冕旒前。", "軹深井里有屠者，荆歌壯士不復還。", "伯樂相馬只相骨，咄咄常情迷賈鞭。", "春來萬事不欲語，惟願沽酒不著錢。", "大鐺長杓酌還引，日日如此過百年。", "相家新有檢正官，謂我落魄早見憐。", "東軒小桃間梅蘂，清香秀色能相先。", "不將貴勢略雅舊，脫巾取酒容流連。", "瑠璃盆深花透過，愛花移向花邊坐。", "時時飄蘂落盆中，冉冉天仙空裏墜。", "醉後草書疑有神，牆間怒角拿飛雲。", "掃禿千毫興未盡，惆悵粉壁何時新。", "盆空不記上馬去，曉來但見衣巾污。", "古人名節堆故紙，多少沉埋不知數。", "明朝花落在須臾，莫遣高門無入路。"]'),
('fa7fb22e-1057-4c91-be8b-2f02291104d0','次韵參寥杜孝錫','李之儀','宋','宋诗','song-poetry','','[]','君不見深山窮谷千丈潭，懸崖絕壁倒挂松。',202,'全唐诗/poet.song.55000.json','["君不見深山窮谷千丈潭，懸崖絕壁倒挂松。", "雷霆雨電有時一洒遍八極，繁霜雪霽能邀夜月來高穹。", "又不見江頭龜手洴澼絖，裂地得侯終有逢。", "長安大雪幾千尺，高卧不愧衣玲瓏。", "揖人而相若反掌，登天有路非難通。", "天之可上勢或便，得相乃在須臾中。", "朝冠貂蟬暮徽纆，曲肱何在三千鍾。", "方東遽北安足究，豈異海舶隨狂風。", "舞雩而詠吾與點，坐中客滿誰知融。", "屹屹杜夫子，靈芝翳深叢。", "百年轉盼皆腐朽，且將逸駕聊與同。", "我慙圭觚刺人眼，空向霜天望飛鴻。"]'),
('c1e9dbc7-5326-43f4-8f90-22e520747e7b','送李仲益及第調濠州司戶還錢塘','李之儀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶昨西湖弄烟月，玉面少年搔紺髮。',256,'全唐诗/poet.song.55000.json','["憶昨西湖弄烟月，玉面少年搔紺髮。", "六月正午斷人行，坐上無風不覺熱。", "長安塵沙五月尾，汗透纖絺甚懸水。", "相逢惝怳秋已深，冰骨令人冷如洗。", "吾家謫仙應已朽，采石風流誰可後。", "却恐騎鯨下紫霄，斯人豈是人間有。", "春風標名冠禮部，睥睨英豪皆培塿。", "三月飛花試集英，筆下光芒射斗牛。", "共說唱名須第一，人事天時良可必。", "大任先當益未能，何謂揚雄老終吃。", "滄溟洶湧百怪見，鯨鬣虯髯豈難辨。", "莫謂卑飛遽自陵，功曹曾是將軍願。", "集賢學士文章舊，平日追隨今太守。", "到日應須倒屣迎，還聞下榻南昌秀。", "濠上觀魚魚正躍，携手何人知此樂。", "妙處期君向上求，可笑蝸牛爭兩角。"]'),
('d38ff87b-396b-41c7-a25a-8f6ac1425537','爲道見還詩因次其韵兼簡孝錫','李之儀','宋','宋诗','song-poetry','','[]','反衣狐裘矜綠裏，月落宵行易淪委。',192,'全唐诗/poet.song.55000.json','["反衣狐裘矜綠裏，月落宵行易淪委。", "崎嶇身世等秋蓬，皎皎吾心淡如水。", "青雲有路誰引目，肯學荒疏輟洗髓。", "經營一飽困南北，未易功名輸故紙。", "爾來投迹間諸彥，白雪每容參下里。", "何殊溺者得尺素，聊謝箕翁徒洗耳。", "大官供庖事鉛槧，時引古人同凈几。", "枉老王郎特我賢，華衮相先慙溢美。", "清風冷落勞悵望，誰謂雲間見黄綺。", "因收倦緒聊紡織，半是棄餘安足喜。", "一片簫韶送下天，遊遍華胥如喚起。", "從此修途可問津，豈復龍頭却蛇尾。"]'),
('2f51ecab-7919-41c3-8ec6-cebe03da1818','送陳瑩中及第歸洪州','李之儀','宋','宋诗','song-poetry','','[]','七月江南秋已到，江水如天魚尾掉。',96,'全唐诗/poet.song.55000.json','["七月江南秋已到，江水如天魚尾掉。", "處處團橘欲黄時，家家門前艤歸棹。", "西山佳氣徹青雲，潘郎門巷如深春。", "陳家有兒新及第，新着恩袍歸見親。", "爲報行人洗眼看，養兒如此誰不羨。", "願兒不要重科第，事業功名他日見。"]'),
('b6283d9d-7009-402f-8e4c-7233e9ab6cff','古東門行','李之儀','宋','宋诗','song-poetry','','[]','元鼎元年東有兵，未央催班不待明。',156,'全唐诗/poet.song.55000.json','["元鼎元年東有兵，未央催班不待明。", "龍驤虎步擁旄出，蟻蟻部曲隨鳴鉦。", "三千珠履皆上客，囊中有錐誰爲發。", "莫歌雌兔眼迷離，長城可倚知在誰。", "千羊不如一狐腋，草底寒蟲漫啾唧。", "兩口四目未必智，天下奇才余星墜。", "舟中指可掬，冀北馬羣空。", "漆身吞炭爲國士，射足接處謀已同。", "義感丹誠虹貫日，壇上成功方頃刻。", "縱有明珠千丈長，安能保得頭常黑。"]'),
('993a3e56-d243-496f-9a92-5ef126cedb37','春日同梁十四宴李公昭朝霞閣侍兒舞梁州曲徹客有以潤羅爲贈公昭命玉杯滿酌酬之又以金鍾邀兒相屬既釂出烏絲欄索詩','李之儀','宋','宋诗','song-poetry','','[]','都城春風吹落花，都城九陌無塵沙。',204,'全唐诗/poet.song.55000.json','["都城春風吹落花，都城九陌無塵沙。", "貂裘公子醼何處，闌干百尺陵朝霞。", "鳳箏新調玉指軟，黄金捍撥當胸遮。", "紫檀屢碎翻成拍，紅茸毯襯鴉頭襪。", "回旋誰許綵雲輕，欲斷還催猶未徹。", "新鶑弄雛乳燕飛，一曲凉州春日遲。", "百疋纏頭隨玉盃，咿啞一鬨爭扶持。", "公子笑不已，下客懽正濃。", "更邀婭姹持金鍾，一釂直欲滄溟空。", "從他海若在平地，明珠墮淚愁蛟龍。", "珊瑚突兀撐高峰，便疑巴姬御來風。", "月漸滿，銀河低。", "歸路促，街鼓稀。", "何時再到紅茸地，更倩游絲惹住衣。"]'),
('89b32bec-0763-44e4-98f8-e5a8e622251a','盧泉之水次韵晁堯民贈張隠人','李之儀','宋','宋诗','song-poetry','','[]','盧泉之水名河長，裂臍不到空莽蒼。',96,'全唐诗/poet.song.55000.json','["盧泉之水名河長，裂臍不到空莽蒼。", "讀君詩句心已凉，便覺滿耳清浪浪。", "彼方逐臭如竊香，肝膈素飽神鷹揚。", "有客飯水衣朝陽，睥睨不語中何傷。", "過從德君想更樂，直欲造化窮微茫。", "何當相從老此水，桀跖夷齊均是死。"]'),
('4a7e3e27-fcf5-4ab3-9e44-b9f26874c09c','飲散留別希仲自江州倅罷歸壁間掛廬山圖約爲象戲終席不果又約明日而纔徹余遂行','李之儀','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','密雨着地三四尺，斑駁雲開日已西。',96,'全唐诗/poet.song.55000.json','["密雨着地三四尺，斑駁雲開日已西。", "坐來指點經行處，問我何年別虎溪。", "十分酒到一舉盡，笑我强飲如登梯。", "燈火熒熒夜未艾，回首但覺娥眉低。", "今朝未食先破趙，明日憑熊欲下齊。", "門外馬嘶獨未起，據鞍纔許趨鷄啼。"]'),
('1b470769-723a-46f9-91f0-8e1afe5b72ec','和張文潛喜東坡過嶺','李之儀','宋','宋诗','song-poetry','','[]','紛紛擾擾何爲哉，一身之餘皆儻來。',64,'全唐诗/poet.song.55000.json','["紛紛擾擾何爲哉，一身之餘皆儻來。", "當前荆棘誰所樹，到了醯酸蚋方聚。", "公歸斯文乃有主，公去妖淫幾人誤。", "狐狸罷嘷蛟龍衆，戶外何嫌常滿屨。"]'),
('40fcb9c4-8f46-4936-b4ac-6f4a71bd0e54','合流遇潘子真出斯文相示因置酒','李之儀','宋','宋诗','song-poetry','','[]','山谷老子久不見，豫章詩人何許來。',64,'全唐诗/poet.song.55000.json','["山谷老子久不見，豫章詩人何許來。", "章江未覺清徹骨，西山一带寒煙開。", "文章明鏡現諸相，句律蟄戶驚春雷。", "紅爐勸坐且一醉，爲我更賦揚州梅。"]'),
('cfda6e1d-c387-47cf-82d0-08e3018682fe','撚須寄傅子淵','李之儀','宋','宋诗','song-poetry','','[]','一日幾回撚白鬚，我本于世非葭莩。',144,'全唐诗/poet.song.55000.json','["一日幾回撚白鬚，我本于世非葭莩。", "奈何寸沫長自濡，起倒不供須人扶。", "眼前擾擾嘈笙竽，況于得失隨有無。", "鼠壤狼籍多棄餘，史雲空悲釜生魚。", "抓搔世垢清肌膚，愈下愈拙真挈壺。", "愛極并愛屋上烏，古詩有之今輒如。", "不願百尺騰龜趺，不願去爲在涇鳬。", "只願卒歲眼長淤，百無所見常踟躕。", "出門擿埴尋君居，萬里付於千里駒。"]'),
('fbd777c9-47aa-40ca-8c8d-767d75027581','送保定錢弼違且約相見後行','李之儀','宋','宋诗','song-poetry','','[]','平生不願與物迕，所向未始值坑谷。',272,'全唐诗/poet.song.55000.json','["平生不願與物迕，所向未始值坑谷。", "濁斯濯足清濯纓，世間此理固纖曲。", "朱顔見君一笑可，兩眼照人光煜煜。", "深沉不可犯毫髮，遲暮已許同松竹。", "去年相逢儼如昨，歎我何殊侵曉燭。", "衰殘壯盛等復虛，且可清樽對殽蔌。", "軍興百邑不可遏，與期縱橫猶沸粥。", "念君去替無幾日，頗復驅馳隨檢束。", "君方撫掌笑我迂，物理循環同一局。", "有來則受去莫追，忍看紛紛自魚肉。", "我愧君言但首肯，明朝君去追奔軸。", "臨行春色已無有，勉强歌呼趨紅綠。", "思君不見一長吁，忽得書來親愈篤。", "約我歸來敘離別，滿紙抑揚疑諭蜀。", "豈知重門鎖白首，迹雖伏櫪心麋鹿。", "寄聲少作旬浹計，莫便雲間參去鵠。", "乖離會合杳難量，君能規規如世俗。"]'),
('fe6bf795-0301-46f2-a11d-bed79fed1952','得璉老莊僧書所報周悉且速東歸既愧其勤因述書語爲謝仍約官滿就見','李之儀','宋','宋诗','song-poetry','','[]','故人書報新種畦，東臯豆麥稻水西。',192,'全唐诗/poet.song.55000.json','["故人書報新種畦，東臯豆麥稻水西。", "更添莊屋成兩脫，築出湧路排沙泥。", "柳插千本竹萬个，雞豚母子羣相携。", "又倚前岡闢場圃，更下南泊來鳧鷖。", "兩年課役已似此，數歲漸可如山溪。", "吾師報地適我與，胸中瑩徹真琉璃。", "一錢不敢力爲盡，只得一飯仍鷄棲。", "我慙汩沒落陷穽，眼前差路知幾蹊。", "緬懷吾邦歸未得，書來未讀先酸悽。", "本無去來强縶縛，亦非顛倒隨傾擠。", "萬衆過眼即他物，列鼎既飽均朝虀。", "明年定作一村老，非施委曲誰刀圭。"]'),
('f57aa532-3029-4354-b98c-aabdd242a345','內侍劉有方畜名畫乃內虢國夫人夜遊圖最爲絕筆東坡館北客都亭馹有方敢跋其後既作詩以相示時欲和而偶未暇今閱集得詩遂次其韵以申前志','李之儀','宋','宋诗','song-poetry','','[]','天街雨過花滿窗，萬人壁立驚游龍。',112,'全唐诗/poet.song.55000.json','["天街雨過花滿窗，萬人壁立驚游龍。", "飄飄衣袂欲仙去，寶鞭遙指蓬萊宮。", "真人睡起春纔柳，誰眷琵琶最先手。", "合懽堂裏謝使人，暗香猶带天階塵。", "宛然相對若可語，筆墨頓失當時痕。", "開眼成今合眼古，回頭自有來時路。", "長風破浪真快哉，快處須防倒騎虎。"]'),
('6b18b0c6-8624-4052-88a8-c59831492c87','常愛東坡去年花落在徐州對月酣歌美清夜今夜黄州見落花小院閉門風露下二詩因即其韵聊寄目前  其一','李之儀','宋','宋诗','song-poetry','','[]','老來不慣離家久，獨卧一庵今八夜。',160,'全唐诗/poet.song.55000.json','["老來不慣離家久，獨卧一庵今八夜。", "抵搔十爪垢已滿，降伏千魔心未下。", "熒熒病眼日更昏，皎皎孤懷誰與瀉。", "恨無鸞帳與誰俱，獨有筇枝伴身亞。", "華嚴性海偶深味，兜率陀天聊復借。", "平生好書陋顔柳，近日作詩幾沈謝。", "百年旅夢行將覺，萬里家園猶未舍。", "妄緣儻或未嘗膽，佳境安得如食蔗。", "從來少味燕偏知，早已忘機鼠休怕。", "行當遂作重屏圖，闒茸凡材任譏駡。"]'),
('33676e00-1d7d-4ad0-b609-3d3811c35b05','常愛東坡去年花落在徐州對月酣歌美清夜今夜黄州見落花小院閉門風露下二詩因即其韵聊寄目前  其二','李之儀','宋','宋诗','song-poetry','','[]','良宵明月爲誰好，記得初來正合夜。',160,'全唐诗/poet.song.55000.json','["良宵明月爲誰好，記得初來正合夜。", "城頭火客喏不斷，花上鵲棲驚欲下。", "更深未覺單衣怯，風細只疑清露瀉。", "漂流南北心已老，綿歷間關身自亞。", "傷心黄卷不相契，過眼青春難更借。", "那知交臂輒深扃，驟學問囚誰與謝。", "家書杳邈隔重嶺，客飯酸鹹真傳舍。", "慇懃兒女置隻鯉，璀璨盤蔬勝木蔗。", "定知何日遂能歸，却憶今朝真可怕。", "解衣就枕已多三，喘咄多言翻自駡。"]'),
('af02abe3-c5d8-4c8a-b028-17db02af30ec','初夜有雨意欲曉風大作','李之儀','宋','宋诗','song-poetry','','[]','昨夜雪深疑有雨，五更還作掃雲風。',144,'全唐诗/poet.song.55000.json','["昨夜雪深疑有雨，五更還作掃雲風。", "我于此地雖無責，傷時失事心則同。", "起來悵望一吁歔，又覺烈日侵階紅。", "隔牆鼓吹去何許，入戶哀怨號無蹤。", "尋花戀蘂爾自樂，啼夫哭子情無窮。", "平生感慨垂老別，異時獨與新豐翁。", "邇來眼力不解事，彷彿推墮此境中。", "天公豈肯違一物，爾且莫嘆杼柚空。", "無心致禱禱必應，會見一雨半年豐。"]'),
('d35d79cd-cd9d-46b2-b8f2-51472172b82f','送慕容若禔公幹環慶邠寧','李之儀','宋','宋诗','song-poetry','','[]','四月邊城氣如煮，問龍乞水將致雨。',176,'全唐诗/poet.song.55000.json','["四月邊城氣如煮，問龍乞水將致雨。", "起我獨有泛蓮人，相與授誠香一縷。", "腹枵不擬謝僧疏，愁對焦枯無告語。", "君時捧檄不我捨，意欲同分神所怒。", "此誠未契我輒罷，想望絕疑隔烟霧。", "一朝報我檄難留，明日清晨離此去。", "我慙君住本爲我，君行我乃不得祖。", "固知身世不相期，戚戚安能效兒女。", "君還我亦脫韁鎖，聞道荆醅如潑乳。", "使君況是我輩人，便約臨高目東注。", "經由第一莫遲回，尤物須知原有主。"]'),
('f1fd705f-dec8-4b2a-a1e7-208627498762','再次韵并寄寧州孫子發','李之儀','宋','宋诗','song-poetry','','[]','顧我從來奈烹煮，況復顛風并怪雨。',176,'全唐诗/poet.song.55000.json','["顧我從來奈烹煮，況復顛風并怪雨。", "出門未必趁鴻鵠，閉門何曾下縿縷。", "比來重作坐禪僧，日與虛空相晤語。", "初非小智肯自私，終謂大國不可怒。", "倦途傾蓋得吾人，獨喜山行逢豹霧。", "僅愧依融累歲留，猶勝投閎經宿去。", "東州勝事久欲講，老滕元將效懷祖。", "豈知敏手驟輸君，使君方詠羅敷女。", "願侍一笑作先容，試覺醍醐分酪乳。", "寧州別乘吾所畏，屹然萬弩不得注。", "寄聲到眼不須論，畢竟生涯誰能主。"]'),
('4ba89f1c-33f9-4ee8-b405-f95f848f9197','喜雨用前韵','李之儀','宋','宋诗','song-poetry','','[]','凋瘵尪殘不勝煮，欲救鑊湯須是雨。',176,'全唐诗/poet.song.55000.json','["凋瘵尪殘不勝煮，欲救鑊湯須是雨。", "天公愛人甚赤子，忍將性命輕毛縷。", "使君屹起石門城，歸路壺漿喧笑語。", "定知此雨必隨來，何用與龍爭喜怒。", "初疑點點洒醍醐，漸次濛濛縈瑞霧。", "一滴入地須一尺，萬室焦枯如洗去。", "我慙無力助精虔，獨致微誠祈佛祖。", "深扃不得陪賀燕，坐跋歌姝參舞女。", "近傳一斛出六斗，盞面浮蛆泛牛乳。", "煩君說與猿臂翁，留得滂沱猛如注。", "醉中寄我慶豐謠，想見今朝賓與主。"]'),
('ebbe9ea6-b752-40e5-b5e5-13c70ab28aac','謝慕容若禔惠橘皮湯用前韵','李之儀','宋','宋诗','song-poetry','','[]','有幻色身同一煮，誰振楊枝洒甘雨。',176,'全唐诗/poet.song.55000.json','["有幻色身同一煮，誰振楊枝洒甘雨。", "一息不御百虐隨，邪正交差窮脈縷。", "昔人有術我得早，自約初到必與語。", "日來靜坐不能遣，痞嗌忽作河豚怒。", "腹腸迤邐吼雷霆，嘔啞繽紛雜珠霧。", "吾僚恩勤漫馳告，果爲新留陳輒去。", "君臣辨正參苦良，物物經營本農祖。", "一杯狼籍走三彭，再啜逡巡失魔女。", "恍疑身在清凉國，無異金堂逢石乳。", "便當竄入經驗法，何用忉忉增補注。", "多慙世語必見臨，不會作客勞煩主。"]'),
('64661533-ca41-460c-bfd9-70c6fc2e6ab6','謝傅子淵惠虀醋','李之儀','宋','宋诗','song-poetry','','[]','一罌瀲灧香馥郁，刻意傳來敵珠玉。',128,'全唐诗/poet.song.55000.json','["一罌瀲灧香馥郁，刻意傳來敵珠玉。", "畫屏當袢世俗珍，獨喜小甲隨宜粟。", "老翁病起疏匕箸，頓覺加餐不勞祝。", "喜輿頗訝併日食，庖有力疲憂斷續。", "舌根有相未須遮，定應雙笋沒春芽。", "只愁此法不能錄，歸去尋思空自嗟。", "天酥辟易醍醐釅，且從樂處爲生涯。", "他人若問真消息，請向原州覓傅家。"]'),
('df677e2f-f419-458d-9f6b-dc8760785da4','築城詞效張籍體','李之儀','宋','宋诗','song-poetry','','[]','齊眉去，朝天回。',88,'全唐诗/poet.song.55000.json','["齊眉去，朝天回。", "一聲號，千聲催。", "土勻纔布一摶許，試錐只恐錐鋒摧。", "萬仞連雲絕川路，胡騎回還不敢覷。", "但云本是漢家地，如此携家渡河去。", "渡河去，莫回頭。", "漢家人人要首級，渭州門外籤爾喉。"]'),
('2cd046ba-9d95-47d3-9246-14f98eed066e','寄耀州畢九','李之儀','宋','宋诗','song-poetry','','[]','造物于我終何功，寓形宇宙一粟同。',160,'全唐诗/poet.song.55000.json','["造物于我終何功，寓形宇宙一粟同。", "由粟而形則可物，自形而我如飄風。", "我初與子未束髮，長我一歲今皆翁。", "間關世故憂愁集，悔不相向但盲聾。", "邇來夢寐亦驚噩，無異船鼓撾鼕鼕。", "逢場作戲固聊爾，隨緣應責疇能充。", "邊城氛埃蔽天赤，春物豈暇尋青紅。", "頗知別乘甚相得，共玩雙翠臨雕籠。", "酒闌起舞屢脫帽，笑指落月如懸銅。", "何當容我作鼎足，未易歸馬催匆匆。"]'),
('92ce583b-cada-443b-ae61-2f0aaed2e539','壁間所掛山水圖','李之儀','宋','宋诗','song-poetry','','[]','老驥無能空在閑，苜蓿既飽思行山。',128,'全唐诗/poet.song.55000.json','["老驥無能空在閑，苜蓿既飽思行山。", "誰知尺幅分向背，恍如百里隨躋攀。", "雲煙濛濛心共遠，草樹陰陰日將晚。", "一聲幽鳥隔前溪，萬古回春來疊巘。", "凉風彷彿飛清霜，奉身九折忍王陽。", "嗟我胡爲不自愛，逐物顛倒輕餘光。", "爪䍦活計知何日，相對無言搔短髮。", "芒鞋竹杖清自在，皎皎吾心真匪石。"]'),
('1375004b-90af-4ff9-b6c8-b7f815d39909','送郎祖仁罷九江稅省親仙源','李之儀','宋','宋诗','song-poetry','','[]','石磴縈紆行一髮，下見滄溟湧初月。',64,'全唐诗/poet.song.55000.json','["石磴縈紆行一髮，下見滄溟湧初月。", "不應佳氣無所歸，十載聲名藹吳越。", "香爐峰下新解官，疋馬又過桑麻間。", "知有秦人篆字否，不妨高處小塵寰。"]'),
('d0159289-c045-4059-a7d3-127a5788668c','四時詞擬徐陵用今體次東坡舊韵 春','李之儀','宋','宋诗','song-poetry','','[]','紅綠枝頭自開落，薄日低雲天一幕。',64,'全唐诗/poet.song.55000.json','["紅綠枝頭自開落，薄日低雲天一幕。", "可堪困緒尚眠蠶，未擬歡心隨破萼。", "寶環半脫畏侵肌，百刻縈香竟屬誰。", "旋製稱衣宮樣窄，慵看架上去年衣。"]'),
('a9dd3c00-7300-46a3-8662-ab704d74b9c7','四時詞擬徐陵用今體次東坡舊韵 夏','李之儀','宋','宋诗','song-poetry','','[]','蜀葵易過紅榴永，鱗鱗瑩角波紋冷。',64,'全唐诗/poet.song.55000.json','["蜀葵易過紅榴永，鱗鱗瑩角波紋冷。", "水光汗透玉枕凉，扇影風摇深院靜。", "無言一向幾回顰，品盡么絃竟不勻。", "空被梁間偷眼燕，黄蜂元是竊香人。"]'),
('ccbe8d9d-d6e7-47ad-83f8-ccbddc0296be','四時詞擬徐陵用今體次東坡舊韵 秋','李之儀','宋','宋诗','song-poetry','','[]','畫圖展盡瀟湘綠，窈窕新詞寫啼竹。',64,'全唐诗/poet.song.55000.json','["畫圖展盡瀟湘綠，窈窕新詞寫啼竹。", "薄衾笑拂又經年，已報莎雞入重屋。", "漸施簾幙作深扃，時看明河步廣庭。", "旋索羅衣防露下，隔牆聞叫侍兒聲。"]'),
('9885807a-d631-4189-8607-41f23bb8f1f2','四時詞擬徐陵用今體次東坡舊韵 冬','李之儀','宋','宋诗','song-poetry','','[]','休願車輪生四角，莫向金樽嫌酒薄。',64,'全唐诗/poet.song.55000.json','["休願車輪生四角，莫向金樽嫌酒薄。", "門外風號雁陣低，擁衾同看殘燈落。", "轆轤敲凍驚棲鴉，睡紅笑引燕脂霞。", "未擬雕籠問鸚鵡，先投宿酒敵霜花。"]'),
('b172a8bf-5097-410f-94dc-62cfedd3e005','次韵東城所畫郭功甫家壁竹木怪石詩','李之儀','宋','宋诗','song-poetry','','[]','大枝憑陵力爭出，小幹縈紆穿瘦石。',96,'全唐诗/poet.song.55000.json','["大枝憑陵力爭出，小幹縈紆穿瘦石。", "一盃未釂筆已濡，此理分明來面壁。", "我嘗傍觀不見畫，只見佛祖遭呵駡。", "人知見畫不見人，紛紛豈是知公者。", "汗流几案慘無光，忽然到眼如鋒鋩。", "急將兩耳掩雙手，河海振動電電吼。"]'),
('669bb25d-54af-4018-a81c-2e31ee36770a','答吳子友見寄昔與子友同書局以此韵往來人各十二篇今子友仍用元韵遂復次之各十三篇矣','李之儀','宋','宋诗','song-poetry','','[]','憶昔榱題雜梁棟，懷璧握珠容抱甕。',160,'全唐诗/poet.song.55000.json','["憶昔榱題雜梁棟，懷璧握珠容抱甕。", "大宛天馬本不羈，擫耳轅駒援就控。", "撈蝦摸蟹力易盡，搏虎擒蛟殺方痛。", "君時正射晁董策，直把黄金變鉛汞。", "顧我衰遲特相子，許我過比儀韶鳳。", "回頭已數六端午，幾向夢中自占夢。", "邇來欲述陷膚語，豈謂書詞情愈重。", "琅琅楚虞奏未缺，杳杳燕鴻目頻送。", "壯君已赴宣室召，老來未棄蟭螟動。", "詩成新月半侵簾，更聽樓頭角初弄。"]'),
('d805305b-81b1-4f6b-a9a8-24e17de3d09b','答成都侍其純父用其韵','李之儀','宋','宋诗','song-poetry','','[]','鹿頭關下花深處，竹馬曾尋綵衣路。',128,'全唐诗/poet.song.55000.json','["鹿頭關下花深處，竹馬曾尋綵衣路。", "雖知梨栗是生涯，人道風煙如鄠杜。", "四十年來若斷橋，問津無計冷瀟瀟。", "一聞此語心先醉，似向江邊笋自燒。", "羨君材器森諸有，寶带垂腰今一叟。", "未說常開壇上旗，且須再遣雲中守。", "從來別駕不謀身，欲作蛾眉會裏人。", "本是文殊親接引，定應見處必逢君。"]'),
('7e08ab33-0806-4dc7-868c-68648608ece5','蘇子瞻因膠西趙明叔賦薄薄酒杜孝錫晁堯民黄魯直從而有作孝錫復以屬予意則同也聊以廣之  其一','李之儀','宋','宋诗','song-poetry','','[]','薄薄酒，勝茶湯。',100,'全唐诗/poet.song.55000.json','["薄薄酒，勝茶湯。", "刳麝臍，爲有香。", "斷尾山雞避文章，直木先伐甘井竭，誰將列鼎移黄粱。", "揚雄草玄反嘲白，麯糵寧非井丹食。", "却念牛衣兒女心，王郎漫致回天力。", "五湖歸去弄煙月，伏劍成名空玉雪。", "飲薄酒，醉後紛紛亦何有。"]'),
('eb1bc3c0-9397-4ec9-ae41-c0a27c0bd718','蘇子瞻因膠西趙明叔賦薄薄酒杜孝錫晁堯民黄魯直從而有作孝錫復以屬予意則同也聊以廣之  其二','李之儀','宋','宋诗','song-poetry','','[]','莫厭薄酒薄，莫惡醜婦醜。',94,'全唐诗/poet.song.55000.json','["莫厭薄酒薄，莫惡醜婦醜。", "君不見王尋百萬驅虎豹，千兵掃蕩同拉朽。", "又不見高堂笙歌午夜飲，明日哭聲喧正寢。", "莫厭薄酒薄，到頭一醉亦足樂。", "莫惡醜婦醜，携子弄孫同白首。", "高飛遠走固亦樂，莫救眼前忘時後。"]'),
('9155701a-acf4-4309-acd3-ac1beb3581b3','過雨飲臨潁何希仲家蒙督詩即席爲贈','李之儀','宋','宋诗','song-poetry','','[]','君不見張子房，素書未授抵遊俠。',352,'全唐诗/poet.song.55000.json','["君不見張子房，素書未授抵遊俠。", "又不見蕭望之，不能碌碌反抱關。", "漢業已成赤松去，殺吾賢傅終感嘆。", "乘時致用固不免，要須繒繳無由攀。", "八十釣渭濱，揮旄仗鉞興艱難。", "臂鷹上蔡市，復得不可空多言。", "周傾秦得漢亦起，虎噬鯨吞羝觸藩。", "一興一廢竟誰有，要之有數歸元元。", "元元亦何爲，與君論子細。", "須將劇孟作敵國，未信葉公真勇士。", "竊借聲名人自歎，白公梟首方爲是。", "乾旋坤轉只等閒，收放僅在毫端耳。", "何郎目如電，奮髯兒童驚。", "眼光在酒裏，一飲黄河傾。", "不作么麽貴公子，橫行欲得十萬兵。", "吾語何郎少卑之，犀有角兮麝有臍。", "果知有累不早計，抑揚畢竟何所之。", "滿酌勸君飲，吾語無文章。", "鞭笞六龍駕扶桑，上朝元君陪紫皇。", "霞衣玉簡鬚如霜，俯仰八極何茫茫。", "方時與君俱此舉，如何煩君蹔起舞。", "舞徹聽我歌，我歌端爲我輩作。", "蠢蠢萬類隨江河，肯同兒女戰蝸角，酒酣雨淚揮滂沱。"]'),
('753d6240-91fa-430b-87a9-ba84bf70dd39','正旦日大雪過秀州城外聞樂神踏歌打鼓','李之儀','宋','宋诗','song-poetry','','[]','歲除夜雪一寸許，便覺新年喜氣多。',64,'全唐诗/poet.song.55000.json','["歲除夜雪一寸許，便覺新年喜氣多。", "大觀元年第一日，一番勝事信可歌。", "歌不已，鼓聲起，漫壟連村如市裏。", "更願雪深一尺餘，收了去年三尺水。"]'),
('9cc5a197-2888-4bac-88a1-0963c8ff1224','問傅子淵求冷淘醋','李之儀','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','君不見東林木魚催萬指，巾鉢紛紛似流水。',134,'全唐诗/poet.song.55000.json','["君不見東林木魚催萬指，巾鉢紛紛似流水。", "銀絲百遍連夜具，大解行虀如酒醴。", "又不見親賢宅中午睡足，花簇春羔衒紅綠。", "一窩隨首髮猶粗，妖冶均調笑相續。", "他日何人參智海，研乳磨薑搗椒薤。", "便覺廬山落眼中，誰爲窮邊輒相會。", "往還斷絕惟緘默，蹔遠葷羶味薝蔔。", "親賢勝事不可尋，且向箇中求一則。"]'),
('436c9be7-b999-4672-93e1-69a06dbf6acb','賀李方叔得眉山玉堂賜馬公自書券','李之儀','宋','宋诗','song-poetry','','[]','帝閑萬馬皆天寵，一一盡是真龍種。',149,'全唐诗/poet.song.55000.json','["帝閑萬馬皆天寵，一一盡是真龍種。", "欲知志氣吞萬里，駿意向人耳雙竦。", "翰林下直出玉堂，狨鞍寶轡聲琅琅。", "傳呼一聲驚里閈，新向庭中賜驌驦。", "明年乞得東南守，畫舸西河卧載酒。", "免令此馬老江山，故用贈君良獨厚。", "憐君從來家苦貧，坐冷儒士喜意新。", "自書券字甚雄偉，作書遠報江河人。", "翰林好士裴丞相，知君亦負玉堂望。", "願君寶此。"]'),
('402d82de-3733-4883-856f-1ec0877995e1','雨中自瓜步謁寶覺遂約遊黄社寶覺遽有儀真之行雨後獨往夜分方到泥滑路巇乘步相半','李之儀','宋','宋诗','song-poetry','','[]','夢寢東南遊，金山居第一。',204,'全唐诗/poet.song.55000.json','["夢寢東南遊，金山居第一。", "泊船瓜州口，風雨繫黑日。", "冒雨訪老胡，翛然出蘿蓽。", "壁間十弟子，云是王維筆。", "生者今何在，別有一丈室。", "相期同過之，佳思久披拂。", "差池成獨往，敢憚泥沒膝。", "投鞭望橫參，露重衣如濕。", "方諸湛漏魄，指顧盡纖息。", "目眩神爲清，壺冰蕩肝膈。", "亹亹相問勞，軟語皆中律。", "頗怪不預知，有似驚暴客。", "杈牙荐爐紅，柔脆脩林茁。", "老淚感陸生，明盤皎霜橘。", "木魚動曉堂，永味固南畢。", "百年驚枯槁，平日膠在漆。", "幅巾行此時，歲暮悲蟋蟀。"]'),
('ccced78c-c358-4a25-b18b-b026f613dc16','金山寄懷秦太虛用建除體','李之儀','宋','宋诗','song-poetry','','[]','建古求亡子，寓意一何疏。',144,'全唐诗/poet.song.55000.json','["建古求亡子，寓意一何疏。", "除道聲出師，老將定胡盧。", "滿座語更發，誰是囊中珠。", "平生不少貸，鮮不相謂迂。", "定分固有來，跛鱉參乘駒。", "執別纔幾日，眷眷瞻雲衢。", "破碎物役爾，此理君何如。", "危步上傑觀，疇昔相携扶。", "成茲塵外趨，感慨反不舒。", "收我漏盡景，課君種樹書。", "開山一百里，玉粒隨香葅。", "閉口不復語，早晚同歸與。"]'),
('5ab754d5-e89b-4d29-840d-5053f63e4235','毗陵西城樓感懷','李之儀','宋','宋诗','song-poetry','','[]','平臯已春風，昨夜猶繁霜。',120,'全唐诗/poet.song.55000.json','["平臯已春風，昨夜猶繁霜。", "倦客驚節物，遊子思故鄉。", "樓高白日促，遠目空悲凉。", "願言平生歡，各在天一方。", "遡遊不可從，山川阻且長。", "安得一樽酒，咿啞共深堂。", "孤懷昔蕭屑，壯志猶激昂。", "無階際玄護，尚期夢池塘。", "饑鷹在千里，怒鬣存三湘。", "寒鴉似相求，依依度斜陽。"]'),
('72758f37-71c6-46f7-8137-b55386cf305b','秦太虛寄書云想君在毗陵廣坐中白眼望青天也因錄此語爲寄兼簡諸君','李之儀','宋','宋诗','song-poetry','','[]','白眼望青天，我乃厭多酒。',96,'全唐诗/poet.song.55000.json','["白眼望青天，我乃厭多酒。", "秦郎才語新，高低秀蜀柳。", "春風昨夜來，傳書自江口。", "固爲愁水光，物物慙我醜。", "歸程無日多，僧窗不驚帚。", "投懷二三子，自許口不朽。", "笑言忌有累，醆斚來所有。", "莫問夜如何，爲君專一斗。"]'),
('4c25f8f2-e347-41f5-8454-e757bbe70558','維揚會張曼老陳瑩中分韵得柳字','李之儀','宋','宋诗','song-poetry','','[]','我生固有地，物物皆可口。',168,'全唐诗/poet.song.55000.json','["我生固有地，物物皆可口。", "身行半天下，荐饑無不有。", "讀書恨未博，每索多掣肘。", "一逢可意人，似對靈和柳。", "老來益落寞，永日類中酒。", "北舟得二妙，洗盡平生垢。", "參軍欲陵春，記室寒掛斗。", "雍容送落日，百衲爲抖擻。", "崎嶇等外驚，瞥眼自妍醜。", "真樂極胡越，誰可論不朽。", "昔人固欣慕，僅欲操箕帚。", "堂皇幾千仞，未易窺戶牖。", "逡巡即千里，轉盼百年久。", "一笑且低回，朱顔今皓首。"]'),
('d6773408-80b9-4a7a-ab1f-b6f96af7f266','次韵魯直留別','李之儀','宋','宋诗','song-poetry','','[]','南北二十年，短褐足塵垢。',192,'全唐诗/poet.song.55000.json','["南北二十年，短褐足塵垢。", "九仞未及泉，竭心恚地厚。", "積翳開前山，月在山之顔。", "目斷兩黄鵠，夢寐長躋攀。", "我飯苦多噎，見君遽出氣。", "定有囊中藥，痿人果知起。", "枯槁洗朝露，咀嚼玉壺冰。", "蔓草豈自得，香發須高陵。", "齚舌真有味，辨口空齒落。", "頓悟孺子歌，會當濯其濁。", "允蹈固未見，能言人亦難。", "得微可齊語，引置莊嶽間。", "大路平如掌，仁者貴安宅。", "直絃爲君彈，萬里等尋尺。", "何年紀渻子，相向猶木雞。", "肝肺已自鏤，土苴非所知。"]'),
('895e8f1f-a7a6-4882-b7b1-d7325427da5e','鮮于子駿用魯直見寄韵因以爲謝','李之儀','宋','宋诗','song-poetry','','[]','雲間彼上人，處汙能見垢。',192,'全唐诗/poet.song.55000.json','["雲間彼上人，處汙能見垢。", "咄咄向風雅，入國知溫厚。", "別來仰高山，霜風刮衰顔。", "新詩解人頤，調古不可攀。", "練練瑚璉姿，森森棟梁氣。", "願學固有歸，黯然由此起。", "世味淡于蠟，孤懷冷如冰。", "十年問歸路，歌舞懷西陵。", "歲晏感飄蓬，老去委瓠落。", "豈無杖頭錢，斗酒不問濁。", "尚平累愈重，欲去亦良難。", "安得厠木雁，才與不才間。", "遇君本有地，悵我將焉宅。", "引領遡家山，一望幾千尺。", "何須驚墮葉，會當鑒攘雞。", "風來北窗下，此況誰爲知。"]'),
('1d6104f3-6c57-44d1-9d1a-0b1792e0715c','次韵子瞻古風詩二首  其一','李之儀','宋','宋诗','song-poetry','','[]','無兒晚讀書，得之兩河場。',96,'全唐诗/poet.song.55000.json','["無兒晚讀書，得之兩河場。", "何待少陵詩，閃閃已生光。", "深山秀蘭芽，無人方自香。", "未央鎖千門，可知曼修廊。", "俯仰要自得，犧樽浪青黄。", "惡木熱亦蔭，盜泉渴須嘗。", "果能奪固有，利害置兩傍。", "匪我亦匪人，用托寧見傷。"]'),
('e5c525ff-1c7c-455c-a766-8146bd9fac0b','次韵子瞻古風詩二首  其二','李之儀','宋','宋诗','song-poetry','','[]','紅爐一勺水，湧沸如雷聲。',84,'全唐诗/poet.song.55000.json','["紅爐一勺水，湧沸如雷聲。", "德君戒終南，爲君歌采苓。", "水盡焰仍烈，崎嶇閱修齡。", "由來外一重，疇非君死生。", "風物托茲世，異種聊並蒂。", "榮謝等春秋，何勞騖多計。", "眷眷後世雄，惟君有以似。"]'),
('a9670be3-dddf-4547-8130-72dcfc7d5dd5','子瞻參寥太虛同遊惠山用王武陵竇郡朱宿三詩韵各有所賦參寥錄以相示余將遊焉用次其韵  其一','李之儀','宋','宋诗','song-poetry','','[]','曾爲惠山客，心已寄蒼茫。',72,'全唐诗/poet.song.55000.json','["曾爲惠山客，心已寄蒼茫。", "知今幾何時，常在山間堂。", "淹留情莫蟄，悵望身疑翔。", "聯翩得秀句，古殿逢燈光。", "耳冷徹孤韵，神幽拂清香。", "買舟行有期，此興安能忘。"]'),
('4e02acf8-85dc-4346-a2ea-6e82009399f9','子瞻參寥太虛同遊惠山用王武陵竇郡朱宿三詩韵各有所賦參寥錄以相示余將遊焉用次其韵  其二','李之儀','宋','宋诗','song-poetry','','[]','三子骨已朽，來者非一人。',72,'全唐诗/poet.song.55000.json','["三子骨已朽，來者非一人。", "簫聲起孤鳳，抑按皆清新。", "松陰貯老月，蘚暈涵蒼磷。", "崎嶇固有屬，千載無纖塵。", "物物吾已矣，今昔是可均。", "何當事一廛，顧水終爲鄰。"]'),
('349f48fb-23d4-42ae-bec3-90c43673677a','子瞻參寥太虛同遊惠山用王武陵竇郡朱宿三詩韵各有所賦參寥錄以相示余將遊焉用次其韵  其三','李之儀','宋','宋诗','song-poetry','','[]','膏肓有前人，老意繫叢樾。',72,'全唐诗/poet.song.55000.json','["膏肓有前人，老意繫叢樾。", "差池紛鬢霜，味蠟火已絕。", "一啜風潄液，幽思起復滅。", "詎慚數及七，緬予在明月。", "疏更蹇修途，景耿重激發。", "泠然儻可御，千古同一轍。"]'),
('4017b340-1309-498b-b14f-31a57a90cb89','再登斗野亭路舊韵寄太虛','李之儀','宋','宋诗','song-poetry','','[]','北舟攬黄氏，楚楚不自平。',120,'全唐诗/poet.song.55000.json','["北舟攬黄氏，楚楚不自平。", "故步聊低回，新月微風清。", "蛙聲語莫下，泡湧浮修甍。", "何在超世游，翳路情難傾。", "西堂夢不到，春草還復生。", "長年浸枯枿，有時懷層城。", "適從吳兒炊，又作淮人烹。", "皇皇徧諸侯，吾人愧安行。", "獨抱照乘姿，花枝似相明。", "拂衣歸待旦，南州逢顧榮。"]'),
('fe2ddef6-aa04-4161-ac96-1630523da583','秦太虛出魯直所寄詩因次其韵','李之儀','宋','宋诗','song-poetry','','[]','別子又春杪，幽懷誰與讙。',96,'全唐诗/poet.song.55000.json','["別子又春杪，幽懷誰與讙。", "返復事遠途，繚繞如理綿。", "家山雖入眼，尚疑隔晨煙。", "破悶得子詩，鳴雞還到船。", "追隨日苦短，容易悲長年。", "猶能共一轍，植足臨天旋。", "下澤政有味，萬戶自我捐。", "唯有不捨心，常如俯奔川。"]'),
('f0f85ac2-9bb0-488f-8d48-94b77921cde8','次韵家室送別','李之儀','宋','宋诗','song-poetry','','[]','幾年保新阡，託身斗一方。',240,'全唐诗/poet.song.55000.json','["幾年保新阡，託身斗一方。", "問語得野人，禾黍共登場。", "遷疏儻可老，持鬚時抑揚。", "顧非馬上才，猶懷袖中剛。", "西風蕩微氣，仰視明星光。", "叩齒咏真主，白眉誰最良。", "師門守邊鑰，表表南方强。", "逋誅百年寇，敢謂莫我當。", "牝雞久司晨，羣吠移當陽。", "葷羶固難律，誰可無宮商。", "堂堂發天機，右鉞左仗黄。", "一旦念風雲，果知籌策長。", "洗滌盡餘滓，萬翼爭回翔。", "能無出囊穎，及顧箕子傍。", "平生慣草衣，豈堪事戎行。", "强歌出塞曲，夭矯參龍章。", "蠅因逸驥速，馬爲奏瑟昂。", "尚期騖鼓操，奮力起病牀。", "賀蘭奪故穴，安西還舊疆。", "歸上千萬壽，重賡庶事康。"]'),
('ce2cbfa4-2e7e-450a-a91e-2518cf1d0c58','和參寥過敝廬留宿因見寄之韵爲謝','李之儀','宋','宋诗','song-poetry','','[]','及此仲春月，頗欲謝遠步。',108,'全唐诗/poet.song.55000.json','["及此仲春月，頗欲謝遠步。", "世味久已疏，何憚魚生釜。", "青陰合廣除，似失北門路。", "端知雞在塒，未媿豹隠霧。", "飄蕭方外遊，繾綣慰遲暮。", "共待青光來，軟語坐良樹。", "呼風破炎蒸，扣齒却忘慮。", "逡巡棲鳥驚，不記衣上露。", "臨分期屢來，此樂復誰與。"]'),
('e344a7ee-4e06-45f8-a0c1-8c9ecda2c039','送孫叔靜','李之儀','宋','宋诗','song-poetry','','[]','浮雲無定着，乍合還分離。',168,'全唐诗/poet.song.55000.json','["浮雲無定着，乍合還分離。", "廓開萬里天，好是無雲時。", "我懷苦蕭屑，多感不自拾。", "奈何情所親，容易成南飛。", "秦人雖受寶，睨柱誰瑕疵。", "空能九賓賞，終負連城歸。", "此道固有命，如君應未遲。", "且從淮上游，霜濃蟹螯肥。", "載取一樽酒，里門相扶携。", "笑語欲難背，古人良可期。", "開編若對面，謔浪尤相宜。", "皎皎澄漢月，森森瓊樹枝。", "燕地重郭隗，吳兒輕陸機。", "曉來猶薄露，會見高風披。"]'),
('290090e6-780a-4013-bb2b-b12ebed30565','次韵黄魯直晁堯民游馬頰歸','李之儀','宋','宋诗','song-poetry','','[]','洋洋引天津，湍悍誰爲寫。',72,'全唐诗/poet.song.55000.json','["洋洋引天津，湍悍誰爲寫。", "謀臧神所勞，穹築限修野。", "緬懷二三子，感物寓土苴。", "卯飲束貂裘，指顧來其下。", "霜風面欲黎，踉蹌倚羸馬。", "一笑等飛雲，吾生竟何者。"]'),
('bbcb0fc4-074a-477d-a5e4-a63428084382','次韵晁堯民黄魯直蘇子瞻同賦半粲字韵十往返而不倦者','李之儀','宋','宋诗','song-poetry','','[]','耿耿萬里心，振衣常夜半。',204,'全唐诗/poet.song.55000.json','["耿耿萬里心，振衣常夜半。", "明星當戶高，仰首每自嘆。", "是身固虛空，殆將等閒玩。", "永懷一寸光，有之詎能散。", "南山富蕨薇，采采寧待伴。", "不媿郢中曲，誰報青玉案。", "千載北窗風，鄭聲何可亂。", "子職若崎嶇，垢指寧與盥。", "我慙老更拙，欲和知良難。", "但能襲餘塵，未易窺重關。", "路年與君俱，纔此意少寬。", "奈何捨我去，鴻鵠隨騫摶。", "岑樓起膚寸，萬仞始一拳。", "知君未易量，願君更加餐。", "親髮日益白，何以爲親懽。", "以義不以時，吾君正求賢。", "只欠明光宮，峨峨望君冠。"]'),
('51cef2e8-2464-4b47-91fe-62ff4f49e376','寄范七平凉有一優者頗相似每見即與從容聊遣吾思之不能已也','李之儀','宋','宋诗','song-poetry','','[]','吾友范君誼，宛似丘遲詩。',180,'全唐诗/poet.song.55000.json','["吾友范君誼，宛似丘遲詩。", "點綴花映草，草長鶑亂飛。", "詠詩知吾人，因人想其詩。", "不知胸中寬，西域方鞭笞。", "昔爲守禦策，堅壁不容錐。", "今作進討計，萬里入鼓鼙。", "相從惜日短，既別恨見遲。", "雖無老成人，彷彿頰頳兒。", "每見挽手語，問我將何爲。", "我非濁子者，我友實似之。", "典刑不可見，況復堂上奇。", "邊城氣候晚，四月猶夾衣。", "青燈照冷坐，素目披重帷。", "孤懷苦蕭屑，人事終難期。", "何當命典刑，一笑相淋漓。"]'),
('810c1e03-6c29-4a35-9ca5-0c878154d1d6','浴','李之儀','宋','宋诗','song-poetry','','[]','靜坐已十日，聊復資一浴。',180,'全唐诗/poet.song.55000.json','["靜坐已十日，聊復資一浴。", "我髮不滿梳，安得別置沐。", "浴暖連頭澆，快哉如出谷。", "我生本離垢，妄念即桎梏。", "外物强扶持，何異雨中竹。", "亦不無雨愧，亦不有雨足。", "森森自然往，無榮亦無辱。", "振衣步空庭，又見黄粱熟。", "進退葵何從，晨羞詎宜緩。", "叩齒感莧史，虛心豈魚貫。", "乃知抱關者，俯首固非懦。", "烈日下嚴霜，盃水沃熾炭。", "物理自回旋，何方即吾館。", "年來老頓逼，四月未覺煖。", "勉力更無念，已矣見此粲。"]');
